// تحميل ملف bootstrap الرئيسي الذي يقوم بتحميل جميع المكونات
require_once __DIR__ . '/src/bootstrap.php';


function sod_has_arabic_chars(string $text): bool {
    return $text !== '' && preg_match('/\p{Arabic}/u', $text) === 1;
}

function sod_fix_mojibake_text($value): string {
    $text = trim((string)$value);
    if ($text === '') return '';

    $normalized = preg_replace('/\s+/u', ' ', $text);
    if (!is_string($normalized)) $normalized = $text;
    $text = trim($normalized);

    if (sod_has_arabic_chars($text)) return $text;
    if (!preg_match('/[ÃâØÙÐð]/u', $text) && strpos($text, '�') === false) return $text;

    $candidates = [];
    if (function_exists('iconv')) {
        $c1 = @iconv('Windows-1252', 'UTF-8//IGNORE', $text);
        if (is_string($c1) && $c1 !== '') $candidates[] = $c1;
        $c2 = @iconv('ISO-8859-1', 'UTF-8//IGNORE', $text);
        if (is_string($c2) && $c2 !== '') $candidates[] = $c2;
    }
    if (function_exists('mb_convert_encoding')) {
        $c3 = @mb_convert_encoding($text, 'UTF-8', 'Windows-1252');
        if (is_string($c3) && $c3 !== '') $candidates[] = $c3;
        $c4 = @mb_convert_encoding($text, 'UTF-8', 'ISO-8859-1');
        if (is_string($c4) && $c4 !== '') $candidates[] = $c4;
    }
    if (function_exists('utf8_encode')) {
        $c5 = @utf8_encode($text);
        if (is_string($c5) && $c5 !== '') $candidates[] = $c5;
    }
    foreach ($candidates as $fixed) {
        $fixed_norm = preg_replace('/\s+/u', ' ', $fixed);
        if (is_string($fixed_norm)) $fixed = trim($fixed_norm);
        if (sod_has_arabic_chars($fixed) || !preg_match('/[ÃâØÙÐð]/u', $fixed)) {
            return $fixed;
        }
    }

    return $text;
}

function sod_normalize_string_list(array $values): array {
    $out = [];
    $seen = [];
    foreach ($values as $value) {
        $value = sod_fix_mojibake_text($value);
        if ($value === '') continue;
        $key = function_exists('mb_strtolower') ? mb_strtolower($value, 'UTF-8') : strtolower($value);
        if (isset($seen[$key])) continue;
        $seen[$key] = true;
        $out[] = $value;
    }
    return $out;
}

function sod_json_flags(): int {
    $flags = 0;
    if (defined('JSON_UNESCAPED_UNICODE')) $flags |= JSON_UNESCAPED_UNICODE;
    if (defined('JSON_INVALID_UTF8_SUBSTITUTE')) $flags |= JSON_INVALID_UTF8_SUBSTITUTE;
    return $flags;
}

function sod_send_json_success($data = null, int $status_code = 200): void {
    wp_send_json_success($data, $status_code, sod_json_flags());
}

function sod_send_json_error($data = null, ?int $status_code = null): void {
    wp_send_json_error($data, $status_code, sod_json_flags());
}

function sod_contains_mojibake_markers(string $text): bool {
    return $text !== '' && !sod_has_arabic_chars($text) && preg_match('/[ØÙÃÐï¿½]/u', $text) === 1;
}

function sod_prepare_json_payload($value) {
    if (is_string($value)) {
        return sod_fix_mojibake_text($value);
    }
    if (!is_array($value)) {
        return $value;
    }

    $out = [];
    foreach ($value as $key => $item) {
        $fixed_key = is_string($key) ? sod_fix_mojibake_text($key) : $key;
        $out[$fixed_key] = sod_prepare_json_payload($item);
    }
    return $out;
}

function sod_clean_bank_value($value): string {
    $value = sod_fix_mojibake_text($value);
    $value = wp_strip_all_tags((string)$value);
    $value = preg_replace('/[\x{200B}-\x{200F}\x{202A}-\x{202E}\x{2066}-\x{2069}]/u', '', $value);
    $value = preg_replace('/\s+/u', ' ', $value);
    if (!is_string($value)) return '';
    return trim($value, " \t\n\r\0\x0B,.;:|/\\-–—()[]{}\"'`…");
}

function sod_is_valid_bank_value(string $canonical, string $value): bool {
    $value = sod_clean_bank_value($value);
    if ($value === '') return false;
    if (sod_contains_mojibake_markers($value)) return false;
    if (preg_match('/^(?:[\p{P}\p{S}\d\s]+)$/u', $value)) return false;
    if (preg_match('/https?:|www\.|admin-ajax|<script|<\/|^\W+$/iu', $value)) return false;
    if (preg_match('/\b\d{1,2}[-\/]\d{1,2}[-\/]\d{2,4}\b/u', $value)) return false;
    if (preg_match('/[#@]/u', $value)) return false;
    if (sod_safe_substr($value, 0, 1) === ',' || sod_safe_substr($value, -1, 1) === ',') return false;

    $word_count = count(array_filter(preg_split('/\s+/u', $value)));
    $len = sod_safe_strlen($value);
    $slash_count = substr_count($value, '/');
    $comma_count = substr_count($value, ',');

    if ($canonical === 'targets') {
        if ($len > 70 || $word_count > 8 || $comma_count > 3 || $slash_count > 3) return false;
        if (preg_match('/(?:المناطق المتأثرة|استهداف|الماضي|اليوم|هذا اليوم|خسائر بشرية|من دون|وقد|وأدى|ظهر اليوم)/u', $value)) return false;
        return true;
    }

    if ($canonical === 'regions') {
        if ($len > 40 || $word_count > 5 || $comma_count > 1 || $slash_count > 2) return false;
        return true;
    }

    if (in_array($canonical, ['actors', 'contexts', 'intents', 'weapons', 'types', 'levels'], true)) {
        if ($len > 60 || $word_count > 6 || $comma_count > 2 || $slash_count > 2) return false;
        return true;
    }

    return $len <= 60;
}

function sod_filter_bank_values(array $values, string $canonical): array {
    $out = [];
    $seen = [];
    foreach ($values as $value) {
        $value = sod_clean_bank_value($value);
        if (!sod_is_valid_bank_value($canonical, $value)) continue;
        $key = function_exists('mb_strtolower') ? mb_strtolower($value, 'UTF-8') : strtolower($value);
        if (isset($seen[$key])) continue;
        $seen[$key] = true;
        $out[] = $value;
    }
    return $out;
}

function sod_safe_strlen($text): int {
    $text = (string)$text;
    if (function_exists('mb_strlen')) return (int)mb_strlen($text, 'UTF-8');
    return strlen($text);
}

function sod_safe_substr($text, int $start, int $length): string {
    $text = (string)$text;
    if (function_exists('mb_substr')) return (string)mb_substr($text, $start, $length, 'UTF-8');
    return (string)substr($text, $start, $length);
}

function sod_repair_option_payload($value) {
    if (is_string($value)) return sod_fix_mojibake_text($value);
    if (!is_array($value)) return $value;

    $out = [];
    foreach ($value as $key => $item) {
        $fixed_key = is_string($key) ? sod_fix_mojibake_text($key) : $key;
        $out[$fixed_key] = sod_repair_option_payload($item);
    }
    return $out;
}

function sod_self_heal_mojibake_options(): void {
    static $done = false;
    if ($done) return;
    $done = true;

    $flag = 'sod_mojibake_self_heal_v4';
    if (get_option($flag, 0)) return;

    $option_keys = [
        'sod_bank_actors',
        'sod_bank_targets',
        'sod_bank_contexts',
        'sod_bank_intents',
        'sod_bank_weapons',
        'sod_bank_types',
        'sod_bank_levels',
        'sod_bank_regions',
        'sod_visible_learning_banks',
        'so_focus_regions',
        'so_exec_reports_footer',
    ];

    $canonical_map = [
        'sod_bank_actors' => 'actors',
        'sod_bank_targets' => 'targets',
        'sod_bank_contexts' => 'contexts',
        'sod_bank_intents' => 'intents',
        'sod_bank_weapons' => 'weapons',
        'sod_bank_types' => 'types',
        'sod_bank_levels' => 'levels',
        'sod_bank_regions' => 'regions',
    ];

    foreach ($option_keys as $option_key) {
        $current = get_option($option_key, null);
        if ($current === null) continue;
        $fixed = sod_repair_option_payload($current);
        if (is_array($fixed)) {
            foreach ($fixed as $k => $vals) {
                $canon = $canonical_map[$option_key] ?? sod_normalize_bank_key((string)$k);
                if (is_array($vals)) {
                    $fixed[$k] = sod_filter_bank_values(sod_normalize_string_list($vals), $canon);
                }
            }
        }
        if ($fixed !== $current) update_option($option_key, $fixed, false);
    }

    update_option($flag, time(), false);
}

add_action('init', 'sod_self_heal_mojibake_options', 1);

function sod_force_clean_learning_banks(): void {
    $option_keys = [
        'sod_bank_actors',
        'sod_bank_targets',
        'sod_bank_contexts',
        'sod_bank_intents',
        'sod_bank_weapons',
        'sod_bank_types',
        'sod_bank_levels',
        'sod_bank_regions',
        'sod_visible_learning_banks',
    ];

    delete_option('sod_mojibake_self_heal_v4');
    sod_self_heal_mojibake_options();
    foreach ($option_keys as $key) {
        $current = get_option($key, null);
        if ($current === null) continue;
        if ($key === 'sod_visible_learning_banks' && is_array($current)) {
            sod_save_visible_learning_banks($current);
            continue;
        }
        if (is_array($current)) {
            update_option($key, sod_normalize_string_list($current), false);
        }
    }
    sod_save_visible_learning_banks(sod_get_visible_learning_banks());
}

function sod_clean_entity_graph_records(): int {
    global $wpdb;
    $table = $wpdb->prefix . 'so_entity_graph';
    $rows = $wpdb->get_results("SELECT id, actor_name, target_name, region FROM {$table}", ARRAY_A);
    if (!is_array($rows) || empty($rows)) return 0;
    $updated = 0;
    foreach ($rows as $row) {
        $actor = sod_fix_mojibake_text((string)($row['actor_name'] ?? ''));
        $target = sod_fix_mojibake_text((string)($row['target_name'] ?? ''));
        $region = sod_fix_mojibake_text((string)($row['region'] ?? ''));
        if ($actor === ($row['actor_name'] ?? '') && $target === ($row['target_name'] ?? '') && $region === ($row['region'] ?? '')) {
            continue;
        }
        $wpdb->update($table, [
            'actor_name' => $actor,
            'target_name' => $target,
            'region' => $region,
        ], ['id' => (int)$row['id']]);
        $updated++;
    }
    return $updated;
}

function sod_should_inject_frontend_ui(): bool {
    if (is_admin() || sod_is_dashboard_route()) return true;
    global $post;
    if (!$post || empty($post->post_content)) return false;
    foreach ([
        'sod_powerbi','sod_ticker','sod_threat_analyzer','sod_command_deck',
        'osint_dashboard','osint_map','osint_command_center','osint_dashboard_panel',
        'strategic_osint_powerbi','strategic_osint_ticker','strategic_osint_v7_brief'
    ] as $tag) {
        if (has_shortcode((string)$post->post_content, $tag)) return true;
    }
    return false;
}

function sod_should_enqueue_public_assets(): bool {
    if (sod_is_dashboard_route()) return true;
    if (is_admin()) return false;
    global $post;
    if (!$post || empty($post->post_content)) return false;
    return sod_should_inject_frontend_ui();
}

function sod_reclassify_event_after_insert(int $event_id): bool {
    global $wpdb;
    if ($event_id <= 0) return false;
    $table = $wpdb->prefix . 'so_news_events';
    $row = $wpdb->get_row($wpdb->prepare("SELECT * FROM {$table} WHERE id = %d", $event_id), ARRAY_A);
    if (!$row) return false;

    $item = [
        'title' => (string)($row['title'] ?? ''),
        'link' => (string)($row['link'] ?? ''),
        'source' => (string)($row['source_name'] ?? $row['source'] ?? ''),
        'source_name' => (string)($row['source_name'] ?? $row['source'] ?? ''),
        'date' => (string)($row['event_timestamp'] ?? ''),
        'image_url' => (string)($row['image_url'] ?? ''),
    ];
    $analyzed = SO_OSINT_Engine::process_event($item);
    if (!is_array($analyzed)) return false;
    $analyzed = sod_finalize_reanalysis_payload($row, $item, $analyzed);
    $update = [
        'intel_type' => (string)($analyzed['intel_type'] ?? ($row['intel_type'] ?? '')),
        'tactical_level' => (string)($analyzed['tactical_level'] ?? ($row['tactical_level'] ?? '')),
        'region' => (string)($analyzed['region'] ?? ($row['region'] ?? '')),
        'actor_v2' => (string)($analyzed['actor_v2'] ?? ($row['actor_v2'] ?? '')),
        'score' => (int)($analyzed['score'] ?? ($row['score'] ?? 0)),
        'war_data' => (string)($analyzed['war_data'] ?? ($row['war_data'] ?? '{}')),
        'field_data' => (string)($analyzed['field_data'] ?? ($row['field_data'] ?? '{}')),
        'target_v2' => (string)($analyzed['target_v2'] ?? ($row['target_v2'] ?? '')),
        'context_actor' => (string)($analyzed['context_actor'] ?? ($row['context_actor'] ?? '')),
        'intent' => (string)($analyzed['intent'] ?? ($row['intent'] ?? '')),
        'weapon_v2' => (string)($analyzed['weapon_v2'] ?? ($row['weapon_v2'] ?? '')),
    ];
    $update = sod_db_filter_data_by_columns($table, $update);
    if (empty($update)) return false;
    $wpdb->update($table, $update, ['id' => $event_id], sod_db_build_formats($update), ['%d']);
    return true;
}

add_action('so_reclassify_event_after_insert', function ($event_id) {
    sod_reclassify_event_after_insert((int)$event_id);
}, 10, 1);


// ===== NEW BANK-DRIVEN CLASSIFICATION ENGINE =====
function sod_get_all_banks(){
    sod_self_heal_mojibake_options();
    return [
        'actors' => sod_filter_bank_values(sod_normalize_string_list((array)get_option('sod_bank_actors', [])), 'actors'),
        'targets' => sod_filter_bank_values(sod_normalize_string_list((array)get_option('sod_bank_targets', [])), 'targets'),
        'contexts' => sod_filter_bank_values(sod_normalize_string_list((array)get_option('sod_bank_contexts', [])), 'contexts'),
        'intents' => sod_filter_bank_values(sod_normalize_string_list((array)get_option('sod_bank_intents', [])), 'intents'),
        'weapons' => sod_filter_bank_values(sod_normalize_string_list((array)get_option('sod_bank_weapons', [])), 'weapons'),
    ];
}

/**
 * مطابقة متقدمة مع دعم الأوزان والكلمات المفتاحية والسياق
 */
function sod_match_bank($text, $bank_values, $options = []) {
    $matches = [];
    $text = (string)$text;
    $text_lower = mb_strtolower($text);
    $text_clean = so_clean_text($text);

    foreach ($bank_values as $key => $value) {
        // دعم المصفوفات ذات المفاتيح والقيم (للأوزان المخصصة)
        if (is_array($value)) {
            $term = trim((string)($value['term'] ?? ''));
            $weight = (float)($value['weight'] ?? 1.0);
            $keywords = isset($value['keywords']) ? (array)$value['keywords'] : [$term];
        } else {
            $term = trim((string)$value);
            $weight = 1.0;
            $keywords = [$term];
        }

        if ($term === '') continue;

        $score = 0;
        $matched_keyword = '';

        // 1. مطابقة الكلمات المفتاحية داخل النص
        foreach ($keywords as $kw) {
            $kw = trim((string)$kw);
            if ($kw === '') continue;

            if (mb_stripos($text, $kw) !== false) {
                $score += 15 * $weight;
                if ($matched_keyword === '') $matched_keyword = $kw;

                if (preg_match('/(^|[^\p{L}\p{N}_])' . preg_quote($kw, '/') . '([^\p{L}\p{N}_]|$)/ui', $text)) {
                    $score += 10 * $weight;
                }
            }
        }

        // 2. مطابقة مباشرة للـ term بدل similar_text المكلف
        if ($score === 0 && mb_stripos($text_clean, $term) !== false) {
            $score += 6 * $weight;
        }

        // 3. مطابقة الجذور (للغة العربية)
        if (function_exists('sod_arabic_root_match')) {
            $root_score = sod_arabic_root_match($text_clean, $term);
            if ($root_score > 0) {
                $score += $root_score * $weight;
            }
        }

        // 4. مكافأة السياق القريب
        if (!empty($options['context_words']) && $score > 0) {
            foreach ((array)$options['context_words'] as $ctx_word) {
                if ($ctx_word !== '' && mb_stripos($text, $ctx_word) !== false) {
                    $score += 5 * $weight;
                    break;
                }
            }
        }

        // 5. عقوبة للمدخلات العامة جداً ضمن بنك الفاعلين
        if (!empty($options['bank']) && $options['bank'] === 'actors') {
            $generic_actor_terms = ['إسرائيل', 'اسرائيل', 'أمريكا', 'امريكا', 'الولايات المتحدة', 'إيران', 'ايران'];
            if (in_array($term, $generic_actor_terms, true)) {
                $score *= 0.55;
            }
        }

        if ($score > 0) {
            $matches[$term] = [
                'score' => round($score, 2),
                'keyword' => $matched_keyword,
                'weight' => $weight,
            ];
        }
    }

    // ترتيب حسب النتيجة
    uasort($matches, function($a, $b) {
        return $b['score'] <=> $a['score'];
    });

    return $matches;
}

/**
 * استخراج الجذر العربي للمطابقة الدلالية
 */
function sod_arabic_root_match($text, $term) {
    // جذور شائعة للأفعال المتعلقة بالصراع
    $roots = [
        'قصف' => ['يقصف', 'قصف', 'تقصف', 'مقصف'],
        'ضرب' => ['يضرب', 'ضرب', 'تضرب', 'مضروب'],
        'استهد' => ['يستهدف', 'استهدف', 'تستهدف', 'مستهدف'],
        'أطل' => ['يطلق', 'أطلق', 'تطلق', 'إطلاق'],
        'داهم' => ['يداهم', 'داهم', 'تداهم', 'مداهمة'],
        'اغت' => ['يغتال', 'اغتيال', 'تغتال', 'مغتال'],
    ];
    
    $score = 0;
    foreach ($roots as $root => $variations) {
        if (stripos($term, $root) !== false) {
            foreach ($variations as $var) {
                if (stripos($text, $var) !== false) {
                    $score += 8;
                }
            }
        }
    }
    return $score;
}

function sod_resolve_field($text, $bank){
    $banks = sod_get_all_banks();
    $vals = isset($banks[$bank]) ? $banks[$bank] : [];
    $m = sod_match_bank($text, $vals, ['bank' => $bank]);
    return !empty($m) ? array_key_first($m) : '';
}

function sod_detect_action_type($text) {
    $text = so_clean_text((string)$text);

    if (preg_match('/(غارة|غارات|قصف|استهداف|هجوم|اشتباك|كمين|إطلاق صواريخ|إطلاق نار|مسيّرة|مسيرة|توغل|اقتحام|اغتيال|تفجير|قنص|اعتقال|اعتراض|طيران حربي|طيران معاد|عدوان|اعتداء إسرائيلي|اعتداء اسرائيلي|مدفعية|دبابات)/ui', $text)) {
        return 'military';
    }

    if (preg_match('/(تصريح|قال|أكد|صرح|أعلن|أفاد|نقل عن|بحسب|وفق|ذكر|كشف|رويترز|وسائل إعلام|وسائل اعلام|تقرير|تحليل|مراسل|صحيفة|قناة|إذاعة|تغطية خاصة)/ui', $text)) {
        return 'statement';
    }

    if (preg_match('/(مفاوضات|محادثات|لقاء|اجتماع|اتفاق|قمة|وفد|دبلوماسي|ديبلوماسي|مؤتمر|وزارة الخارجية)/ui', $text)) {
        return 'diplomatic';
    }

    return 'unknown';
}


function sod_detect_event_mode($text) {
    $text = so_clean_text((string)$text);

    if (preg_match('/(لقد انتهى الحدث|انتهى الحدث|انذار احمر|إنذار أحمر|صفارات الإنذار|صافرات الإنذار|الجبهة الداخلية|تسوفار|خشية تسلل|تسلل طائرة بدون طيار|منطقة إنذار)/ui', $text)) {
        return 'defensive_alert';
    }

    if (
        preg_match('/(مفاوضات|محادثات|لقاء|اجتماع|وفد|قمة|مؤتمر|تصريح|قال|أكد|صرح|أعلن|أفاد|رويترز|مصدر دبلوماسي|وزارة الخارجية|وقف إطلاق النار|هدنة|ترحب|نأمل|يلتقي|التقى|المتحدثة باسم|المتحدث باسم|مستشار|البيت الأبيض|البيت الابيض|الحكومة الإيرانية|الخارجية الإيرانية|وزارة الصحة|وزارة الخدمة المدنية|تقرير|تحليل|صورة|صور)/ui', $text)
        && !preg_match('/(غارة|قصف|استهداف|هجوم|اشتباك|اقتحام|توغل|صاروخ|صواريخ|مسيّرة|مسيرة|دبابة|ثكنة|رشقة|صلية|كمين|أغار|اعتداء إسرائيلي|تم رصد غارة|تم رصد قصف|تم رصد اقتحام|تم رصد هجوم|استهدفنا|استهدف مجاهدونا)/ui', $text)
    ) {
        return 'political';
    }

    if (preg_match('/(غارة|قصف|استهداف|هجوم|اشتباك|اقتحام|توغل|صاروخ|صواريخ|مسيّرة|مسيرة|دبابة|ثكنة|رشقة|صلية|كمين|أغار|اعتداء إسرائيلي|تم رصد غارة|تم رصد قصف|تم رصد اقتحام|تم رصد هجوم|استهدفنا|استهدف مجاهدونا|إطلاق نار|استطلاع بطائرة مسيّرة)/ui', $text)) {
        return 'kinetic';
    }

    return 'unknown';
}

function sod_is_non_military_context($text) {
    $text = so_clean_text((string)$text);

    if (preg_match('/(مفاوضات|محادثات|وفد|اجتماع|لقاء|قمة|مؤتمر|وزارة الخارجية|دبلوماسي|ديبلوماسي|رئيس الوزراء|الرئيس|وقف إطلاق النار|وقف اطلاق النار|هدنة|اتفاق|البيت الأبيض|البيت الابيض|المتحدثة باسم|المتحدث باسم|مستشار|صورة|صور|تقرير|تحليل|تغطية خاصة|كاتب|محلل سياسي)/ui', $text)) {
        return true;
    }

    if (preg_match('/(تصريح|قال|أكد|صرح|أعلن|أفاد|نقل عن|بحسب|وفق|ذكر|كشف|شجب|استنكر|أدان|رحب|حث|دعا|طالب|ينفي|يرفض|لن تتنازل|لن تتراجع)/ui', $text) && !preg_match('/(غارة|قصف|استهداف|هجوم|اشتباك|إطلاق صواريخ|إطلاق نار|توغل|اقتحام|اغتيال|كمين)/ui', $text)) {
        return true;
    }

    if (preg_match('/(وسائل إعلام|وسائل اعلام|صحيفة|قناة|إذاعة|تحليل|تقرير إعلامي|تغطية خاصة|كاتب|محلل سياسي|رويترز|الغارديان|نيويورك تايمز|العربية|الميادين|الجزيرة|نتبلوكس|سي بي اس|سی‌بی‌اس)/ui', $text) && !preg_match('/(غارة|قصف|استهداف|هجوم|اشتباك|إطلاق صواريخ|توغل|اقتحام|اغتيال|كمين)/ui', $text)) {
        return true;
    }

    return false;
}

function sod_prepare_actor_bank($actors_bank) {
    $prepared = [];
    foreach ((array)$actors_bank as $item) {
        if (is_array($item)) {
            $term = trim((string)($item['term'] ?? ''));
            $keywords = isset($item['keywords']) ? array_values(array_filter(array_map('trim', (array)$item['keywords']))) : [];
            $weight = (float)($item['weight'] ?? 1.0);
        } else {
            $term = trim((string)$item);
            $keywords = [$term];
            $weight = 1.0;
        }

        if ($term === '') continue;

        if ($term === 'جيش العدو الإسرائيلي') {
            $keywords = array_values(array_unique(array_filter(array_merge($keywords, ['الجيش الإسرائيلي','جيش الاحتلال','قوات الاحتلال','طيران الاحتلال','الطائرات الحربية الإسرائيلية','الطيران الحربي المعادي','العدو الإسرائيلي','الاحتلال الإسرائيلي']))));
            $weight = max($weight, 1.2);
        }

        if (in_array($term, ['إسرائيل','اسرائيل'], true)) {
            $keywords = array_values(array_filter($keywords, function($kw) {
                return !in_array(trim((string)$kw), ['إسرائيل','اسرائيل'], true);
            }));
            $weight = min($weight, 0.45);
        }

        $prepared[] = [
            'term' => $term,
            'keywords' => !empty($keywords) ? $keywords : [$term],
            'weight' => $weight,
        ];
    }

    return $prepared;
}

function sod_extract_actors_ranked($text, $bank) {
    $matches = sod_match_bank($text, $bank, ['bank' => 'actors']);
    if (empty($matches)) return [];
    return array_slice(array_keys($matches), 0, 3);
}

function sod_detect_target_from_text($text, $targets_bank = []) {
    $text = so_clean_text((string)$text);

    if (preg_match('/(?:استهدف(?:ت)?|قصف(?:ت)?|هاجم(?:ت)?|أغار(?:ت)? على|شن(?:ت)? غارة على|توغل(?:ت)? في|اقتحم(?:ت)?|ضرب(?:ت)?|اعترض(?:ت)?)(?:\s+[^\s]+){0,4}\s+(?:على|في)?\s*([^\.،
]{2,120})/ui', $text, $m)) {
        $candidate = trim((string)$m[1]);
        $candidate = preg_replace('/\s+(?:مما|ما أدى|ما ادى|وذلك|حيث|بعد|قبل).*$/u', '', $candidate);
        if ($candidate !== '') return $candidate;
    }

    if (!empty($targets_bank)) {
        $target_matches = sod_match_bank($text, $targets_bank, ['bank' => 'targets']);
        if (!empty($target_matches)) return (string)array_key_first($target_matches);
    }

    return '';
}


function sod_context_memory_get(): array {
    $memory = get_option('sod_context_memory_patterns', []);
    return is_array($memory) ? $memory : [];
}

function sod_context_memory_save_feedback(string $title, array $payload = []): void {
    $title = so_clean_text($title);
    if ($title === '') return;

    $patterns = sod_context_memory_get();
    $entry = [
        'fingerprint' => so_build_title_fingerprint($title),
        'title' => $title,
        'actor_v2' => trim((string)($payload['actor_v2'] ?? '')),
        'intel_type' => trim((string)($payload['intel_type'] ?? '')),
        'region' => trim((string)($payload['region'] ?? '')),
        'context_actor' => trim((string)($payload['context_actor'] ?? '')),
        'intent' => trim((string)($payload['intent'] ?? '')),
        'weapon_v2' => trim((string)($payload['weapon_v2'] ?? '')),
        'saved_at' => time(),
    ];

    if ($entry['actor_v2'] === '') return;

    $patterns[] = $entry;
    if (count($patterns) > 400) {
        $patterns = array_slice($patterns, -400);
    }
    update_option('sod_context_memory_patterns', $patterns, false);
}





function sod_auto_dataset_training_from_newslog(int $limit = 2500): array {
    global $wpdb;
    $table = $wpdb->prefix . 'so_news_events';
    $rows = $wpdb->get_results($wpdb->prepare(
        "SELECT id,title,source_name,intel_type,tactical_level,region,actor_v2,weapon_v2,target_v2,context_actor,intent,score,war_data,field_data
         FROM {$table}
         ORDER BY id DESC
         LIMIT %d",
        max(100, $limit)
    ), ARRAY_A);

    if (empty($rows)) return ['scanned'=>0,'learned'=>0];

    $learned = 0;
    foreach ($rows as $row) {
        $title = so_clean_text((string)($row['title'] ?? ''));
        if ($title === '') continue;

        $manual = sod_get_manual_override_state($row);
        $wd = sod_parse_json_array($row['war_data'] ?? '');
        $evaluationMode = (string)($wd['evaluation_mode'] ?? '');

        $trusted = !empty($manual['enabled'])
            || $evaluationMode === 'manual_override'
            || ((int)($row['score'] ?? 0) >= 130 && !empty($row['actor_v2']) && (string)$row['actor_v2'] !== 'فاعل غير محسوم');

        if (!$trusted) continue;

        $payload = [
            'title' => $title,
            'actor_v2' => (string)($row['actor_v2'] ?? ''),
            'region' => (string)($row['region'] ?? ''),
            'intel_type' => (string)($row['intel_type'] ?? ''),
            'tactical_level' => (string)($row['tactical_level'] ?? ''),
            'score' => (int)($row['score'] ?? 0),
            'target_v2' => (string)($row['target_v2'] ?? ''),
            'context_actor' => (string)($row['context_actor'] ?? ''),
            'intent' => (string)($row['intent'] ?? ''),
            'weapon_v2' => (string)($row['weapon_v2'] ?? ''),
        ];

        SO_Manual_Learning::save_feedback(['title'=>$title,'source_name'=>(string)($row['source_name'] ?? '')], $payload);
        sod_context_memory_save_feedback($title, $payload);

        foreach ([['types',$payload['intel_type']],['levels',$payload['tactical_level']],['regions',$payload['region']],['actors',$payload['actor_v2']],['targets',$payload['target_v2']],['contexts',$payload['context_actor']],['intents',$payload['intent']],['weapons',$payload['weapon_v2']]] as $pair) {
            [$bank, $value] = $pair;
            if ($value !== '' && $value !== 'فاعل غير محسوم' && $value !== 'غير محدد') {
                sod_add_bank_value($bank, $value);
            }
        }
        $learned++;
    }

    update_option('sod_auto_dataset_training_summary', [
        'time' => time(),
        'scanned' => count($rows),
        'learned' => $learned,
    ], false);

    return ['scanned'=>count($rows),'learned'=>$learned];
}


function sod_actor_engine_v2($text) {
    $text = so_clean_text((string)$text);
    $banks = sod_get_all_banks();
    $actors_bank = sod_prepare_actor_bank($banks['actors']);
    $mode = sod_detect_event_mode($text);
    $target = sod_detect_target_from_text($text, $banks['targets']);

    $memory_hit = sod_context_memory_infer($text);
    if (!empty($memory_hit)) {
        return $memory_hit;
    }

    if ($mode === 'defensive_alert') {
        if ($target === '') {
            if (preg_match('/(?:في|خط(?: ?المواجهة)?[:：]?)\s*([^\.
]{2,80})/ui', $text, $m)) {
                $target = trim((string)$m[1]);
            }
        }
        return [
            'primary_actor' => 'منظومة الإنذار / الجبهة الداخلية',
            'secondary_actor' => 'الأراضي المحتلة (إسرائيل)',
            'target' => $target !== '' ? $target : 'منطقة إنذار',
            'confidence' => 92,
            'reason' => 'defensive-alert',
            'actor_matches' => [],
        ];
    }

    $hard_non_military = sod_is_non_military_context($text)
        || preg_match('/(صورة\s+لل?وفد|الوفد\s+الإيراني\s+المفاوض|إعلام\s+إيراني|رويترز\s+عن\s+مصدر|مصدر\s+دبلوماسي|الجزيرة|العربية|الميادين|تغطية\s+خاصة|كاتب|محلل سياسي|نتبلوكس|وزارة الخدمة المدنية|المؤتمر الشعبي|النائب فضل الله|تاكر كارلسون|ولايتي|المتحدثة باسم الحكومة الإيرانية|البيت الأبيض|البيت الابيض|مستشار المرشد الإيراني|مستشار قائد الثورة الإسلامية)/ui', $text);

    if ($mode === 'political' || $hard_non_military) {
        $named_actor = sod_extract_named_nonmilitary_actor($text);
        return [
            'primary_actor' => $named_actor !== '' ? $named_actor : 'فاعل غير محسوم',
            'secondary_actor' => '',
            'target' => '',
            'confidence' => $named_actor !== '' ? 88 : 96,
            'reason' => $named_actor !== '' ? 'non-military-named-actor' : 'non-military-context',
            'actor_matches' => [],
        ];
    }

    $actor_matches = sod_match_bank($text, $actors_bank, ['bank' => 'actors']);

    if (preg_match('/(المقاومة الإسلامية|حزب الله|مجاهدونا|استهدفنا|استهدف مجاهدونا|بيان صادر عن المقاومة الإسلامية|استهدفنا دبابة|استهدفنا تجمّع|ثكنة|مستوطنة|جنود وآليات جيش العدو)/ui', $text)) {
        $actor_matches = ['المقاومة الإسلامية (حزب الله)' => ['score' => 120, 'keyword' => 'المقاومة الإسلامية', 'weight' => 1.6]] + $actor_matches;
    }
    if (preg_match('/(الجيش الإسرائيلي|جيش الاحتلال|قوات الاحتلال|طيران الاحتلال|غارة إسرائيلية|قصف إسرائيلي|اعتداء إسرائيلي|توغل قوات الاحتلال|مستوطنون يقتحمون|الطيران الحربي المعادي|طائرات الاحتلال|طيران العدو|العدو شن غارة|قصف طيران الاحتلال)/ui', $text)) {
        $actor_matches = ['جيش العدو الإسرائيلي' => ['score' => 120, 'keyword' => 'الجيش الإسرائيلي', 'weight' => 1.6]] + $actor_matches;
    }
    if (preg_match('/(^|\s)(حماس|حركة حماس|كتائب القسام)(\s|:|$)/ui', $text)) {
        $actor_matches = ['كتائب القسام (حماس)' => ['score' => 116, 'keyword' => 'حماس', 'weight' => 1.5]] + $actor_matches;
    }
    if (preg_match('/(^|\s)(سرايا القدس|الجهاد الإسلامي)(\s|:|$)/ui', $text)) {
        $actor_matches = ['سرايا القدس (الجهاد الإسلامي)' => ['score' => 114, 'keyword' => 'سرايا القدس', 'weight' => 1.5]] + $actor_matches;
    }

    $actors = array_slice(array_keys($actor_matches), 0, 3);
    $primary = $actors[0] ?? 'فاعل غير محسوم';
    $secondary = $actors[1] ?? '';

    if ($primary === 'فاعل غير محسوم') {
        if (preg_match('/(استهداف دبابة إسرائيلية|استهداف موقع|استهدفنا تجمعا|استهدفنا تجمّعا|ثكنة يعرا|مستوطنة نهاريا|جنود وآليات جيش العدو)/ui', $text)) {
            $primary = 'المقاومة الإسلامية (حزب الله)';
        } elseif (preg_match('/(غارة إسرائيلية|طيران الاحتلال|الطيران الحربي المعادي|طائرات الاحتلال|قوات الاحتلال|مستوطنون يقتحمون)/ui', $text)) {
            $primary = 'جيش العدو الإسرائيلي';
        }
    }

    if (preg_match('/(إعلام|قناة|رويترز|العربية|الميادين|الجزيرة|صحيفة|تغطية|محلل|كاتب)/ui', $primary)) {
        $primary = 'فاعل غير محسوم';
        $secondary = '';
    }

    $confidence = 42;
    if (!empty($actor_matches) && $primary !== 'فاعل غير محسوم') {
        $top_score = (float)($actor_matches[$primary]['score'] ?? 0);
        $confidence += min(35, (int)round($top_score));
    }
    if ($target !== '') $confidence += 10;
    if ($secondary !== '') $confidence += 4;
    if ($primary === 'فاعل غير محسوم') $confidence = min($confidence, 45);
    $confidence = max(15, min(96, $confidence));

    $result = [
        'primary_actor' => $primary,
        'secondary_actor' => $secondary,
        'target' => $target,
        'confidence' => $confidence,
        'reason' => 'kinetic-or-operational-context',
        'actor_matches' => $actor_matches,
    ];

    return sod_governor_ai($result, $text);
}

function sod_resolve_actor($text){
    $result = sod_actor_engine_v2($text);
    return trim((string)($result['primary_actor'] ?? '')) ?: 'فاعل غير محسوم';
}

function sod_classify_event_v3($event){
    $text = so_clean_text((string)($event['title'] ?? '') . ' ' . (string)($event['content'] ?? ''));

    // استخراج سياق إضافي لتحسين المطابقة
    $context_words = [];
    if (preg_match('/(لبنان|فلسطين|سوريا|العراق|اليمن|إيران|ايران|إسرائيل|اسرائيل)/u', $text, $m)) {
        $context_words[] = $m[1];
    }

    $bucket = function_exists('so_detect_content_bucket') ? so_detect_content_bucket($text) : 'general';
    $mode = sod_detect_event_mode($text);
    $actor_ai = sod_governor_ai(sod_actor_engine_v2($text), $text);

    $target_v2 = $actor_ai['target'] !== '' ? $actor_ai['target'] : sod_resolve_field($text, 'targets');
    $context_actor = ($bucket === 'statement' || $bucket === 'report') ? '' : sod_resolve_field($text, 'contexts');
    $intent = sod_resolve_field($text, 'intents');
    $weapon_v2 = sod_resolve_field($text, 'weapons');

    if ($mode === 'defensive_alert') {
        $context_actor = 'إنذار دفاعي';
        $intent = 'دفاع';
        if ($weapon_v2 === '') $weapon_v2 = 'إنذار / اعتراض';
    } elseif ($mode === 'kinetic') {
        if ($intent === '') $intent = 'هجوم';
    }

    if ($bucket === 'statement' || $bucket === 'report' || sod_is_non_military_context($text)) {
        $named_actor = sod_extract_named_nonmilitary_actor($text);
        if ($mode !== 'kinetic') {
            $actor_ai['primary_actor'] = $named_actor !== '' ? $named_actor : 'فاعل غير محسوم';
            $actor_ai['secondary_actor'] = '';
            $actor_ai['target'] = '';
            $actor_ai['confidence'] = $named_actor !== '' ? max((int)($actor_ai['confidence'] ?? 20), 70) : min((int)($actor_ai['confidence'] ?? 20), 35);
            $actor_ai['reason'] = $named_actor !== '' ? 'statement-named-actor' : 'statement-or-report-context';
        }
    }

    $resolved_region = (string)sod_resolve_field($text, 'regions');
    $early_warning = sod_early_warning_ai($text, [
        'actor' => (string)($actor_ai['primary_actor'] ?? ''),
        'region' => $resolved_region,
        'intel_type' => (string)$bucket,
    ]);
    $prediction = sod_prediction_layer($text, [
        'actor' => (string)($actor_ai['primary_actor'] ?? ''),
        'region' => $resolved_region,
        'intel_type' => (string)$bucket,
        'target' => (string)$target_v2,
        'weapon' => (string)$weapon_v2,
        'early_warning' => $early_warning,
    ]);

    return [
        'actor_v2' => $actor_ai['primary_actor'],
        'target_v2' => $target_v2,
        'context_actor' => $actor_ai['secondary_actor'] !== '' ? $actor_ai['secondary_actor'] : $context_actor,
        'intent' => $intent,
        'weapon_v2' => $weapon_v2,
        '_ai_v2' => [
            'confidence' => (int)($actor_ai['confidence'] ?? 20),
            'reason' => (string)($actor_ai['reason'] ?? ''),
            'bucket' => $bucket,
        ],
        '_early_warning' => $early_warning,
        '_prediction' => $prediction,
        '_match_details' => [
            'actor_matches' => !empty($actor_ai['actor_matches']) ? $actor_ai['actor_matches'] : sod_match_bank($text, sod_prepare_actor_bank(sod_get_all_banks()['actors']), ['context_words' => $context_words, 'bank' => 'actors']),
            'weapon_matches' => sod_match_bank($text, sod_get_all_banks()['weapons'], ['context_words' => $context_words, 'bank' => 'weapons']),
        ]
    ];
}


function sod_early_warning_normalize_window($hours) {
    $hours = max(1, (int)$hours);
    if ($hours <= 3) return 'قصير جدًا (1–3 ساعات)';
    if ($hours <= 6) return 'قصير (3–6 ساعات)';
    if ($hours <= 12) return 'قصير/متوسط (6–12 ساعة)';
    if ($hours <= 24) return 'متوسط (12–24 ساعة)';
    return 'أبعد من 24 ساعة';
}

function sod_early_warning_ai($text, $context = []) {
    $text = so_clean_text((string)$text);
    $lower = mb_strtolower($text);

    $score = 0;
    $indicators = [];
    $scenario = 'مراقبة اعتيادية';
    $direction = 'مستقر/غير محسوم';
    $time_hours = 24;
    $confidence = 35;

    $is_alert_end = preg_match('/(لقد انتهى الحدث|انتهى الحدث|تم رفع الانذار|تم رفع الإنذار|زوال الخطر|عودة الحياة إلى طبيعتها)/ui', $lower) === 1;
    $is_defensive_alert = preg_match('/(انذار|إنذار|صفارات|صافرات|الجبهة الداخلية|تسوفار|اعتراض|رصد إطلاق|تسلل طائرة|خطالمواجهة|خط المواجهة)/ui', $lower) === 1;
    $is_kinetic = preg_match('/(غارة|قصف|استهداف|هجوم|اشتباك|توغل|اقتحام|إطلاق صواريخ|صلية صاروخية|مسيّرة|مسيرة|تفجير|اغتيال)/ui', $lower) === 1;
    $is_statement = preg_match('/(مفاوضات|محادثات|تصريح|قال|أكد|رويترز|اجتماع|لقاء|وفد|مؤتمر صحفي)/ui', $lower) === 1 && !$is_kinetic;

    if ($is_alert_end) {
        return [
            'level' => 'منخفض',
            'score' => 8,
            'confidence' => 90,
            'direction' => 'انحسار فوري',
            'window_hours' => 1,
            'window_label' => sod_early_warning_normalize_window(1),
            'scenario' => 'انتهاء حدث إنذاري/دفاعي بدون إشارة تصعيد فوري',
            'indicators' => ['انتهاء الحدث', 'رفع/انحسار الإنذار'],
            'reason' => 'alert-ended',
        ];
    }

    if ($is_statement) {
        $score += 12;
        $confidence += 5;
        $indicators[] = 'سياق سياسي/إعلامي';
        if (preg_match('/(تهديد|توعد|لن نسمح|سنرد|الرد قادم|سندفع الثمن|خط أحمر)/ui', $lower)) {
            $score += 20;
            $time_hours = min($time_hours, 24);
            $scenario = 'تصعيد لفظي قد يتحول إلى فعل ميداني';
            $direction = 'تصعيد سياسي';
            $indicators[] = 'تهديد مباشر';
        }
    }

    $rules = [
        ['pattern' => '/(استنفار|رفع الجهوزية|رفع الجهوزيه|تعزيزات|حشد|تحريك قوات|حشود|إخلاء|إخلاءات|فتح الملاجئ|إغلاق المجال الجوي|تعليق الرحلات)/ui', 'add' => 22, 'indicator' => 'تهيئة/تحضير ميداني', 'window' => 12],
        ['pattern' => '/(انذار|إنذار|صفارات|صافرات|الجبهة الداخلية|تسوفار|اعتراض|رصد إطلاق|تسلل طائرة|طائرة بدون طيار)/ui', 'add' => 18, 'indicator' => 'إشارة إنذار/دفاع جوي', 'window' => 6],
        ['pattern' => '/(غارة|قصف|استهداف|هجوم|اشتباك|توغل|اقتحام|إطلاق صواريخ|صلية صاروخية|اغتيال|تفجير)/ui', 'add' => 28, 'indicator' => 'فعل هجومي قائم', 'window' => 6],
        ['pattern' => '/(رد|رداً على|انتقام|ثأر|الرد قادم|في إطار الرد|ضمن الرد)/ui', 'add' => 20, 'indicator' => 'حلقة رد/رد مقابل', 'window' => 12],
        ['pattern' => '/(دبابة|ميركافا|ثكنة|موقع عسكري|قاعدة|مطار|منشأة|بنية تحتية|مفاعل|منصة غاز|ميناء)/ui', 'add' => 14, 'indicator' => 'أهداف حساسة/عسكرية', 'window' => 12],
        ['pattern' => '/(باليستي|فرط صوتي|كروز|مسيرة انتحارية|صاروخ موجّه|مضاد للدروع)/ui', 'add' => 16, 'indicator' => 'وسيلة عالية الخطورة', 'window' => 12],
        ['pattern' => '/(لبنان|فلسطين|غزة|الضفة|الأراضي المحتلة|إسرائيل|اسرائيل|إيران|ايران|سوريا|العراق|اليمن)/ui', 'add' => 6, 'indicator' => 'ساحة توتر معروفة', 'window' => 24],
    ];

    foreach ($rules as $rule) {
        if (preg_match($rule['pattern'], $lower)) {
            $score += $rule['add'];
            $indicators[] = $rule['indicator'];
            $time_hours = min($time_hours, (int)$rule['window']);
        }
    }

    $actor = trim((string)($context['actor'] ?? $context['actor_v2'] ?? ''));
    $region = trim((string)($context['region'] ?? ''));
    $intel_type = trim((string)($context['intel_type'] ?? ''));

    if ($actor !== '' && !in_array($actor, ['فاعل غير محسوم', 'فاعل سياقي غير مباشر', 'جهة غير معلنة', 'غير محدد'], true)) {
        $score += 10;
        $confidence += 8;
        $indicators[] = 'فاعل محدد';
    }
    if ($region !== '' && $region !== 'غير محدد') {
        $score += 6;
        $confidence += 4;
    }
    if (in_array($intel_type, ['عسكري/أمني', 'تكتيكي/ميداني', 'رصد/إنذار'], true)) {
        $score += 8;
        $confidence += 4;
    }

    if ($is_defensive_alert && !$is_kinetic) {
        $scenario = 'احتمال تجدّد الإنذار أو انتقاله إلى رشقة/اختراق قريب';
        $direction = 'توتر دفاعي';
    } elseif ($is_kinetic) {
        $scenario = 'خطر استمرار الضربات أو موجة رد مقابلة في المدى القريب';
        $direction = 'تصاعد ميداني';
    } elseif ($scenario === 'مراقبة اعتيادية') {
        $scenario = 'لا توجد دلائل كافية على حدث وشيك، لكن الساحة تحتاج متابعة';
    }

    if (preg_match('/(حشد|تعزيزات|استنفار|إخلاء)/ui', $lower) && preg_match('/(غارة|قصف|صاروخ|مسيّرة|اشتباك)/ui', $lower)) {
        $score += 12;
        $confidence += 8;
        $indicators[] = 'تلازم التحضير مع الفعل الميداني';
        $time_hours = min($time_hours, 6);
    }

    $score = max(0, min(100, (int)round($score)));
    $confidence = max(20, min(95, (int)round($confidence + ($score / 8))));

    if ($score >= 75) $level = 'حرج';
    elseif ($score >= 55) $level = 'مرتفع';
    elseif ($score >= 30) $level = 'متوسط';
    else $level = 'منخفض';


    return [
        'level' => $level,
        'score' => $score,
        'confidence' => $confidence,
        'direction' => $direction,
        'window_hours' => (int)$time_hours,
        'window_label' => sod_early_warning_normalize_window($time_hours),
        'scenario' => $scenario,
        'indicators' => array_values(array_unique($indicators)),
        'reason' => $is_kinetic ? 'kinetic-pattern' : ($is_defensive_alert ? 'defensive-pattern' : ($is_statement ? 'statement-pattern' : 'baseline-monitoring')),
    ];
}

function sod_rule_engine_scores($text, $context = []) {
    $text = so_clean_text((string)$text);
    $scores = [
        'attack' => 0,
        'defensive' => 0,
        'political' => 0,
        'media' => 0,
        'logistics' => 0,
    ];

    $rules = [
        'attack' => [
            '/(غارة|قصف|استهداف|هجوم|اشتباك|توغل|اقتحام|إطلاق صواريخ|صلية صاروخية|اغتيال|تفجير|قصف مدفعي|إطلاق نار من دبابات|استهداف دبابة|ثكنة|موقع عسكري)/ui' => 26,
            '/(مسيّرة|مسيرة|صاروخ|صاروخي|مضاد للدروع|ميركافا|محلّقة انقضاضية)/ui' => 18,
            '/(الجيش الإسرائيلي|طيران العدو|طائرات الاحتلال|قوات الاحتلال|المقاومة الإسلامية|حزب الله|استهدفنا|استهدف مجاهدونا)/ui' => 20,
        ],
        'defensive' => [
            '/(انذار|إنذار|صفارات|صافرات|الجبهة الداخلية|تسوفار|خطالمواجهة|خط المواجهة|لقد انتهى الحدث|تسلل طائرة بدون طيار|اعتراض)/ui' => 26,
            '/(انذار احمر|إنذار أحمر|رفع الإنذار|زوال الخطر|خشية تسلل)/ui' => 16,
        ],
        'political' => [
            '/(مفاوضات|محادثات|وفد|اجتماع|لقاء|وزارة|وزير|الرئيس|رئيس الوزراء|الخارجية|هدنة|وقف إطلاق النار|مصدر دبلوماسي)/ui' => 24,
            '/(رويترز|تسنيم|أكد|قال|أعلن|أفاد|أوضح|رحب|طالب|ندد|استنكر)/ui' => 12,
        ],
        'media' => [
            '/(تقرير|تحليل|تغطية خاصة|برنامج|مقابلة|مراسل|وسائل إعلام|صحيفة|وكالة|الكاتب والمحلل السياسي)/ui' => 22,
            '/(إعلام إيراني|إعلام العدو|القناة 12|فوكس نيوز|بلومبرغ|واشنطن بوست|الغارديان)/ui' => 12,
        ],
        'logistics' => [
            '/(مضيق هرمز|الملاحة|الموانئ|الوقود|الغاز|النفط|إمدادات|ناقلة|ناقلات|شحن|بنوك أجنبية|أصول مجمدة)/ui' => 18,
        ],
    ];

    foreach ($rules as $type => $patterns) {
        foreach ($patterns as $pattern => $points) {
            if (preg_match($pattern, $text)) {
                $scores[$type] += $points;
            }
        }
    }

    $actor = trim((string)($context['actor'] ?? ''));
    $region = trim((string)($context['region'] ?? ''));
    $intel_type = trim((string)($context['intel_type'] ?? ''));
    if ($actor !== '' && !in_array($actor, ['فاعل غير محسوم', 'جهة غير معلنة', 'غير محدد'], true)) {
        if (mb_stripos($actor, 'الإنذار') !== false) $scores['defensive'] += 12;
        elseif (preg_match('/(حزب الله|المقاومة|جيش العدو الإسرائيلي)/ui', $actor)) $scores['attack'] += 14;
    }
    if ($region !== '' && $region !== 'غير محدد') {
        $scores['attack'] += 4;
        $scores['defensive'] += 4;
    }
    if (in_array($intel_type, ['عسكري/أمني', 'أمني', 'رصد/إنذار'], true)) $scores['attack'] += 10;
    if ($intel_type === 'سياسي') $scores['political'] += 12;
    if ($intel_type === 'إعلامي') $scores['media'] += 12;

    arsort($scores);
    return $scores;
}

function sod_confidence_system($scores, $boost = 0) {
    $vals = array_values((array)$scores);
    $top = (int)($vals[0] ?? 0);
    $second = (int)($vals[1] ?? 0);
    $gap = max(0, $top - $second);

    $confidence = 35;
    if ($top >= 70) $confidence = 92;
    elseif ($top >= 50) $confidence = 82;
    elseif ($top >= 35) $confidence = 72;
    elseif ($top >= 20) $confidence = 58;

    if ($gap >= 18) $confidence += 8;
    elseif ($gap <= 6) $confidence -= 12;

    $confidence += (int)$boost;
    return max(20, min(97, $confidence));
}

function sod_prediction_layer($text, $context = []) {
    $text = so_clean_text((string)$text);
    $scores = sod_rule_engine_scores($text, $context);
    $mode = array_key_first($scores);
    $early = (isset($context['early_warning']) && is_array($context['early_warning'])) ? $context['early_warning'] : [];
    $confidence = sod_confidence_system($scores, (int)($early['confidence'] ?? 0) / 10);
    $risk = max((int)($early['score'] ?? 0), (int)($scores[$mode] ?? 0));
    $window = (int)($early['window_hours'] ?? 12);
    $actor = trim((string)($context['actor'] ?? 'فاعل غير محسوم')) ?: 'فاعل غير محسوم';
    $region = trim((string)($context['region'] ?? 'غير محدد')) ?: 'غير محدد';
    $target = trim((string)($context['target'] ?? ''));
    $weapon = trim((string)($context['weapon'] ?? ''));
    $scenario = 'مراقبة اعتيادية';
    $next_step = 'استمرار المراقبة';
    $direction = (string)($early['direction'] ?? 'مستقر/غير محسوم');

    if ($mode === 'attack') {
        $scenario = 'احتمال استمرار الضربات أو الرد المقابل خلال نافذة قصيرة';
        $next_step = 'تعزيز المراقبة التكتيكية ومقارنة النمط بآخر 6–12 ساعة';
        $window = min($window, 6);
        if ($weapon !== '') $scenario .= ' باستخدام ' . $weapon;
    } elseif ($mode === 'defensive') {
        $scenario = 'المرجح تجدّد الإنذار أو انتقاله إلى اعتراض/رشقة محدودة';
        $next_step = 'مراقبة صفارات الإنذار وتقاطعات الرصد مع إطلاقات فعلية';
        $window = min($window, 3);
    } elseif ($mode === 'political') {
        $scenario = 'المشهد سياسي/تفاوضي؛ الخطر المباشر أقل ما لم تظهر لغة تهديد أو تحضير ميداني';
        $next_step = 'تخفيض وزن الفاعل العسكري ومراقبة أي انتقال إلى لهجة تهديد أو حشد';
        $window = max($window, 12);
        $actor = 'فاعل غير محسوم';
    } elseif ($mode === 'media') {
        $scenario = 'الخبر إعلامي/تفسيري؛ لا توجد دلالة كافية على فعل وشيك دون مؤشرات مساندة';
        $next_step = 'عدم ترقية الخبر إلى تهديد إلا إذا ترافق مع إنذار أو فعل ميداني';
        $window = max($window, 12);
        $actor = 'فاعل غير محسوم';
    } elseif ($mode === 'logistics') {
        $scenario = 'مؤشر لوجستي/اقتصادي قد يسبق ضغطاً سياسياً أو تصعيداً على المدى المتوسط';
        $next_step = 'ربط الحدث بمؤشرات الملاحة والإمداد والأسواق قبل رفع الإنذار';
        $window = max($window, 12);
    }

    if (preg_match('/(تهديد|توعد|الرد قادم|لن نسمح|سندفع الثمن|خط أحمر)/ui', $text)) {
        $risk = min(100, $risk + 12);
        $confidence = min(97, $confidence + 6);
        $scenario .= ' مع لهجة تهديد واضحة';
    }

    if (preg_match('/(حشد|تعزيزات|رفع الجهوزية|استنفار|إخلاء|فتح الملاجئ)/ui', $text)) {
        $risk = min(100, $risk + 10);
        $window = min($window, 6);
        $next_step = 'رفع أولوية الإنذار لأن الخبر يجمع بين تحضير وإشارة تصعيد';
    }

    if ($risk >= 80) $level = 'حرج';
    elseif ($risk >= 60) $level = 'مرتفع';
    elseif ($risk >= 35) $level = 'متوسط';
    else $level = 'منخفض';

    return [
        'mode' => (string)$mode,
        'confidence' => (int)$confidence,
        'risk_score' => (int)$risk,
        'risk_level' => $level,
        'expected_window_hours' => (int)$window,
        'expected_window_label' => sod_early_warning_normalize_window($window),
        'predicted_actor' => $actor,
        'predicted_region' => $region,
        'predicted_target' => $target,
        'predicted_weapon' => $weapon,
        'direction' => $direction,
        'scenario' => $scenario,
        'next_step' => $next_step,
        'rule_scores' => $scores,
    ];
}


// ==========================================================================
// 1. الثوابت الموحدة — Unified Constants
// ==========================================================================
define('SO_VERSION',          '17.3.1');
define('SO_PLUGIN_DIR',       plugin_dir_path(__FILE__));
define('SO_PLUGIN_URL',       plugin_dir_url(__FILE__));
define('SO_TELEGRAM_LINK',    'https://t.me/osint_lb');
define('SO_SYNC_LOCK_TTL',    120);

define('SOD_VERSION',         '17.3.1');
define('SOD_PLUGIN_DIR',      plugin_dir_path(__FILE__));
define('SOD_PLUGIN_URL',      plugin_dir_url(__FILE__));
define('SOD_TG_LINK',         'https://t.me/osint_lb');
define('SOD_AJAX_NONCE_ACTION', 'sod_ajax_v13');

// ==========================================================================
// 2. الدوال المساعدة العامة — General Utility Functions
// ==========================================================================

function so_array_get($array, $key, $default = null) {
    return is_array($array) && array_key_exists($key, $array) ? $array[$key] : $default;
}

function so_safe_remote_get($url, $args = []) {
    $defaults = [
        'timeout'     => 10,
        'redirection' => 3,
        'sslverify'   => true,
        'headers'     => ['User-Agent' => 'Beiruttime-OSINT/' . SO_VERSION . '; ' . home_url('/')],
    ];
    return wp_remote_get(esc_url_raw($url), wp_parse_args($args, $defaults));
}

function so_safe_remote_post($url, $args = []) {
    $defaults = [
        'timeout'     => 12,
        'redirection' => 2,
        'sslverify'   => true,
        'headers'     => ['User-Agent' => 'Beiruttime-OSINT/' . SO_VERSION . '; ' . home_url('/')],
    ];
    return wp_remote_post(esc_url_raw($url), wp_parse_args($args, $defaults));
}

function so_normalize_event_link($link) {
    if (!empty($link) && filter_var($link, FILTER_VALIDATE_URL)) return esc_url_raw($link);
    return SO_TELEGRAM_LINK;
}

function so_generate_api_key() { return wp_generate_password(48, false, false); }

function so_extract_telegram_message_link($username, $chunk_html) {
    if (preg_match('/href="(https:\/\/t\.me\/[^"]+)"/i', (string)$chunk_html, $m)) return esc_url_raw($m[1]);
    if (!empty($username) && preg_match('/data-post="([^"]+)"/i', (string)$chunk_html, $m2)) return 'https://t.me/' . ltrim($m2[1], '/');
    return !empty($username) ? 'https://t.me/s/' . sanitize_title($username) : SO_TELEGRAM_LINK;
}

function so_normalize_remote_media_url($url) {
    $url = html_entity_decode((string)$url, ENT_QUOTES | ENT_HTML5, 'UTF-8');
    $url = trim($url, "\"' ");
    if (strpos($url, '//') === 0) $url = 'https:' . $url;
    return esc_url_raw($url);
}

function so_extract_telegram_media_url($chunk_html) {
    $html = (string)$chunk_html;
    if (preg_match('/<a[^>]+class="tgme_widget_message_photo_wrap"[^>]+style="[^"]*url\(([^)]+)\)/i', $html, $m)) return so_normalize_remote_media_url($m[1]);
    if (preg_match('/<video[^>]+src="([^"]+)"/i', $html, $m)) return so_normalize_remote_media_url($m[1]);
    if (preg_match('/<img[^>]+src="([^"]+)"/i', $html, $m)) return so_normalize_remote_media_url($m[1]);
    return '';
}

function so_extract_remote_media_urls($value) {
    $value = trim((string)$value);
    if ($value === '') return [];
    $parts = preg_split('/[\r\n,|]+/', $value);
    $out = [];
    foreach ($parts as $part) { $u = so_normalize_remote_media_url($part); if ($u) $out[] = $u; }
    return array_values(array_unique($out));
}

function so_detect_remote_media_type($url) {
    $url = (string)$url;
    if (!$url) return '';
    if (preg_match('/\.(mp4|mov|webm)(\?|$)/i', $url)) return 'video';
    return 'photo';
}

function so_source_items_limit() { return get_option('so_fetch_latest_only', 1) ? 1 : 5; }

function so_diag_record($type, $source, $status, $items = 0, $http = '', $message = '', $title = '') {
    $log = get_option('so_diag_events', []);
    if (!is_array($log)) $log = [];
    $log[] = [
        'time'    => time(), 'type' => sanitize_text_field((string)$type),
        'source'  => sanitize_text_field((string)$source), 'status' => sanitize_text_field((string)$status),
        'items'   => (int)$items, 'http' => sanitize_text_field((string)$http),
        'message' => sanitize_text_field((string)$message), 'title' => sanitize_text_field((string)$title),
    ];
    if (count($log) > 30) $log = array_slice($log, -30);
    update_option('so_diag_events', $log, false);
}

function so_update_last_sync_summary($raw_count, $inserted, $message = '') {
    update_option('so_last_sync_summary', [
        'time' => time(), 'raw_count' => (int)$raw_count, 'inserted' => (int)$inserted,
        'message' => sanitize_text_field((string)$message),
    ], false);
}

function so_update_insert_pipeline_summary($stats = []) {
    if (!is_array($stats)) $stats = [];
    $defaults = ['raw_count'=>0,'candidate_items'=>0,'skipped_old'=>0,'skipped_keyword'=>0,'process_null'=>0,'duplicate_hash'=>0,'inserted'=>0,'db_failed'=>0];
    $stats = array_merge($defaults, $stats);
    $stats['time'] = time();
    update_option('so_last_insert_pipeline', $stats, false);
}

function so_build_insert_hash($candidate_item, $analyzed) {
    $title  = so_normalize_title_for_dedupe((string)($candidate_item['title'] ?? ''));
    $source = sanitize_title((string)($candidate_item['source'] ?? 'unknown'));
    $actor  = trim((string)($analyzed['actor_v2'] ?? ''));
    $region = trim((string)($analyzed['region'] ?? ''));
    $intel  = trim((string)($analyzed['intel_type'] ?? ''));
    $truth  = trim((string)($analyzed['truth_layer'] ?? ''));
    $bucket = floor(((int)($candidate_item['date'] ?? time())) / 900);
    if ($truth === 'defensive_alert') return so_build_alert_signature((string)($candidate_item['title'] ?? ''));
    return md5($source . '|' . $title . '|' . $actor . '|' . $region . '|' . $intel . '|' . $truth . '|' . $bucket);
}

function so_get_news_events_schema_columns() {
    static $cols = null;
    if ($cols !== null) return $cols;
    global $wpdb;
    $results = $wpdb->get_results("SHOW COLUMNS FROM {$wpdb->prefix}so_news_events", ARRAY_A);
    $cols = [];
    if (is_array($results)) foreach ($results as $row) if (!empty($row['Field'])) $cols[$row['Field']] = true;
    return $cols;
}

function so_filter_news_event_row_for_schema($row) {
    $row = is_array($row) ? $row : [];
    $allowed = so_get_news_events_schema_columns();
    if (empty($allowed)) return $row;
    return array_intersect_key($row, $allowed);
}

function so_get_log_file() {
    $upload_dir = wp_upload_dir();
    $log_dir = $upload_dir['basedir'] . '/beiruttime-osint-logs';
    if (!file_exists($log_dir)) { wp_mkdir_p($log_dir); file_put_contents($log_dir . '/.htaccess', "Deny from all\n"); }
    return $log_dir . '/so_debug.log';
}

function so_log($message, $level = 'INFO') {
    if (!get_option('so_enable_logging', true)) return;
    file_put_contents(so_get_log_file(), '[' . gmdate('Y-m-d H:i:s') . "] [$level] $message\n", FILE_APPEND);
}

function so_limit_text($text, $limit = 500) {
    if (sod_safe_strlen($text) > $limit) return sod_safe_substr($text, 0, $limit) . ' ...';
    return $text;
}

function so_clean_text($text) {
    if (empty($text)) return '';
    $text = html_entity_decode($text, ENT_QUOTES | ENT_HTML5, 'UTF-8');
    $text = wp_strip_all_tags($text);
    $text = preg_replace("/\b(?:https?|ftp):\/\/[a-z0-9\-+&@#\/%?=~_|!:,.;]*[a-z0-9\-+&@#\/%=~_|]/i", '', $text);
    $text = preg_replace("/(?:[0-9٠-٩]{1,2}:[0-9٠-٩]{2})\s*(?:ص|م|صباحا|مساء|am|pm)?/ui", '', $text);
    $promotional = ["/قناة\s+.*?على\s+واتساب/ui", "/للاشتراك\s+في\s+قناة/ui", "/عبر\s+الرابط/ui", "/telegram\.me/ui", "/t\.me/ui"];
    $text = preg_replace($promotional, '', $text);
    $text = preg_replace("/[\x{1F300}-\x{1F6FF}\x{2600}-\x{26FF}\x{2700}-\x{27BF}]/u", '', $text);
    $text = str_replace(["'s","عاجل","عاجل:","عاجل |","🚨","📲","🔴","🟢","💥","⚔️","📌","📊","🎯","▪️"], '', $text);
    $lines = preg_split('/\r\n|\r|\n/', $text);
    $arabic_lines = [];
    foreach ($lines as $line) {
        if (preg_match("/[\p{Arabic}]/u", $line)) {
            $line = preg_replace("/\b[a-zA-Z]{2,}\b/", '', $line);
            $arabic_lines[] = trim($line);
        }
    }
    if (empty($arabic_lines)) return trim(preg_replace('/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F]/', '', $text));
    return preg_replace(["/\(\s*\)/","/\[\s*\]/","/\s+/","/[!]{3,}/"], ['','', ' ','!!!'], trim(implode(' ', $arabic_lines)));
}

function so_normalize_title_for_dedupe($title) {
    $title = so_clean_text((string)$title);
    $title = html_entity_decode($title, ENT_QUOTES | ENT_HTML5, 'UTF-8');
    $title = preg_replace('/#[^\s]+/u', ' ', $title);
    $title = preg_replace('/\b(?:عاجل|خبر عاجل|متداول|أنباء أولية|أولية|حصري|متابعة|تحديث|وسائل إعلام|إعلام العدو|وكالة|رويترز|أ\s*ف\s*ب|القناة\s*\d+|صحيفة|مراسل|نقلاً عن|قال|صرح|أعلن|أكد|أفاد)\b/iu', ' ', $title);
    $title = preg_replace('/\b(?:الولايات المتحدة الأميركية|الولايات المتحدة|إيران|لبنان|فلسطين|الأراضي المحتلة|إسرائيل|غزة|الضفة الغربية|سوريا)\s*[:\-–|]+\s*/iu', ' ', $title);
    $title = preg_replace('/\d+[.:]\d+|\d+/u', ' ', $title);
    $title = preg_replace('/[\p{P}\p{S}]+/u', ' ', $title);
    $title = preg_replace('/\s+/u', ' ', trim(mb_strtolower($title)));
    return $title;
}

function so_build_alert_signature($title) {
    $normalized = so_normalize_title_for_dedupe((string)$title);
    $normalized = preg_replace('/\([0-9\/\-: ]+\)/u', '', $normalized);
    return md5(trim(preg_replace('/\s+/u', ' ', $normalized)));
}

// Cross-source title fingerprint — strips 50% of words and hashes for fuzzy dedup
function so_build_title_fingerprint($title) {
    if (empty($title)) return '';
    $n = so_normalize_title_for_dedupe((string)$title);
    // Remove very common stop-words that don't carry meaning
    $stop = ['في','من','إلى','على','عن','مع','هذا','هذه','ذلك','التي','الذي','كان','يكون',
              'قد','أن','أو','لم','لن','هو','هي','هم','بعد','قبل','حتى','عند','الذين',
              'وفي','وعلى','وإلى','وعن','ويؤكد','ويقول','وأضاف','وأوضح','كما','بين','لكن'];
    $words = array_filter(explode(' ', $n));
    $words = array_values(array_filter($words, fn($w)=>!in_array($w,$stop,true)&&mb_strlen($w)>2));
    if (count($words) < 2) return '';
    // Sort words so "استهداف موقع" == "موقع استهداف" → same fingerprint
    sort($words);
    $significant = array_slice($words, 0, 8); // top 8 unique words
    return md5(implode('|', $significant));
}


function so_title_similarity_percent($a, $b) {
    $a = so_normalize_title_for_dedupe((string)$a);
    $b = so_normalize_title_for_dedupe((string)$b);
    if ($a === '' || $b === '') return 0;
    similar_text($a, $b, $percent);
    return (float) $percent;
}

function so_duplicate_candidate_signature($title, $actor = '', $region = '', $intel = '') {
    $n = so_normalize_title_for_dedupe((string)$title);
    $n = preg_replace('/\b(?:لبنان|فلسطين|الأراضي المحتلة|إسرائيل|اسرائيل|سوريا|إيران|حيفا|نهاريا|كريات شمونة|تل أبيب|تل ابيب|الجنوب|الجليل)\b/iu', ' ', $n);
    $n = preg_replace('/\s+/u', ' ', trim($n));
    return md5($n . '|' . trim((string)$actor) . '|' . trim((string)$region) . '|' . trim((string)$intel));
}

function so_cleanup_duplicate_news_events($limit = 1200) {
    global $wpdb;
    $table = $wpdb->prefix . 'so_news_events';
    $rows = $wpdb->get_results($wpdb->prepare(
        "SELECT id,title,actor_v2,region,intel_type,event_timestamp,title_fingerprint,image_url
         FROM {$table}
         ORDER BY event_timestamp DESC
         LIMIT %d",
        (int)$limit
    ), ARRAY_A);

    if (empty($rows)) return ['deleted' => 0, 'kept' => 0];

    $seen = [];
    $delete_ids = [];

    foreach ($rows as $row) {
        $title = (string)($row['title'] ?? '');
        $actor = (string)($row['actor_v2'] ?? '');
        $region = (string)($row['region'] ?? '');
        $intel = (string)($row['intel_type'] ?? '');
        $tfp = (string)($row['title_fingerprint'] ?? '');
        if ($tfp === '') $tfp = so_build_title_fingerprint($title);
        $sig = so_duplicate_candidate_signature($title, $actor, $region, $intel);
        $bucket = floor(((int)$row['event_timestamp']) / 14400);
        $image = trim((string)($row['image_url'] ?? ''));
        $key = ($tfp ?: $sig) . '|' . $bucket;

        $is_dup = false;
        if ($image !== '' && isset($seen['img:' . $image])) {
            $is_dup = true;
        } elseif (isset($seen[$key])) {
            $is_dup = true;
        } else {
            foreach ($seen as $prev) {
                if (!is_array($prev) || empty($prev['title'])) continue;
                if (($prev['region'] ?? '') !== $region) continue;
                $a = so_normalize_title_for_dedupe($title);
                $b = so_normalize_title_for_dedupe($prev['title']);
                similar_text($a, $b, $sim);
                if ($sim >= 92) { $is_dup = true; break; }
            }
        }

        if ($is_dup) {
            $delete_ids[] = (int)$row['id'];
            continue;
        }

        $seen[$key] = ['title' => $title, 'region' => $region, 'actor' => $actor];
        if ($image !== '') $seen['img:' . $image] = ['title' => $title, 'region' => $region, 'actor' => $actor];
    }

    if (!empty($delete_ids)) {
        $in = implode(',', array_map('intval', $delete_ids));
        $wpdb->query("DELETE FROM {$table} WHERE id IN ({$in})");
    }

    return ['deleted' => count($delete_ids), 'kept' => count($rows) - count($delete_ids)];
}


function so_reanalyze_all_news_events($limit = 3000, $offset = 0) {
    global $wpdb;
    $table = $wpdb->prefix . 'so_news_events';
    $rows = $wpdb->get_results($wpdb->prepare(
        "SELECT * FROM {$table}
         ORDER BY id DESC
         LIMIT %d OFFSET %d",
        (int)$limit,
        (int)$offset
    ), ARRAY_A);

    if (empty($rows)) return ['updated' => 0, 'scanned' => 0, 'next_offset' => $offset, 'total' => 0, 'done' => true];

    $updated = 0;
    $locked = 0;
    foreach ($rows as $row) {
        $title = (string)($row['title'] ?? '');
        if ($title === '') continue;

        if (sod_is_manual_locked_row($row)) {
            $update = sod_mark_evaluation_state($row, [
                'war_data' => (string)($row['war_data'] ?? '{}'),
                'field_data' => (string)($row['field_data'] ?? '{}'),
            ], 'manual_override');
            sod_db_safe_update($table, $update, ['id' => (int)$row['id']]);
            $locked++;
            continue;
        }

        $item = [
            'title'      => (string)($row['title'] ?? ''),
            'link'       => (string)($row['link'] ?? ''),
            'source'     => (string)($row['source_name'] ?? $row['source'] ?? ''),
            'color'      => (string)($row['source_color'] ?? '#1da1f2'),
            'date'       => (string)($row['event_timestamp'] ?? ''),
            'agency_loc' => (string)($row['agency_loc'] ?? ''),
            'image_url'  => (string)($row['image_url'] ?? ''),
            'content'    => (string)($row['content'] ?? ''),
        ];

        $analyzed = SO_OSINT_Engine::process_event($item);
        if (!$analyzed || !is_array($analyzed)) continue;
        $analyzed = sod_finalize_reanalysis_payload($row, $item, $analyzed);
        $wd = sod_parse_json_array($analyzed['war_data'] ?? '{}');
        $target_v2 = (string)($wd['target'] ?? ($analyzed['target_v2'] ?? ''));
        $context_actor = (string)($wd['context_actor'] ?? ($analyzed['context_actor'] ?? ''));
        $intent = (string)($wd['intent'] ?? ($analyzed['intent'] ?? ''));
        $weapon_v2 = (string)($wd['weapon_means'] ?? ($analyzed['weapon_v2'] ?? ''));

        $update_payload = [
            'title_fingerprint' => function_exists('so_build_title_fingerprint') ? so_build_title_fingerprint($title) : md5($title),
            'intel_type'     => (string)($analyzed['intel_type'] ?? ($row['intel_type'] ?? '')),
            'tactical_level' => (string)($analyzed['tactical_level'] ?? ($row['tactical_level'] ?? '')),
            'region'         => (string)($analyzed['region'] ?? ($row['region'] ?? '')),
            'actor_v2'       => (string)($analyzed['actor_v2'] ?? ($row['actor_v2'] ?? 'فاعل غير محسوم')),
            'score'          => (int)($analyzed['score'] ?? ($row['score'] ?? 0)),
            'war_data'       => (string)($analyzed['war_data'] ?? '{}'),
            'field_data'     => (string)($analyzed['field_data'] ?? '{}'),
            'target_v2'      => $target_v2,
            'context_actor'  => $context_actor,
            'intent'         => $intent,
            'weapon_v2'      => $weapon_v2,
        ];
        $update_payload = sod_mark_evaluation_state($row, $update_payload, 'auto');
        $res = sod_db_safe_update($table, $update_payload, ['id' => (int)$row['id']]);
        if (!empty($res['ok'])) {
            $updated++;
            foreach ([['types',$update_payload['intel_type']],['levels',$update_payload['tactical_level']],['regions',$update_payload['region']],['actors',$update_payload['actor_v2']],['targets',$target_v2],['contexts',$context_actor],['intents',$intent],['weapons',$weapon_v2]] as $pair) {
                [$bk,$val] = $pair;
                if ($val !== '' && $val !== 'فاعل غير محسوم' && $val !== 'غير محدد') sod_add_bank_value($bk, $val);
            }
        }
    }

    $next_offset = $offset + count($rows);
    $total = (int) $wpdb->get_var("SELECT COUNT(*) FROM {$table}");
    $done = $next_offset >= $total;

    $train = ['scanned' => 0, 'learned' => 0, 'deferred' => 1];
    if ($done) {
        $train = sod_auto_dataset_training_from_newslog(min(2500, max(400, (int)$limit)));
    }

    update_option('so_last_reanalysis_summary', [
        'time' => time(),
        'updated' => (int)$updated,
        'locked' => (int)$locked,
        'scanned' => (int)count($rows),
        'limit' => (int)$limit,
        'offset' => (int)$offset,
        'next_offset' => (int)$next_offset,
        'total' => (int)$total,
        'done' => (bool)$done,
        'engine' => 'sod_auto_eval_v17_4_2',
        'training' => $train,
    ], false);

    return [
        'updated' => (int)$updated,
        'locked' => (int)$locked,
        'scanned' => (int)count($rows),
        'next_offset' => (int)$next_offset,
        'total' => (int)$total,
        'done' => (bool)$done,
        'training' => $train,
    ];
}

function sod_finalize_reanalysis_payload(array $row, array $item, array $analyzed): array {
    $title = (string)($item['title'] ?? ($row['title'] ?? ''));
    $semantic = sod_classify_event_v3($item);
    $explicit_actor = function_exists('sod_infer_explicit_speaker_actor') ? trim((string)sod_infer_explicit_speaker_actor($title)) : '';

    $analyzed = SO_Manual_Learning::apply_to_analyzed($item, $analyzed);
    $analyzed = sod_apply_manual_override_to_analyzed($analyzed, $row);

    $current_actor = trim((string)($analyzed['actor_v2'] ?? ''));
    $semantic_actor = trim((string)($semantic['actor_v2'] ?? ''));
    $fallback_actor = function_exists('sod_infer_actor_fallback')
        ? trim((string)sod_infer_actor_fallback($title, (string)($analyzed['region'] ?? ($row['region'] ?? '')), (string)($item['source'] ?? '')))
        : '';
    $unknown_actor_values = ['','غير محدد','عام/مجهول','فاعل غير محسوم','فاعل قيد التقييم','جهة غير معلنة','فاعل سياقي','فاعل سياقي غير مباشر'];

    if ($semantic_actor !== '' && (
        in_array($current_actor, $unknown_actor_values, true)
        || ($current_actor === 'جيش العدو الإسرائيلي' && (sod_is_non_military_context($title) || $semantic_actor !== 'جيش العدو الإسرائيلي'))
        || $semantic_actor !== $current_actor
    )) {
        $analyzed['actor_v2'] = $semantic_actor;
    }
    if ($fallback_actor !== '' && (
        trim((string)($analyzed['actor_v2'] ?? '')) === ''
        || in_array(trim((string)($analyzed['actor_v2'] ?? '')), $unknown_actor_values, true)
        || (trim((string)($analyzed['actor_v2'] ?? '')) === 'جيش العدو الإسرائيلي' && $fallback_actor !== 'جيش العدو الإسرائيلي')
    )) {
        $analyzed['actor_v2'] = $fallback_actor;
    }

    foreach (['target_v2', 'context_actor', 'intent', 'weapon_v2'] as $field) {
        $semantic_value = trim((string)($semantic[$field] ?? ''));
        if ($semantic_value !== '') {
            $analyzed[$field] = $semantic_value;
        }
    }

    $semantic_intel = trim((string)($semantic['intel_type'] ?? ''));
    if ($semantic_intel !== '' && ($semantic_intel !== 'عام' || trim((string)($analyzed['intel_type'] ?? '')) === '')) {
        if (in_array(trim((string)($analyzed['intel_type'] ?? '')), ['', 'عام', 'غير محدد'], true) || $semantic_intel !== 'عام') {
            $analyzed['intel_type'] = $semantic_intel;
        }
    }
    $semantic_level = trim((string)($semantic['tactical_level'] ?? ''));
    if ($semantic_level !== '' && in_array(trim((string)($analyzed['tactical_level'] ?? '')), ['', 'عام', 'تكتيكي'], true)) {
        $analyzed['tactical_level'] = $semantic_level;
    }
    $semantic_region = trim((string)($semantic['region'] ?? ''));
    if ($semantic_region !== '' && in_array(trim((string)($analyzed['region'] ?? '')), ['', 'غير محدد'], true)) {
        $analyzed['region'] = $semantic_region;
    }

    if (empty($analyzed['context_actor']) && sod_is_non_military_context($title)) {
        $bucket = (string)($semantic['_ai_v2']['bucket'] ?? '');
        if (in_array($bucket, ['statement', 'report'], true)) {
            $analyzed['context_actor'] = 'سياق تصريحي/إعلامي';
        }
    }

    if (empty($analyzed['intent'])) {
        $bucket = (string)($semantic['_ai_v2']['bucket'] ?? '');
        $intel_type = trim((string)($analyzed['intel_type'] ?? ''));
        $mode = sod_detect_event_mode($title);
        if ($mode === 'defensive_alert') {
            $analyzed['intent'] = 'دفاع';
        } elseif ($mode === 'kinetic') {
            $analyzed['intent'] = 'هجوم';
        } elseif (in_array($bucket, ['statement', 'report'], true) || sod_is_non_military_context($title)) {
            $analyzed['intent'] = 'تموضع/رسائل سياسية';
        } elseif ($intel_type === 'إعلامي') {
            $analyzed['intent'] = 'تغطية/رسائل إعلامية';
        } elseif (in_array($intel_type, ['عسكري/أمني', 'تكتيكي/ميداني', 'رصد/إنذار'], true)) {
            $analyzed['intent'] = 'نشاط ميداني';
        }
    }

    $region_for_rule = (string)($analyzed['region'] ?? ($row['region'] ?? ''));
    $analyzed['actor_v2'] = sod_force_requested_actor_rule((string)($analyzed['actor_v2'] ?? ''), $region_for_rule, $title);
    if ($explicit_actor !== '') {
        $analyzed['actor_v2'] = $explicit_actor;
    }
    $actor_after_rule = trim((string)($analyzed['actor_v2'] ?? ''));
    $is_media_actor = in_array($actor_after_rule, ['المنار', 'الميادين', 'قناة العربية', 'التلفزيون الإيراني', 'إعلام إسرائيلي', 'وكالة فارس', 'وكالة تسنيم'], true);
    $is_kinetic_title = preg_match('/(غارة|غارات|قصف|استهداف|اقتحام|عدوان|اعتداء|هجوم|اشتباكات|نيران مشاة|قصف مدفعي|طيران حربي|مسيّرة|مسيرة)/ui', $title) === 1;
    if ($is_media_actor && $is_kinetic_title && function_exists('sod_infer_actor_fallback')) {
        $media_safe_actor = trim((string)sod_infer_actor_fallback($title, $region_for_rule, ''));
        if ($media_safe_actor !== '' && !in_array($media_safe_actor, ['المنار', 'الميادين', 'قناة العربية', 'التلفزيون الإيراني', 'إعلام إسرائيلي', 'وكالة فارس', 'وكالة تسنيم'], true)) {
            $analyzed['actor_v2'] = $media_safe_actor;
        }
    }
    if ($is_media_actor && !$is_kinetic_title) {
        $media_safe_actor = function_exists('sod_infer_actor_fallback') ? trim((string)sod_infer_actor_fallback($title, $region_for_rule, '')) : '';
        if ($media_safe_actor !== '' && !in_array($media_safe_actor, ['المنار', 'الميادين', 'قناة العربية', 'التلفزيون الإيراني', 'إعلام إسرائيلي', 'وكالة فارس', 'وكالة تسنيم'], true)) {
            $analyzed['actor_v2'] = $media_safe_actor;
        } elseif (preg_match('/(وكالة\s*[\"“”]?\s*تسنيم|تسنيم|وكالة فارس|فارس|التلفزيون الإيراني|إيرنا|إعلام إيراني)/ui', $title)) {
            $analyzed['actor_v2'] = 'إيران';
        }
    }

    $wd = sod_parse_json_array($analyzed['war_data'] ?? '{}');
    $fd = sod_parse_json_array($analyzed['field_data'] ?? '{}');
    $wd['actor'] = (string)($analyzed['actor_v2'] ?? '');
    if (!empty($analyzed['target_v2'])) $wd['target'] = (string)$analyzed['target_v2'];
    if (!empty($analyzed['context_actor'])) $wd['context_actor'] = (string)$analyzed['context_actor'];
    if (!empty($analyzed['intent'])) $wd['intent'] = (string)$analyzed['intent'];
    if (!empty($analyzed['weapon_v2'])) $wd['weapon_means'] = (string)$analyzed['weapon_v2'];
    if (!isset($wd['early_warning'])) {
        $wd['early_warning'] = sod_early_warning_ai($title, [
            'actor' => (string)($analyzed['actor_v2'] ?? ''),
            'region' => $region_for_rule,
            'intel_type' => (string)($analyzed['intel_type'] ?? ''),
        ]);
    }
    if (!isset($wd['prediction_layer'])) {
        $wd['prediction_layer'] = sod_prediction_layer($title, [
            'actor' => (string)($analyzed['actor_v2'] ?? ''),
            'region' => $region_for_rule,
            'intel_type' => (string)($analyzed['intel_type'] ?? ''),
            'target' => (string)($analyzed['target_v2'] ?? ''),
            'weapon' => (string)($analyzed['weapon_v2'] ?? ''),
            'early_warning' => $wd['early_warning'],
        ]);
    }
    $fd['reanalysis_engine'] = 'sod_finalize_reanalysis_payload_v1';
    $analyzed['war_data'] = wp_json_encode($wd, JSON_UNESCAPED_UNICODE);
    $analyzed['field_data'] = wp_json_encode($fd, JSON_UNESCAPED_UNICODE);

    return $analyzed;
}

function so_reanalyze_all_news_events_full($batch = 1000, $reset = false) {
    global $wpdb;
    $table = $wpdb->prefix . 'so_news_events';
    $batch = max(10, (int)$batch);

    if ($reset) {
        update_option('so_reanalyze_cursor', 0, false);
        update_option('so_reanalyze_running', 1, false);
    }

    $offset = (int) get_option('so_reanalyze_cursor', 0);
    $total = (int) $wpdb->get_var("SELECT COUNT(*) FROM {$table}");

    $result = so_reanalyze_all_news_events($batch, $offset);
    $next_offset = (int)($result['next_offset'] ?? $offset);
    $done = !empty($result['done']);

    update_option('so_reanalyze_cursor', $done ? 0 : $next_offset, false);
    update_option('so_reanalyze_running', $done ? 0 : 1, false);

    $processed = min($done ? $total : $next_offset, $total);
    $percent = $total > 0 ? (int) round(($processed / $total) * 100) : 100;

    $progress = [
        'time' => time(),
        'batch' => $batch,
        'processed' => (int)$processed,
        'total' => (int)$total,
        'percent' => (int)$percent,
        'updated' => (int)($result['updated'] ?? 0),
        'done' => (bool)$done,
        'next_offset' => (int)($done ? 0 : $next_offset),
        'running' => $done ? 0 : 1,
    ];
    update_option('so_reanalyze_progress', $progress, false);

    return $progress;
}

function so_headline_word_count($text) {
    $text = so_clean_text((string)$text);
    $text = preg_replace('/[\p{P}\p{S}]+/u', ' ', $text);
    $text = preg_replace('/\s+/u', ' ', trim($text));
    if ($text === '') return 0;
    return count(array_filter(explode(' ', $text), function($w) { return trim($w) !== ''; }));
}

function so_is_substantial_headline($text) {
    $text = so_clean_text((string)$text);
    if ($text === '' || mb_strlen($text) < 8) return false;
    return so_headline_word_count($text) >= 3;
}

function so_is_lenient_source_name($source_name) {
    $source_name = trim((string)$source_name);
    if ($source_name === '') return false;
    return preg_match('/(الاعلام العبري بالعربي|نوفوستي|روسيا الاتحادية|قناة الحرس الثوري|الاعلام الحربي|الميادين|ايران بالعربي|RNN_Alerts_AR|قناة الساحات|قناة العربية|bintjbeil)/ui', $source_name) === 1;
}

function so_filter_source_candidate($candidate) {
    $title       = so_clean_text((string)($candidate['title'] ?? ''));
    $source_name = (string)($candidate['source'] ?? '');
    $media       = trim((string)($candidate['image_url'] ?? ''));
    $is_lenient  = so_is_lenient_source_name($source_name);
    if ($title === '') return false;
    if (so_is_substantial_headline($title)) return true;
    if ($is_lenient && mb_strlen($title) >= 14 && so_headline_word_count($title) >= 2) return true;
    if ($media !== '' && mb_strlen($title) >= 10) return true;
    if (preg_match('/(غارة|قصف|هجوم|استهداف|اشتباك|كمين|بيان صادر|مسيّرة|مسيرة|صاروخ|صواريخ|اقتحام|انذار|إنذار|صفارات|المتحدث باسم|الناطق العسكري|مقر خاتم الأنبياء|الحرس الثوري)/ui', $title)) return true;
    return false;
}

function so_should_publish_raw_item($item) {
    $title = so_clean_text((string)($item['title'] ?? ''));
    if (!so_filter_source_candidate(array_merge((array)$item, ['title' => $title]))) return false;
    $ts = (int)($item['date'] ?? 0);
    if (!$ts) return false;
    $source_name = trim((string)($item['source'] ?? ''));
    $max_age = so_is_lenient_source_name($source_name) ? 6 * HOUR_IN_SECONDS : 2 * HOUR_IN_SECONDS;
    if ((time() - $ts) > $max_age) return false;
    static $seen_runtime = [];
    $normalized = so_normalize_title_for_dedupe($title);
    if ($normalized === '') return false;
    $runtime_key = md5(($source_name ?: 'unknown') . '|' . $normalized . '|' . gmdate('Y-m-d H', $ts));
    if (isset($seen_runtime[$runtime_key])) return false;
    $seen_runtime[$runtime_key] = 1;
    return true;
}

function so_detect_strategic_frame($title) {
    $lower = mb_strtolower((string)$title);
    if (preg_match('/(رد|انتقام|ثأر|الموجة|رداً على|ضمن الرد|انتقامية)/ui', $lower)) return 'retaliation';
    if (preg_match('/(هدنة|وقف إطلاق|تهدئة|اتفاق|حوار|مفاوضات)/ui', $lower)) return 'de_escalation';
    if (preg_match('/(سيصعّد|تصعيد|مرحلة ثانية|أشد|أوسع|سنفجر|سنرد|توعد|تهديد)/ui', $lower)) return 'escalation';
    if (preg_match('/(حصيلة|إحصائية|تقرير|متابعة|عمليات الإغاثة|لا تزال مستمرة)/ui', $lower)) return 'aftermath';
    return 'continuity';
}

function so_detect_conflict_context($title) {
    $lower = mb_strtolower((string)$title);
    if (preg_match('/(رداً على|في إطار الرد|انتقام|انتقامية|الموجة\s*\d+|وعد صادق|ضمن الرد)/ui', $lower)) return 'linked_retaliation_cycle';
    if (preg_match('/(استمرار|لا تزال|متواصلة|يتواصل|مستمرة|اليوم الثالث|اليوم الرابع|منذ)/ui', $lower)) return 'ongoing_conflict';
    if (preg_match('/(هدنة|وقف إطلاق|مفاوضات|اتفاق|حوار)/ui', $lower)) return 'diplomatic_phase';
    if (preg_match('/(إنذار مبكر|صفارات الإنذار|قيادة الجبهة الداخلية|رصد إطلاق)/ui', $lower)) return 'defensive_alert_phase';
    if (preg_match('/(حصيلة|شهداء|جرحى|إغاثة|إنقاذ)/ui', $lower)) return 'post_strike_aftermath';
    return 'standalone_or_unclear';
}

function so_detect_war_direction($title) {
    $lower = mb_strtolower((string)$title);
    if (preg_match('/(هدنة|وقف إطلاق|مفاوضات|اتفاق|حوار)/ui', $lower)) return 'de-escalating';
    if (preg_match('/(مرحلة ثانية|أشد|أوسع|تصعيد|توعد|سنفجر|سنرد|عدوان|غارة|قصف|استهداف)/ui', $lower)) return 'escalating';
    if (preg_match('/(حصيلة|إغاثة|إنقاذ|عمليات الإغاثة|لا تزال مستمرة)/ui', $lower)) return 'aftermath';
    return 'stable_or_unclear';
}

function so_detect_verification_nature($title) {
    $lower = mb_strtolower((string)$title);
    if (preg_match('/(قيادة الجبهة الداخلية|الإنذار المبكر|تسوفار|انذار احمر|إنذار أحمر|صفارات(?: الإنذار)?)/ui', $lower)) return 'defensive_alert';
    if (preg_match('/(نظرًا لرصد إطلاق صواريخ|رصد إطلاق صواريخ|من المحتمل تفعيل الإنذارات)/ui', $lower)) return 'detected_launch';
    if (preg_match('/(أطلقنا|استهدفنا|هجوم صاروخي|غارة|قصف|تفجير|استهداف مباشر|صلية صاروخية|مسيّرة انقضاضية)/ui', $lower)) return 'confirmed_attack';
    if (preg_match('/(قال|صرح|أعلن|أكد|في مقابلة|البابا|الفاتيكان|الكرسي الرسولي|لاوون|ترامب|ترمب|الرئيس عون|ولايتي)/ui', $lower)) return 'statement';
    if (preg_match('/(وزارة الصحة|الصحة اللبنانية|الهلال الأحمر|إحصائية|حصيلة|تقرير|متابعة|عمليات الإغاثة)/ui', $lower)) return 'report';
    return 'unknown';
}

function so_detect_content_bucket($title, $source_name = '') {
    $text = so_clean_text((string)$title . ' ' . (string)$source_name);
    if (preg_match('/\b(?:متداول|أنباء أولية|أولي(?:ة)?|غير مؤكد|يُتداول|مزاعم|شائعات?)\b/iu', $text)) return 'rumor';
    if (preg_match('/\b(?:قال|قالت|صرح|صرحت|أعلن|أعلنت|أكد|أكدت|أفاد|أفادت|كشف|هدد|توعد|ترامب|ترمب|بوتين|مدفيديف|البيت الأبيض|وزارة الخارجية|في مقابلة|تعليقاً على|ولايتي|الرئيس عون|البابا|الفاتيكان|نرحب|نرفض|ندين|نطالب|يطالب|يدين|يرفض|يرحب|مؤتمر صحفي|لقاء دبلوماسي|قمة ثنائية|اتفاقية|بروتوكول|مذكرة تفاهم|اتفاق سلام|مباحثات|محادثات|زعيم|رئيس حزب|قائد حزب|زعيم حزب|وزير خارجية|ناطق باسم|متحدث|رئيس الوزراء|إخفاق|انتقد|انتقدت|أسوأ|فشل سياسي|إخفاق استراتيجي|كنيست|برلمان|حزب ديمقراطي|حزب ليكود|لن يكون|أعلنا|أوضح)\b/iu', $text) && !preg_match('/\b(?:استهدفنا|نفذنا|شنّينا|أطلقنا|قصفنا|استهدفت القواعد|نفذت عملية)\b/iu', $text)) return 'statement';
    if (preg_match('/\b(?:رويترز|وكالة|صحيفة|القناة\s*\d+|تقرير|تحليل|إحاطة|ملخص|نقلاً عن|وسائل إعلام|إعلام العدو|إحصائية|وزارة الصحة|الهلال الأحمر)\b/iu', $text) && !preg_match('/\b(?:استهدفنا|قصف|غارة|هجوم|اشتباك|انفجار|اغتيال|اقتحام|إطلاق)\b/iu', $text)) return 'report';
    if (preg_match('/\b(?:زلزال|هزة|فيضانات|إعصار|عاصفة|حرائق غابات|بركان|تسونامي|انهيار أرضي)\b/iu', $text)) return 'disaster';
    if (preg_match('/\b(?:غارة|قصف|هجوم|استهداف|اشتباك|كمين|إطلاق|اعتقال|اقتحام|انفجار|اغتيال|توغل|اعتراض|مسيّرة|مسيرة|صاروخ|صلية صاروخية)\b/iu', $text)) return 'field';
    return 'general';
}



function so_is_non_intel_noise($title) {
    $text = so_clean_text((string)$title);
    if ($text === '') return true;
    $negative = [
        'درب التبانة','مجرة','رواد الفضاء','رائد فضاء','أرتيميس','وكالة ناسا','ناسا','القمر','فضاء','كوكب','كسوف','خسوف',
        'طقس','الأرصاد الجوية','رياضة','مباراة','كرة القدم','الدوري',
        'فنان','فنانة','ممثل','ممثلة','مسلسل','ترفيه','برجك','أبراج','طبخ','وصفة','منوعات',
        'الدورات الصيفية','الأنشطة الصيفية','الأنشطة الثقافية','تدشين الدورات','الأنشطة التربوية',
        'ندعوكم للاشتراك','للاشتراك','تابعونا','سعيا منا لنشر','سعياً منا لنشر','تنويه','اعادة النشر',
        'live from the international space station','space station','iss'
    ];
    foreach ($negative as $term) {
        if (mb_stripos($text, $term) !== false) return true;
    }
    return false;
}

function so_classify_editorial_axis($title, $source_name = '') {
    $text = so_clean_text((string)$title . ' ' . (string)$source_name);
    $lower = mb_strtolower($text);

    if (so_is_non_intel_noise($text)) return 'غير استخباراتي';

    // رسمي/سياسي أولاً قبل أي fallback ميداني
    if (preg_match('/(يعلن الحداد|الحداد الوطني|الاتحاد العمالي العام|تعطيل|إقفال|قرار رسمي|بيان حكومي|إعلان الحداد)/ui', $lower)) return 'سياسي';
    if (preg_match('/(وزير الخارجية|بحث هاتفيا|بحث هاتفي|بحث هاتفياً|بحث هاتفيًا|مستجدات الأوضاع|مباحثات|اجتماع|لقاء|اتصال هاتفي|تصريح|أكد|أكدت|قال|قالت|الرئيس بري|الرئيس|دبلوماسي|ديبلوماسي)/ui', $lower) && !preg_match('/(غارة|قصف|هجوم|اغتيال|اشتباك|اقتحام|صاروخ|مسيرة|مسيّرة|رصد)/ui', $lower)) return 'سياسي';

    if (preg_match('/(شجب|يشجب|ندد|تنديد|يدين|إدانة|ندين|استنكار|تستنكر|مستنكر|نندد)/ui', $lower)) return 'شجب/استنكار';

    if (preg_match('/(بيان صادر|بيان|المكتب السياسي|العلاقات العامة|أصدر|أصدرت|أعلنت|أعلن)/ui', $lower) && !preg_match('/(غارة|قصف|هجوم|اغتيال|اشتباك|اقتحام|صاروخ|مسيرة|مسيّرة|رصد)/ui', $lower)) return 'بيان';

    if (preg_match('/(وكالة|وسائل إعلام|وسائل اعلام|مراسل|فيديو|يوثق|مشاهد|لقطة|تسنيم|منصات للمستوطنين|إعلام العدو|اعلام العدو|ذا أتلانتيك)/ui', $lower) && !preg_match('/(غارة|قصف|هجوم|اغتيال|اشتباك|اقتحام|صاروخ|مسيرة|مسيّرة|رصد قصف|رصد غارة|رصد ضربة)/ui', $lower)) return 'إعلامي';

    if (preg_match('/(نووي|نووية|يوراني|مفاعل|تخصيب|سلاح نووي)/ui', $lower)) return 'نووي';

    if (preg_match('/(سفينة|سفن|المضيق|مضيق هرمز|ناقلات النفط|المرور|شحن|إمداد|إمدادات|لوجستي|اقتصادي)/ui', $lower)) return 'اقتصادي/لوجستي';

    if (preg_match('/(تم رصد|صافرات الإنذار|صافرات الانذار|إنذار|انذار|اعتراض|صاروخ اعتراضي|حدث أمني|حدث امني)/ui', $lower)) return 'رصد/إنذار';

    if (preg_match('/(غارة|غارة جوية|قصف مدفعي|قصف|هجوم|اغتيال|اشتباك|كمين|توغل|اقتحام|صاروخ|مسيرة|مسيّرة|استهداف|ضربة بطائرة مسيّرة|ضربة بطائرة مسيرة|سقوط صواريخ|انفجارات قوية)/ui', $lower)) return 'عسكري/أمني';

    return 'تكتيكي/ميداني';
}


function so_bt_contains_any($text, array $terms) {
    foreach ($terms as $term) {
        if ($term !== '' && mb_stripos($text, $term) !== false) return true;
    }
    return false;
}

function so_bt_detect_region_v2($title) {
    $t = so_clean_text((string)$title);
    $map = [
        'لبنان' => ['لبنان','الضاحية','الضاحية الجنوبية','بيروت','الظريف','القاسمية','جسر القاسمية','بشامون','دير الزهراني','الزهراني','دبل','برعشيت','رشاف','حداثا','زوطر','زوطر الشرقية','زوطر الغربية','كوثرية السياد','صفد البطيخ','دير سريان','بنت جبيل','النبطية','الجنوب','جنوبي لبنان','صور','الخيام','شقرا','ديرنطار','كفرا','حاريص','الجميجمة','مجدل سلم','الجناح'],
        'فلسطين' => ['فلسطين','الضفة الغربية','طوباس','تياسير','حزما','جنين','نابلس','الخليل','رام الله','قلقيلية','طولكرم','بيت لحم','غزة','قطاع غزة','الشيخ عجلين','دوار النابلسي','رفح','خان يونس','خانيونس','جباليا','السيلة الحارثية','شرق مدينة غزة'],
        'الأراضي المحتلة (إسرائيل)' => [
        'الأراضي المحتلة','إسرائيل','اسرائيل','تل أبيب','تل ابيب','حيفا','بتاح تكفا','القدس المحتلة',
        'منطقة الوسط','صفد','نهاريا','عسقلان','بئر السبع','المستوطنات','مستوطنات',
        'المطلة','مسكافعام','مسجاف عام','أفيفيم','يرؤون','شلومي','حانيتا','بتست',
        'راموت نفتالي','راموت نافتالي','كريات شمونة','كريات شمونه','مرغليوت','المنارة','إصبع الجليل',
        'الجليل الأعلى','الجليل الاعلى','الجليل الغربي','سهل الحولة','كفار جلعادي','تل حاي','بيت هيلل',
        'كفار بلوم','كفار يوفال','ريحانية','علماه','زرعيت','شومرا','شوميراه','ايفن مناحم',
        'عكا','الزيب','رأس الناقورة','راس الناقورة','متسوفا','بيتست','معالوت ترشيحا'
    ],
        'إيران' => ['إيران','ايران','طهران','مضيق هرمز','هرمز','بوشهر','نطنز','أصفهان','خارك','عبادان','شيراز','تبريز'],
        'الأردن' => ['الأردن','الأردنية','العاصمة الأردنية','عمان'],
        'الخليج' => ['السعودية','السعودي','الكويت','الكويتي','سلطنة عمان','عمان الخليجية','الخليج'],
        'تركيا' => ['تركيا','تركي','تركية','سفينة تركية','سفن تركية'],
        'سوريا' => ['سوريا','دمشق','حمص','حلب','درعا','اللاذقية','القنيطرة'],
        'العراق' => ['العراق','بغداد','البصرة','أربيل','الأنبار','كركوك'],
        'اليمن' => ['اليمن','صنعاء','الحديدة','صعدة','تعز'],
    ];
    foreach ($map as $region => $terms) {
        if (so_bt_contains_any($t, $terms)) return $region;
    }
    return 'غير محدد';
}

function so_normalize_actor_label($actor) {
    $actor = trim((string)$actor);
    $unknowns = ['', 'جهة غير معلنة', 'عام/مجهول', 'غير محدد', 'مجهول', 'عام', 'فاعل غير محسوم', 'فاعل قيد التقييم', 'فاعل سياقي', 'فاعل سياقي غير مباشر'];
    if (in_array($actor, $unknowns, true)) {
        return 'فاعل سياقي غير مباشر';
    }
    return $actor;
}

function so_force_actor_not_unknown($actor, $title, $region='', $source_name='') {
    $actor = trim((string)$actor);
    if ($actor !== '') return $actor;
    
    $title = so_clean_text((string)$title);
    $t = $title . ' ' . trim((string)$source_name);
    $lower = mb_strtolower($t);
    
    // استبعاد الأحداث الدبلوماسية/السياسية أولاً - هذه لا تُنسب لإسرائيل أبداً
    $is_diplomatic = preg_match('/(مفاوضات|محادثات|وفد|اجتماع|لقاء|قمة|مؤتمر|بيان سياسي|تصريح|وزارة الخارجية|الرئيس|رئيس الوزراء|الأمم المتحدة|الاتحاد الأوروبي|جامعة الدول العربية)/ui', $t);
    $is_economic = preg_match('/(اقتصاد|نفط|غاز|طاقة|أسعار|سوق|تجارة|استثمار|بنك|صندوق|عملة|تضخم|مالية|ميزانية)/ui', $t);
    $is_media_report = preg_match('/(وسائل إعلام|تقرير إعلامي|تحليل|صحيفة|قناة|إذاعة|موقع إخباري|رويترز|غارديان|نيويورك تايمز|وول ستريت جورنال|أكسيوس|بوليتيكو)/ui', $t);
    $is_political_statement = preg_match('/(قال|أكد|صرح|أعلن|أفاد|نقل عن|بحسب|وفق|ذكر|كشف|شجب|استنكر|أدان|رحب|حث|دعا|طالب|طالبوا)/ui', $t);
    
    // لا تُطبَّق القواعد الاستنتاجية على الأحداث غير العسكرية
    if ($is_diplomatic || $is_economic || $is_media_report || $is_political_statement) {
        return 'فاعل غير محسوم';
    }
    
    // لبنان: غارات/قصف → إسرائيل (فقط مع أفعال عسكرية صريحة)
    if (($region === 'لبنان' || preg_match('/(لبنان|بيروت|الضاحية|الجنوب|النبطية|بنت جبيل|الخيام|شقرا|عدشيت|صور|صيدا|جبل لبنان)/ui', $t))
        && preg_match('/(غارة|غارات|قصف|استهداف|طيران حربي|طيران الاحتلال|طيران معادي|مسيّرة معادية|مسيرة معادية|عدوان|اعتداء إسرائيلي|اعتداء اسرائيلي)/ui', $t)) {
        return 'جيش العدو الإسرائيلي';
    }
    
    // فلسطين: اقتحامات/قصف → إسرائيل (فقط مع أفعال عسكرية صريحة)
    if (($region === 'فلسطين' || preg_match('/(غزة|الضفة الغربية|جنين|نابلس|الخليل|رفح|خان يونس|بيت لاهيا|جباليا|طولكرم)/ui', $t))
        && preg_match('/(اقتحام|اعتقالات|اعتقال|إطلاق نار من دبابات|إطلاق نار بحري|قصف مدفعي|قصف|نسف|جرافات|توغل)/ui', $t)) {
        return 'جيش العدو الإسرائيلي';
    }
    
    return 'فاعل غير محسوم';
}

function so_bt_detect_actor_v2($title, $source_name = '') {
    $title = so_clean_text((string)$title);
    $source_name = trim((string)$source_name);
    $t = so_clean_text($title . ' ' . $source_name);
    $region = so_bt_detect_region_v3_patch($title, so_bt_detect_region_v2($title));
    $named_nonmilitary = sod_extract_named_nonmilitary_actor($t);
    $has_attack_markers = preg_match('/(غارة|غارات|قصف|استهداف|استهدفت|عدوان|اشتباك|توغل|اقتحام|صاروخ|صواريخ|طيران حربي|الطيران الحربي|مسيرة|مسيّرة|هجوم|اغتيال|إطلاق نار|استطلاع بطائرة مسيّرة|تم رصد)/ui', $title) === 1;

    if (sod_is_non_military_context($t) && !$has_attack_markers) {
        if ($named_nonmilitary !== '') {
            return $named_nonmilitary;
        }
        if (preg_match('/(إيران|ايران|طهران)/ui', $title)) {
            return 'إيران';
        }
        if (preg_match('/(الولايات المتحدة|أمريكا|امريكا|واشنطن|البيت الأبيض|ترامب|ترمب)/ui', $title)) {
            return 'الولايات المتحدة';
        }
        if (preg_match('/(باكستان|إسلام آباد|اسلام آباد)/ui', $title)) {
            return 'باكستان';
        }
        return 'فاعل غير محسوم';
    }

    // بيانات إعلام العدو / الصفارات
    if (preg_match('/(صفارات(?: الإنذار)?|صافرات(?: الإنذار)?|إنذار|انذار|الجبهة الداخلية|خشية تسلل)/ui', $title)) {
        return 'الجبهة الداخلية الإسرائيلية';
    }

    // أفعال هجومية إسرائيلية داخل لبنان
    if (
        ($region === 'لبنان' || preg_match('/(لبنان|بيروت|الضاحية|صور|النبطية|بنت جبيل|الخيام|دير الزهراني|المنصوري|كونين|قانا|حناويه|بشامون|سن الفيل|تلة الخياط|الأنصارية|الجناح|حي السلم|زحلة|بعلبك|الهرمل|صيدا|العباسية|حاصبيا|مرج الزهور)/ui', $title)) &&
        preg_match('/(غارة|غارات|قصف|استهداف|استهدفت|عدوان|اعتداء إسرائيلي|اعتداء اسرائيلي|طيران حربي|الطيران الحربي المعادي|مسيّرة|مسيرة|تحليق حربي|حربي فوق)/ui', $title)
    ) {
        return 'جيش العدو الإسرائيلي';
    }

    // مقاومة لبنانية
    if (preg_match('/(مراسل المنار|الإعلام الحربي|الاعلام الحربي|المقاومة الإسلامي(?:ة)?|حزب الله|مجاهدو المقاومة|مجاهدونا|استهدف مجاهدو|استهدف مجاهدو|صلية صاروخية من لبنان|إطلاق صواريخ من لبنان|أطلق من لبنان|باتجاه الأراضي المحتلة|باتجاه فلسطين المحتلة|تدمير دبابة ميركافا)/ui', $title . ' ' . $source_name)) {
        return 'المقاومة الإسلامية (حزب الله)';
    }

    // سقوط صاروخ / رشقات على الداخل المحتل
    if (
        ($region === 'الأراضي المحتلة (إسرائيل)' || preg_match('/(كريات شمونة|نهاريا|حيفا|عكا|تل أبيب|بتاح تكفا|بئر السبع|المنارة|مرغليوت|أفيفيم|مسكافعام|راموت نفتالي|الجليل|النقب|القدس المحتلة)/ui', $title)) &&
        preg_match('/(سقوط صاروخ|إطلاق صواريخ|صواريخ|رشقة|رشقات|صلية|صلية صاروخية)/ui', $title)
    ) {
        return 'جهة مقاومة من لبنان';
    }

    // اقتحامات واعتقالات في فلسطين
    if (($region === 'فلسطين' || preg_match('/(الضفة الغربية|غزة|جنين|نابلس|طولكرم|الخليل|قلقيلية|رفح|خان يونس|جباليا)/ui', $title))
        && preg_match('/(اقتحام|اعتقال|اعتقالات|قصف|نسف|إطلاق نار من دبابات|إطلاق نار بحري)/ui', $title)) {
        return 'جيش العدو الإسرائيلي';
    }

    // جهات رسمية لبنانية
    if ($region === 'لبنان' && preg_match('/(مصادر رسمية لبنانية|مصدر رسمي لبناني|وزارة الصحة اللبنانية|الجيش اللبناني|رئاسة الجمهورية|الرئيس|مجلس الوزراء|نواف سلام|قيادة الجيش|وزارة الصحة|لبنان: وزير|مسؤول لبناني)/ui', $title)) {
        return 'لبنان';
    }

    // إيران: فقط في السياق الدبلوماسي/السياسي (وفود، مفاوضات، لقاءات) - لا تُنسب للأحداث العسكرية
    if (preg_match('/(وفد|مفاوضات|محادثات|اجتماع|لقاء|زيارة|قمة|مؤتمر|وزير الخارجية|الرئيس|رئيس الوزراء|خامنئي|بزشكيان|عراقجي|قاليباف)/ui', $title)) {
        // استبعاد أي سياق عسكري لإيران
        if (preg_match('/(غارة|قصف|استهداف|صاروخ|مسيرات|حرب|قتل|اغتيال)/ui', $title)) {
            // هذا حدث عسكري، لا تُنسب لإيران الدبلوماسية
            return 'فاعل سياقي غير مباشر';
        }
        if (preg_match('/(إيران|ايران|طهران)/ui', $title)) {
            return 'إيران';
        }
        if (preg_match('/(الولايات المتحدة|أمريكا|امريكا|واشنطن|البيت الأبيض|ترامب|ترمب|فيتكوف|كوشنر|فانس)/ui', $title)) {
            return 'الولايات المتحدة';
        }
        if (preg_match('/(باكستان|إسلام آباد)/ui', $title)) {
            return 'باكستان';
        }
        return $named_nonmilitary !== '' ? $named_nonmilitary : 'فاعل غير محسوم';
    }
    
    // إيران العسكرية (الحرس الثوري)
    if (preg_match('/(الحرس الثوري|حرس الثورة|خاتم الأنبياء|قائد قوة القدس|قاآني)/ui', $title)) {
        return 'الحرس الثوري الإيراني';
    }

    return $named_nonmilitary !== '' ? $named_nonmilitary : 'فاعل غير محسوم';
}

function so_bt_score_news_v2($title, $classification, $actor, $region, $source_name = '') {
    $t = so_clean_text((string)$title . ' ' . (string)$source_name);
    if ($classification === 'غير استخباراتي') return 0;

    // حالات خاصة أولاً
    if (preg_match('/(الحداد الوطني|يعلن الحداد|الاتحاد العمالي العام)/ui', $t)) return 18;

    $score = 10;
    switch ($classification) {
        case 'إعلامي': $score += 8; break;
        case 'سياسي': $score += 22; break;
        case 'بيان': $score += 24; break;
        case 'شجب/استنكار': $score += 14; break;
        case 'اقتصادي/لوجستي': $score += 38; break;
        case 'رصد/إنذار': $score += 48; break;
        case 'عسكري/أمني': $score += 95; break;
        case 'تكتيكي/ميداني': $score += 58; break;
        case 'نووي': $score += 120; break;
        default: $score += 15; break;
    }

    if ($actor === 'جيش العدو الإسرائيلي') $score += 25;
    elseif ($actor === 'إيران') $score += 18;
    elseif ($actor === 'الحرس الثوري الإيراني') $score += 20;
    elseif ($actor === 'الولايات المتحدة') $score += 15;
    elseif ($actor === 'فلسطينيون' || $actor === 'فصائل المقاومة الفلسطينية') $score += 18;
    elseif ($actor === 'المقاومة الإسلامية (حزب الله)') $score += 30;
    elseif ($actor === 'الجبهة الداخلية الإسرائيلية') $score += 8;
    elseif ($actor === 'مستوطنون إسرائيليون') $score += 10;
    elseif ($actor === 'فاعل غير محسوم' || $actor === 'فاعل سياقي غير مباشر' || $actor === 'فاعل سياقي') $score -= 2;
    elseif ($actor === 'سوق / قطاع طاقة ونقل') $score += 6;
    elseif ($actor === 'محتوى إعلامي / غير عملياتي') $score -= 18;
    elseif (in_array($actor, ['لبنان','إسبانيا','فرنسا','ألمانيا','المملكة المتحدة','إيطاليا','الاتحاد الأوروبي','الإمارات','قطر','الكويت','العراق','سلطنة عمان','السعودية','روسيا','الهند','باكستان','كولومبيا','البحرين','أدنوك / الإمارات','السلطة الفلسطينية','الجبهة الشعبية لتحرير فلسطين','الجبهة الديمقراطية لتحرير فلسطين','المقاومة العراقية'], true)) $score += 6;

    if (in_array($region, ['لبنان','فلسطين','الأراضي المحتلة (إسرائيل)','إيران','الخليج'], true)) $score += 12;
    elseif ($region === 'غير محدد') $score -= 5;

    if (preg_match('/(مقتل|قتيل|قتلى|شهيد|شهداء|استشهاد|إصابة|إصابات|اغتيال|انهيار مبنى|ضربة مباشرة|حريق كبير|أعمدة النيران)/ui', $t)) $score += 30;
    if (preg_match('/(صلية صاروخية|صليّات صاروخية|عدة صواريخ|رشقة صاروخية)/ui', $t)) $score += 20;
    if (preg_match('/(عشرات الصواريخ|صواريخ باليستية|أوسع قصف|غارة عنيفة|غارتان|سلسلة من 21 غارة|قصف متعدد|قصف واسع)/ui', $t)) $score += 22;

    // تقليل الإعلامي المحض
    if (preg_match('/(فيديو يوثق|لحظة شن|منصات للمستوطنين|إعلام العدو:|اعلام العدو:|مراسل)/ui', $t) && $classification === 'إعلامي') $score -= 12;

    // رفع محدود لمضيق هرمز
    if (preg_match('/(مضيق هرمز|حشود من السفن|السفن متوقفة|ناقلات النفط)/ui', $t)) $score += 12;

    if ($classification === 'رصد/إنذار' && !preg_match('/(تم رصد غارة|تم رصد قصف|إطلاق صواريخ|صلية صاروخية|اقتحام|اعتقالات|إطلاق نار من دبابات)/ui', $t)) $score -= 10;
    if (preg_match('/(تنويه|ندعوكم|للاشتراك|ناسا|القمر|رواد فضاء|درب التبانة)/ui', $t)) $score = 0;

    return max(0, min(200, (int)$score));
}


function so_bt_classify_v4($title, $source_name = '', $region = '', $actor = '') {
    $t = so_clean_text((string)$title);
    $s = so_clean_text((string)$source_name);
    $a = so_clean_text((string)$actor);
    $full = trim($t . ' ' . $s);
    
    // Check actor for resistance/military actors first
    $is_resistance_actor = preg_match('/(المقاومة الإسلامية|حزب الله|حماس|الجهاد الإسلامي|كتائب القسام|سرايا القدس|الحرس الثوري|قوة القدس)/ui', $a);
    $is_enemy_actor = preg_match('/(جيش العدو الإسرائيلي|الجيش الإسرائيلي|الجبهة الداخلية| IDF |Israel)/ui', $a);

    // 0) Non-intel / technical / awareness content
    if (preg_match('/(حماية_الخصوصية|أمن_المعلومات|أندرويد|هذا الفيديو يعرض|إعدادات مهم(?:ة|ّة)|نشرة تقنية|نصائح تقنية|خصوصية|التكنولوجيا)/ui', $full)) {
        return 'غير استخباراتي';
    }

    // 1) Military / security FIRST - Enhanced to catch resistance operations even with media sources
    $military_keywords = '(غارة|غارات|قصف|استهداف|اعتداء إسرائيلي|اعتداء اسرائيلي|صاروخ|صواريخ|صلية|مسيّرة|مسيرة|فسفوري|ميركافا|أغار|اغار|ضربة|اغتيال|هجوم مزدوج|محلّقة انقضاضية|طيران حربي|الطيران الحربي المعادي|استهدف بلد|استهدف بلدة|استهدفت بلدة|مجزرة|اقتحام|اعتقالات|دبابات|مدفعي|رصد قصف|raid|strike|bombing|missile|drone)';
    
    if (preg_match('/'.$military_keywords.'/ui', $full)) {
        return 'عسكري/أمني';
    }
    
    // Also classify as military if actor is resistance/enemy and title mentions attack/target
    if (($is_resistance_actor || $is_enemy_actor) && preg_match('/(استهدف|استهداف|ضرب|قصف|أطلق|صاروخ|مسيّرة|عملية|كمين|اشتباك)/ui', $t)) {
        return 'عسكري/أمني';
    }

    // 2) Alerts / warning / detection
    if (preg_match('/(صفارات الإنذار|صافرات الإنذار|انذار|إنذار|خشية تسلل|تم رصد|الجبهة الداخلية|تجدد دوي صفارات|دخول طائرات مسيّرة|إطلاق نار كواد كوبتر|إطلاق نار بحري|إطلاق نار من آليات)/ui', $full)) {
        return 'رصد/إنذار';
    }

    // 3) Economic / logistics
    if (preg_match('/(خام برنت|العقود الآجلة|النفط|الغاز|الشحنات|الملاحة|إمدادات|مضيق هرمز|ناقلات|أسواق|للبرميل|الطاقة|مشاريع نفطية|وقود|اقتصادي|اقتصادية)/ui', $full)) {
        return 'اقتصادي/لوجستي';
    }

    // 4) Condemnation / denunciation
    if (preg_match('/(ندين|نستنكر|شجب|استنكار|نندد|إدانة)/ui', $full)) {
        return 'شجب/استنكار';
    }

    // 5) Political / diplomatic / official - Enhanced
    $political_keywords = '(وزارة الخارجية|وزير|رئيس|حكومة|بيان|الفاتيكان|بابا الفاتيكان|مجموعة السبع|السفارة|روبيو|السفير|الدفاع|الخارجية|الرئاسة|مجلس الأمن|المستشار الألماني|الحكومة الألمانية|وزراء خارجية|وزيرة الجيوش|الدبلوماسي|مصدر دبلوماسي|الجيش الأردني|وزارة الدفاع|وزارة النفط|وزير الصحة|رئيس الجمهورية|قيادة الجيش|حرس الثورة|قائد قوة القدس|مفاوضات|وفد|محادثات|قمة|اجتماع دولي|مبادرة|وساطة|هدنة|وقف إطلاق النار)';
    
    if (preg_match('/'.$political_keywords.'/ui', $full)) {
        // But override if it's clearly about a military action
        if (!preg_match('/'.$military_keywords.'/ui', $full)) {
            return 'سياسي';
        }
        return 'عسكري/أمني'; // Military takes precedence
    }

    // 6) Media / coverage / commentary - Only if no military content
    if (preg_match('/(مراسل|وسائل إعلام|وسائل اعلام|إعلام العدو|اعلام العدو|القناة 12|يديعوت|فوكس نيوز|تغطية خاصة|آخر مستجدات العمليات العسكرية|رويترز|بلومبرغ|أكسيوس|واشنطن بوست|صحيفة|وكالة)/ui', $full)) {
        // Check if the actual content is about military action despite being from media source
        if (preg_match('/'.$military_keywords.'/ui', $t) || $is_resistance_actor || $is_enemy_actor) {
            return 'عسكري/أمني';
        }
        return 'إعلامي';
    }

    return 'تكتيكي/ميداني';
}



function so_bt_analyze_news_v2($title, $source_name = '') {
    $title = so_clean_text((string)$title);
    if (so_is_non_intel_noise($title)) {
        return ['ignored'=>true,'classification'=>'غير استخباراتي','region'=>'غير محدد','actor'=>'مستبعد/غير استخباراتي','score'=>0];
    }
    $region = function_exists('so_bt_detect_region_v3_patch') ? so_bt_detect_region_v3_patch($title, so_bt_detect_region_v2($title)) : so_bt_detect_region_v2($title);
    $class = sod_classify_event_v3(['title'=>$title,'content'=>'']);
    $actor = $class['actor_v2'] ?: 'فاعل غير محسوم';
    $classification = so_bt_classify_v4($title, $source_name, $region, $actor);
    $score = so_bt_score_news_v2($title, $classification, $actor, $region, $source_name);
    return ['ignored'=>false,'classification'=>$classification,'region'=>$region,'actor'=>$actor,'score'=>$score];
}


function so_build_dynamic_recommendations($stats) {
    $rec = [];
    $top_regions = $stats['top_regions'] ?? [];
    $threat_level = (string)($stats['threat_level'] ?? '');
    $avg_score = (int)($stats['avg_score'] ?? 0);
    $critical = (int)($stats['critical'] ?? 0);
    $trend = (string)($stats['trend'] ?? '');
    $has_il = !empty($stats['has_il']);
    $has_us = !empty($stats['has_us']);
    $has_iran = !empty($stats['has_iran']);
    $unattr_ratio = (float)($stats['unattributed_ratio'] ?? 0);
    $dominant_type = (string)($stats['dominant_type'] ?? '');
    $lebanon_count = (int)($top_regions['لبنان'] ?? 0);
    $duplicate_like_ratio = (float)($stats['duplicate_like_ratio'] ?? 0);

    if ($lebanon_count >= 25 && $avg_score >= 85) {
        $rec[] = 'تركيز الجهد التنفيذي على الساحة اللبنانية بسبب كثافة الضربات وارتفاع متوسط الخطورة.';
    }
    if ($trend === 'تصاعدي ↑' && $critical >= 10) {
        $rec[] = 'رفع وتيرة التحديث التنفيذي لأن المؤشرات تدل على تصاعد سريع في الساعات الأخيرة.';
    }
    if ($trend === 'هبوطي ↓' && $critical < 8) {
        $rec[] = 'الحفاظ على الرصد المكثف مع تجنب تضخيم سيناريوهات التصعيد ما لم تظهر موجة جديدة.';
    }
    if ($unattr_ratio >= 0.35) {
        $rec[] = 'إعطاء أولوية لتدقيق الأخبار غير المنسوبة وتجميع المتشابه منها قبل اعتمادها في الاستنتاج النهائي.';
    }
    if ($duplicate_like_ratio >= 0.28) {
        $rec[] = 'تقليل أثر الأخبار المتشابهة عبر التجميع قبل إدخالها في التقييم حتى لا يتضخم المشهد اصطناعياً.';
    }
    if ($has_il && $dominant_type === 'عسكري/أمني') {
        $rec[] = 'تركيز المراقبة على الضربات الجوية والأهداف المتحركة والبنى الحساسة ضمن مناطق النشاط الإسرائيلي المكثف.';
    }
    if ($has_us && $has_iran) {
        $rec[] = 'تعزيز الربط بين المؤشرات السياسية الأميركية–الإيرانية وبين التغيرات الميدانية قبل تثبيت أي تقدير نهائي.';
    }
    if ($dominant_type === 'سياسي') {
        $rec[] = 'تقديم التحليل السياسي والدبلوماسي على التقديرات الميدانية لأن النشاط التصريحي هو المهيمن حالياً.';
    }
    if ($dominant_type === 'شجب/استنكار' || $dominant_type === 'بيان') {
        $rec[] = 'عدم مساواة بيانات الشجب والاستنكار بالأحداث الميدانية عند حساب مستوى التهديد التنفيذي.';
    }
    if ($critical >= 20 && str_contains($threat_level, 'حرج')) {
        $rec[] = "ارتفاع غير اعتيادي في الأحداث الحرجة ({$critical} حدث) — إبقاء التصعيد التنفيذي عند المستوى الأعلى.";
    }
    if (empty($rec)) {
        $rec[] = 'لا توجد مؤشرات كافية على تغير نوعي يستدعي توصيات استثنائية — يُكتفى بالرصد الاعتيادي.';
    }
    return array_values(array_unique($rec));
}

function so_pick_top_developments($events, $limit = 8) {
    $picked = [];
    $seen = [];
    foreach ($events as $e) {
        $fp = so_build_title_fingerprint((string)($e['title'] ?? ''));
        if ($fp && isset($seen[$fp])) continue;
        $seen[$fp ?: md5((string)($e['title'] ?? ''))] = 1;
        $picked[] = $e;
        if (count($picked) >= $limit) break;
    }
    return $picked;
}

function so_extract_rss_items_fallback($xml_body, $source = []) {
    $items = [];
    if (!preg_match_all('/<item\b[\s\S]*?<\/item>/i', (string)$xml_body, $matches)) return [];
    foreach (($matches[0] ?? []) as $chunk) {
        $title = ''; $link = ''; $pub = '';
        if (preg_match('/<title>(?:<!\[CDATA\[)?([\s\S]*?)(?:\]\]>)?<\/title>/i', $chunk, $m)) $title = so_clean_text($m[1]);
        if (preg_match('/<link>(?:<!\[CDATA\[)?([\s\S]*?)(?:\]\]>)?<\/link>/i', $chunk, $m)) $link = so_normalize_event_link(trim(html_entity_decode($m[1], ENT_QUOTES | ENT_HTML5, 'UTF-8')));
        if (preg_match('/<pubDate>(?:<!\[CDATA\[)?([\s\S]*?)(?:\]\]>)?<\/pubDate>/i', $chunk, $m)) $pub = trim($m[1]);
        $candidate = ['title'=>$title,'link'=>$link?:so_normalize_event_link((string)($source['url']??'')),'source'=>$source['name']??'','color'=>$source['color']??'','date'=>strtotime($pub)?:time(),'agency_loc'=>$source['location']??'','image_url'=>''];
        if (!so_should_publish_raw_item($candidate)) continue;
        $items[] = $candidate;
        if (count($items) >= so_source_items_limit()) break;
    }
    return $items;
}

function so_extract_origin_target_layer_simple($title, $region = '', $actor = '') {
    $text = so_clean_text((string)$title);
    $lower = mb_strtolower($text);
    $origin = ''; $target = ''; $battlefield = (string)$region; $classification = 'general';
    if (preg_match('/(أبو عبيدة|كتائب القسام|حماس|حركة حماس)/ui', $lower)) { $origin = 'فلسطين'; $classification = 'palestinian_statement'; }
    elseif (preg_match('/(سرايا القدس|أبو حمزة|الجهاد الإسلامي)/ui', $lower)) { $origin = 'فلسطين'; $classification = 'palestinian_statement'; }
    elseif (preg_match('/(الحرس الثوري|حرس الثورة|الجمهورية الإسلامية|إيران|خاتم الأنبياء)/ui', $lower)) {
        $origin = 'إيران';
        $classification = preg_match('/(بيان|أعلن|أفاد|كشف|صرح|أكد)/ui', $lower) ? 'origin_statement' : 'iran_related';
    }
    elseif (preg_match('/(وزارة الصحة اللبنانية|الرئيس عون|الجيش اللبناني|لبنان:)/ui', $lower)) $origin = 'لبنان';
    if (preg_match('/(إسرائيل|الاحتلال|تل أبيب|حيفا|الأراضي المحتلة|الجبهة الداخلية)/ui', $lower)) $target = 'الأراضي المحتلة (إسرائيل)';
    elseif (preg_match('/(لبنان|بيروت|الضاحية|الجنوب|صور|النبطية)/ui', $lower)) $target = 'لبنان';
    elseif (preg_match('/(إيران|بوشهر|طهران|نطنز|منظمة الطاقة الذرية)/ui', $lower)) $target = 'إيران';
    elseif (preg_match('/(غزة|الضفة|فلسطين|رفح|خان يونس|جباليا)/ui', $lower)) $target = 'فلسطين';
    if (preg_match('/(غارة|قصف|استهداف|هجوم|اشتباك|انفجار|اغتيال|توغل|إطلاق صواريخ|مسيّرة|مسيرة)/ui', $lower) && $target !== '') { $battlefield = $target; $classification = 'kinetic_event'; }
    elseif ($origin !== '' && preg_match('/(بيان|أعلن|أفاد|صرح|أكد|قال)/ui', $lower)) $battlefield = $origin;
    return ['origin_country'=>$origin?:'غير محدد','target_country'=>$target?:'غير محدد','battlefield_location'=>$battlefield?:($region?:'غير محدد'),'classification'=>$classification];
}

function so_get_source_reliability_meta($source_name) {
    $source_name = trim((string)$source_name);
    $search_sets = [get_option('so_sources',[]),get_option('so_tg_sources',[]),get_option('so_x_sources',[]),get_option('so_yt_sources',[])];
    foreach ($search_sets as $set) {
        if (!is_array($set)) continue;
        foreach ($set as $src) {
            if (!is_array($src)) continue;
            if (trim((string)($src['name']??'')) === $source_name) {
                $label = trim((string)($src['reliability']??''));
                if ($label !== '') {
                    $weight = 0;
                    if ($label === 'موثوق') $weight = 15; elseif ($label === 'محايد') $weight = 5; elseif ($label === 'غير موثوق') $weight = -25; elseif ($label === 'غير محايد') $weight = -15;
                    return ['label'=>$label,'weight'=>$weight];
                }
            }
        }
    }
    $rels  = get_option('so_source_reliability', []);
    $label = trim((string)($rels[$source_name]??'غير محدد'));
    $weight = 0;
    if ($label === 'موثوق') $weight = 15; elseif ($label === 'محايد') $weight = 5; elseif ($label === 'غير موثوق') $weight = -25; elseif ($label === 'غير محايد') $weight = -15;
    return ['label'=>$label===''?'غير محدد':$label,'weight'=>$weight];
}

function so_extract_best_datetime_from_text($title, $fallback_ts) {
    $title = (string)$title; $fallback_ts = (int)$fallback_ts ?: time();
    if (preg_match('/([0-9٠-٩]{1,2})[\/-]([0-9٠-٩]{1,2})[\/-]([0-9٠-٩]{2,4})(?:[^0-9٠-٩]{1,12}([0-9٠-٩]{1,2}:[0-9٠-٩]{2}))?/u', $title, $m)) {
        $day = intval(strtr($m[1],'٠١٢٣٤٥٦٧٨٩','0123456789'));
        $mon = intval(strtr($m[2],'٠١٢٣٤٥٦٧٨٩','0123456789'));
        $yr  = intval(strtr($m[3],'٠١٢٣٤٥٦٧٨٩','0123456789'));
        if ($yr < 100) $yr += 2000;
        $hm = !empty($m[4]) ? strtr($m[4],'٠١٢٣٤٥٦٧٨٩','0123456789') : gmdate('H:i', $fallback_ts);
        return sprintf('%04d-%02d-%02d %s', $yr, max(1,min(12,$mon)), max(1,min(31,$day)), $hm);
    }
    return gmdate('Y-m-d H:i', $fallback_ts);
}

function so_pick_brief_location_from_text($title, $fallback = '') {
    $title = so_clean_text((string)$title);
    $places = ['عيناتا','عكا','مركبا','المرج','الطيبة','حاروف','النبطية','السلطانية','أرزون','الضفة الغربية','طولكرم','الخليل','قطاع غزة','حي التفاح','أصفهان','بوشهر','مطار بغداد','بغداد','حيفا','نهاريا','عسقلان','تل أبيب','مضيق هرمز'];
    foreach ($places as $place) if (mb_stripos($title, $place) !== false) return $place;
    return $fallback;
}

function so_extract_precise_5w1h($title, $item, $actor, $region, $entities, $flags, $why, $confidence) {
    $title = so_clean_text((string)$title); $lower = mb_strtolower($title);
    $source_name = (string)($item['source'] ?? $item['source_name'] ?? '');
    $source_meta = so_get_source_reliability_meta($source_name);
    $layer = so_extract_origin_target_layer_simple($title, (string)$region, (string)$actor);
    $who_primary = (string)$actor; $who_secondary = '';
    
    // كشف السياق الدبلوماسي/السياسي - لا تُنسب الأحداث السياسية لإسرائيل
    $is_diplomatic_political = preg_match('/(مفاوضات|محادثات|وفد|اجتماع|لقاء|قمة|مؤتمر|تصريح|قال|أكد|صرح|أعلن|أفاد|نقل عن|بحسب|وفق|ذكر|كشف|شجب|استنكر|أدان|رحب|حث|دعا|طالب|وزارة الخارجية|الرئيس|رئيس الوزراء|الأمم المتحدة|الاتحاد الأوروبي|جامعة الدول العربية|بيان سياسي|تقرير إعلامي|وسائل إعلام|صحيفة|قناة|إذاعة|تحليل|رويترز|غارديان|نيويورك تايمز|وول ستريت جورنال|أكسيوس|بوليتيكو|اقتصاد|نفط|غاز|طاقة|أسعار|سوق|تجارة|استثمار|بنك|صندوق|عملة|تضخم|مالية)/ui', $lower);
    
    if (preg_match('/(أبو عبيدة|كتائب القسام|ناطق القسام)/ui', $lower)) { $who_primary = 'كتائب القسام (حماس)'; $who_secondary = 'حماس'; }
    elseif (preg_match('/(أبو حمزة|سرايا القدس)/ui', $lower)) { $who_primary = 'سرايا القدس (الجهاد الإسلامي)'; $who_secondary = 'الجهاد الإسلامي'; }
    elseif (preg_match('/(خاتم الأنبياء|الحرس الثوري|حرس الثورة|العلاقات العامة في حرس الثورة)/ui', $lower)) { $who_primary = 'مقر خاتم الأنبياء / الحرس الثوري الإيراني'; $who_secondary = 'إيران'; }
    elseif (preg_match('/(بيان صادر عن المقاومة الإسلامية|المقاومة الإسلامية في لبنان|دفاعًا عن لبنان)/ui', $lower)) { $who_primary = 'المقاومة الإسلامية (حزب الله)'; $who_secondary = 'لبنان'; }
    // الشرط الحرجة: لا تُنسب إسرائيل إلا في الأحداث العسكرية الحركية الصريحة
    elseif (!$is_diplomatic_political && preg_match('/(الجيش الإسرائيلي|جيش الاحتلال|طيران الاحتلال|سلاح الجو الإسرائيلي|القوات الإسرائيلية|مقاتلات الاحتلال|مدفعية الاحتلال|قصف إسرائيلي|قصف اسرائيلي|غارة إسرائيلية|غارة اسرائيلية|غارات إسرائيلية|غارات اسرائيلية|عدوان إسرائيلي|عدوان اسرائيلي)/ui', $lower)) {
        $who_primary = 'جيش العدو الإسرائيلي';
    }
    elseif (preg_match('/(وزارة الصحة اللبنانية)/ui', $lower)) { $who_primary = 'وزارة الصحة اللبنانية / تقرير'; $who_secondary = 'لبنان'; }
    $has_action_verbs   = preg_match('/(استهدف|قصف|هاجم|أطلق|نفذ|أغار|اغار|اغتيال|اقتحام|دمر|فجر|أسقط|اعترض|كمين|اشتباك|غارة|هجوم|صلية|مسيرات)/ui', $lower) === 1;
    $has_statement_verbs = preg_match('/(قال|صرح|أكد|أفاد|أعلن|الناطق|بيان|العلاقات العامة|المتحدث)/ui', $lower) === 1;
    $what_class = 'general';
    if (!empty($flags['has_direct_kinetic']) || $has_action_verbs) $what_class = 'kinetic';
    elseif (!empty($flags['has_alert_only'])) $what_class = 'alert';
    elseif (!empty($flags['is_summary_report'])) $what_class = 'report';
    elseif (!empty($flags['is_rumor'])) $what_class = 'rumor';
    elseif (!empty($flags['is_statement']) || $has_statement_verbs) $what_class = 'statement';
    if ($has_statement_verbs && !$has_action_verbs) $what_class = 'statement';
    $what_type = 'حدث عام';
    if ($what_class === 'statement') $what_type = 'تصريح / بيان';
    elseif ($what_class === 'report') $what_type = 'تقرير / متابعة';
    elseif ($what_class === 'alert') $what_type = 'إنذار / رصد';
    elseif (preg_match('/(غارة)/ui', $lower)) $what_type = 'غارة';
    elseif (preg_match('/(اقتحام)/ui', $lower)) $what_type = 'اقتحام';
    elseif (preg_match('/(استهدف|استهداف)/ui', $lower)) $what_type = 'استهداف';
    elseif (preg_match('/(هجوم)/ui', $lower)) $what_type = 'هجوم';
    elseif (preg_match('/(كمين)/ui', $lower)) $what_type = 'كمين';
    elseif (!empty($entities['actions'])) $what_type = (string)reset($entities['actions']);
    $why_reason = (string)$why;
    if (preg_match('/(دفاعًا عن[^\.,،\n]+)/u', $title, $m)) $why_reason = trim($m[1]);
    elseif (preg_match('/(رد(?:اً)? على[^\.,،\n]+)/u', $title, $m)) $why_reason = trim($m[1]);
    $how_weapon = !empty($entities['weapons']) ? implode('، ', array_unique(array_filter($entities['weapons']))) : 'غير محدد';
    $how_method = $what_class === 'statement' ? 'خطاب / بيان رسمي' : ($what_class === 'report' ? 'متابعة / نقل معلومات' : ($what_class === 'alert' ? 'رصد / إنذار مبكر' : $how_weapon));
    $where_origin = $layer['origin_country'] ?? 'غير محدد'; $where_target = $layer['target_country'] ?? 'غير محدد';
    $where_event = $layer['battlefield_location'] ?? ($region ?: 'غير محدد');
    $brief_place = so_pick_brief_location_from_text($title, '');
    if ($brief_place !== '') $where_event = $brief_place;
    $where_summary = $where_event;
    if ($what_class === 'statement' && $where_origin !== 'غير محدد' && $where_target !== 'غير محدد' && $where_origin !== $where_target) $where_summary = $where_origin . ' → ' . $where_target;
    $when_event    = so_extract_best_datetime_from_text($title, (int)($item['date'] ?? $item['event_timestamp'] ?? time()));
    $when_publish  = gmdate('Y-m-d H:i', (int)($item['date'] ?? $item['event_timestamp'] ?? time()));
    $confidence_overall = max(10, min(99, intval($confidence) + (int)$source_meta['weight']));
    return [
        'who_primary'=>$who_primary?:'غير محدد','who_secondary'=>$who_secondary,'who_source'=>$source_name?:'غير محدد',
        'what_type'=>$what_type?:'غير محدد','what_class'=>$what_class,'why_reason'=>$why_reason?:'غير محدد',
        'how_method'=>$how_method,'how_weapon'=>$how_weapon,'when_event'=>$when_event,'when_publish'=>$when_publish,
        'where_origin'=>$where_origin?:'غير محدد','where_target'=>$where_target?:'غير محدد',
        'where_event'=>$where_event?:'غير محدد','where_summary'=>$where_summary?:'غير محدد',
        'source_reliability'=>$source_meta['label'],'source_reliability_weight'=>(int)$source_meta['weight'],
        'confidence_who'=>$confidence_overall,'confidence_what'=>$confidence_overall,
        'confidence_where'=>$confidence_overall,'confidence_why'=>$confidence_overall,'confidence_overall'=>$confidence_overall,
    ];
}

function so_narrative_clean_title($title) {
    $title = so_clean_text((string)$title);
    $title = html_entity_decode($title, ENT_QUOTES | ENT_HTML5, 'UTF-8');
    $title = preg_replace('/\s+/u', ' ', trim($title));
    $title = preg_replace('/^(?:#\S+\s*)+/u', '', $title);
    $title = preg_replace('/^(?:إيران|لبنان|فلسطين|الأراضي المحتلة \(إسرائيل\)|سوريا|العراق)\s*[:\-–|]\s*/u', '', $title);
    return trim($title);
}

function so_narrative_limit($text, $limit = 170) {
    $text = trim((string)$text);
    if (mb_strlen($text) <= $limit) return $text;
    $cut = sod_safe_substr($text, 0, $limit);
    $cut = preg_replace('/\s+\S*$/u', '', $cut);
    return rtrim($cut, " .،:-") . '...';
}

function so_build_event_narrative_line($event) {
    $title = so_narrative_clean_title((string)($event['title'] ?? ''));
    $wd = [];
    if (!empty($event['war_data']) && is_string($event['war_data'])) $wd = json_decode($event['war_data'], true) ?: [];
    $p = is_array($wd['5w1h'] ?? null) ? $wd['5w1h'] : [];
    $who = trim((string)($p['who_primary'] ?? ($event['actor_v2'] ?? '')));
    $what = trim((string)($p['what_type'] ?? ''));
    $what_class = trim((string)($p['what_class'] ?? ''));
    $where = trim((string)($p['where_event'] ?? ($p['where_summary'] ?? '')));
    if ($what_class === 'statement') {
        if (strpos($who, 'كتائب القسام') !== false) return so_narrative_limit('كتائب القسام (حماس): ' . $title, 175);
        if (strpos($who, 'خاتم الأنبياء') !== false || strpos($who, 'الحرس الثوري') !== false) return so_narrative_limit('مقر خاتم الأنبياء / الحرس الثوري الإيراني: ' . $title, 175);
        if (strpos($who, 'حزب الله') !== false) return so_narrative_limit('المقاومة الإسلامية (حزب الله): ' . $title, 175);
        return so_narrative_limit(($who !== '' && $who !== 'غير محدد' ? $who . ': ' : '') . $title, 175);
    }
    if ($what_class === 'alert') return so_narrative_limit('إنذار ميداني في ' . ($where ?: 'المنطقة المحددة') . ': ' . $title, 175);
    if ($what_class === 'report') return so_narrative_limit($title, 175);
    if ($what !== '' && $what !== 'حدث عام' && $where !== '' && $where !== 'غير محدد' && $who !== '' && $who !== 'غير محدد') return so_narrative_limit($who . ' نفّذت ' . $what . ' في ' . $where, 175);
    return so_narrative_limit($title, 175);
}

function so_build_actor_confidence($title, $region, $actor) {
    $lower = mb_strtolower((string)$title);
    $primary = so_normalize_actor_label((string)$actor); $secondary = ''; $source = 'unknown'; $confidence = 35;
    $nature = so_detect_verification_nature($title);

    // ── كشف الفاعل الإسرائيلي (الأولوية القصوى للعمليات الحركية) ──────────
    // ملاحظة حرجة: لا تُنسب الأحداث الدبلوماسية/السياسية لإسرائيل أبداً
    // توسيع فلترة الأحداث غير العسكرية لتشمل جميع أشكال التصريحات والأخبار السياسية
    $is_diplomatic_political = preg_match('/(مفاوضات|محادثات|وفد|اجتماع|لقاء|قمة|مؤتمر|تصريح|قال|أكد|صرح|أعلن|أفاد|نقل عن|بحسب|وفق|ذكر|كشف|شجب|استنكر|أدان|رحب|حث|دعا|طالب|وزارة الخارجية|الرئيس|رئيس الوزراء|الأمم المتحدة|الاتحاد الأوروبي|جامعة الدول العربية|بيان سياسي|تقرير إعلامي|وسائل إعلام|صحيفة|قناة|إذاعة|تحليل|رويترز|غارديان|نيويورك تايمز|وول ستريت جورنال|أكسيوس|بوليتيكو|اقتصاد|نفط|غاز|طاقة|أسعار|سوق|تجارة|استثمار|بنك|صندوق|عملة|تضخم|مالية)/ui', $lower);
    
    // نمط العمليات العسكرية الحركية الصريحة فقط
    $il_kinetic = '/(الجيش الإسرائيلي|جيش الاحتلال|طيران الاحتلال|سلاح الجو الإسرائيلي|مقاتلات الاحتلال|مدفعية الاحتلال|الدبابات الإسرائيلية|الزوارق الإسرائيلية|المسيّرات الإسرائيلية|مسيّرة إسرائيلية|مسيرة إسرائيلية|قصف إسرائيلي|قصف اسرائيلي|غارة إسرائيلية|غارة اسرائيلية|غارات إسرائيلية|غارات اسرائيلية|عدوان إسرائيلي|عدوان اسرائيلي|الاحتلال الإسرائيلي|الاحتلال الاسرائيلي|المعادي|المعادية|طيران مسير معادي|الطيران المسير المعادي|طائرة معادية|طائرات معادية|الطيران المعادي|مسيّرة معادية|مسيرة معادية|مسيّرات معادية|زوارق معادية|دبابة معادية|دبابات معادية|مدفعية معادية|قوات معادية|قوة معادية)/ui';
    
    // الشرط الحرجة: إسرائيل تُنسب فقط إذا كان الحدث عسكرياً صريحاً وليس دبلوماسياً/سياسياً
    if (!$is_diplomatic_political && preg_match($il_kinetic, $lower)) {
        $primary = 'جيش العدو الإسرائيلي'; $source = 'explicit'; $confidence = 94;
    }
    // ── المقاومة الإسلامية / حزب الله ──────────────────────────────────────
    elseif (preg_match('/(المقاومة الإسلامية|حزب الله|نصرالله|قوة الرضوان|المقاومة في لبنان)/ui', $lower)) {
        $primary = 'المقاومة الإسلامية (حزب الله)'; $source = 'explicit'; $confidence = 94;
    }
    // ── كتائب القسام / حماس ─────────────────────────────────────────────────
    elseif (preg_match('/(كتائب القسام|أبو عبيدة|ناطق القسام|حركة حماس)/ui', $lower)) {
        $primary = 'كتائب القسام (حماس)'; $source = 'explicit'; $confidence = 94;
    }
    // ── الحرس الثوري الإيراني ───────────────────────────────────────────────
    elseif (preg_match('/(الحرس الثوري|حرس الثورة|خاتم الأنبياء|فيلق القدس)/ui', $lower)) {
        $primary = 'الحرس الثوري الإيراني'; $source = 'explicit'; $confidence = 93;
    }
    // ── سرايا القدس / الجهاد ────────────────────────────────────────────────
    elseif (preg_match('/(سرايا القدس|أبو حمزة|الجهاد الإسلامي الفلسطيني)/ui', $lower)) {
        $primary = 'سرايا القدس (الجهاد الإسلامي)'; $source = 'explicit'; $confidence = 92;
    }
    // ── أنصار الله / الحوثيون ───────────────────────────────────────────────
    elseif (preg_match('/(أنصار الله|الحوثي|يحيى سريع|القوات المسلحة اليمنية)/ui', $lower)) {
        $primary = 'أنصار الله (الحوثيون)'; $source = 'explicit'; $confidence = 91;
    }

    // ── البادئات الجغرافية ────────────────────────────────────────────────────
    // ملاحظة: "لبنان:" بادئة جغرافية وليست فاعلاً — لا تُعيَّن الدولة اللبنانية تلقائياً
    if (preg_match('/^(?:#\s*)?(الولايات المتحدة الأميركية|الولايات المتحدة|أميركا|اميركا)\s*[:\-–|]/ui', $title)) {
        $primary = 'الولايات المتحدة'; $source = 'prefix'; $confidence = max($confidence, 88);
    } elseif (preg_match('/^(?:#\s*)?(إيران|ايران)\s*[:\-–|]/ui', $title)) {
        $primary = 'إيران'; $source = 'prefix'; $confidence = max($confidence, 87);
    } elseif (preg_match('/^(?:#\s*)?(ماليزيا|تركيا|روسيا|الصين|ألمانيا|فرنسا|بريطانيا)\s*[:\-–|]/ui', $title)) {
        // بادئة دولة صريحة → فاعل دبلوماسي/إعلامي
        if (in_array($primary, ['فاعل قيد التقييم','غير محدد'], true)) {
            $source = 'prefix'; $confidence = max($confidence, 75);
        }
    }

    // ── تجاوزات نهائية صريحة ─────────────────────────────────────────────────
    if (preg_match('/(البابا|الفاتيكان)/ui', $lower)) { $primary = 'الكرسي الرسولي / البابا'; $source = 'explicit'; $confidence = 98; }
    if (preg_match('/(ترامب|ترمب|البيت الأبيض|فوكس نيوز)\b/ui', $lower)) { $primary = 'الولايات المتحدة'; $source = 'explicit'; $confidence = 96; }
    if (preg_match('/(وزارة الصحة اللبنانية|الهلال الأحمر اللبناني)/ui', $lower)) { $primary = 'وزارة الصحة اللبنانية / تقرير'; $source = 'explicit'; $confidence = 95; }
    if (preg_match('/(الجيش اللبناني|قوى الأمن الداخلي)\b/ui', $lower)) { $primary = 'الجيش اللبناني'; $source = 'explicit'; $confidence = 93; }

    if ($nature === 'defensive_alert' || $nature === 'detected_launch') {
        if ($primary === 'فاعل قيد التقييم') { $primary = 'الجبهة الداخلية الإسرائيلية'; $source = 'verification_matrix'; $confidence = ($nature === 'defensive_alert') ? 52 : 46; }
    }
    return ['primary'=>$primary,'secondary'=>$secondary,'confidence'=>$confidence,'source'=>$source,'nature'=>$nature];
}

// ==========================================================================
// دالة الإسناد الاحترافي — Attribution Engine (Rules v2)
// ==========================================================================
function so_extract_actor_attribution(string $text): array {
    $result = ['name'=>null,'raw'=>null,'status'=>'unattributed','confidence'=>0.0,'evidence'=>[]];
    $lower  = mb_strtolower(trim($text));

    // ── قواعد فلسطينية/استيطانية صريحة ───────────────────────────────────
    if (preg_match('/(من قبل فلسطيني|فلسطينيون|فلسطينيين|فلسطيني\b|شاب فلسطيني|مقاوم فلسطيني)/ui', $lower)) {
        return ['name'=>'فلسطينيون','raw'=>'فلسطيني','status'=>'confirmed','confidence'=>0.94,'evidence'=>['فلسطيني']];
    }
    if (preg_match('/(مستوطن|مستوطنين|بؤرة استيطانية)/ui', $lower) && preg_match('/(الضفة الغربية|طوباس|تياسير|حزما|جنين|نابلس|الخليل|رام الله)/ui', $lower)) {
        return ['name'=>'فلسطينيون','raw'=>'مستوطن/الضفة الغربية','status'=>'inferred','confidence'=>0.78,'evidence'=>['مستوطن','الضفة الغربية']];
    }

    

    // ── جدول توحيد الأسماء ──────────────────────────────────────────────────
    $PERSON_TO_ACTOR = [
        'نتنياهو'=>'جيش العدو الإسرائيلي','بن غفير'=>'جيش العدو الإسرائيلي',
        'غالانت'=>'جيش العدو الإسرائيلي','كوهين'=>'جيش العدو الإسرائيلي',
        'ترامب'=>'الولايات المتحدة','ترمب'=>'الولايات المتحدة',
        'جي دي فانس'=>'الولايات المتحدة','فانس'=>'الولايات المتحدة',
        'ستيف ويتكوف'=>'الولايات المتحدة','ويتكوف'=>'الولايات المتحدة',
        'بلينكن'=>'الولايات المتحدة','البيت الأبيض'=>'الولايات المتحدة',
        'خامنئي'=>'إيران','بزشكيان'=>'إيران','أمير عبداللهيان'=>'إيران',
        'عراقجي'=>'إيران','قاليباف'=>'إيران',
        'السيسي'=>'مصر','الملك عبدالله'=>'الأردن',
        'روبرت بيب'=>'الولايات المتحدة',
    ];

    // ── قرائن مؤكدة (confirmed) ─────────────────────────────────────────────
    // ملاحظة حرجة: لا تُنسب الأحداث الدبلوماسية/السياسية لإسرائيل أبداً
    // فقط الأحداث العسكرية الحركية الصريحة تُنسب لإسرائيل
    $is_diplomatic_political = preg_match('/(مفاوضات|محادثات|وفد|اجتماع|لقاء|قمة|مؤتمر|تصريح|قال|أكد|صرح|أعلن|أفاد|نقل عن|بحسب|وفق|ذكر|كشف|شجب|استنكر|أدان|رحب|حث|دعا|طالب|وزارة الخارجية|الرئيس|رئيس الوزراء|الأمم المتحدة|الاتحاد الأوروبي|جامعة الدول العربية|بيان سياسي|تقرير إعلامي|وسائل إعلام|صحيفة|قناة|إذاعة|تحليل|رويترز|غارديان|نيويورك تايمز|وول ستريت جورنال|أكسيوس|بوليتيكو|اقتصاد|نفط|غاز|طاقة|أسعار|سوق|تجارة|استثمار|بنك|صندوق|عملة|تضخم|مالية)/ui', $lower);
    
    $CONFIRMED = [
        'جيش العدو الإسرائيلي' => [
            // أفعال عسكرية صريحة فقط - لا تشمل التصريحات أو الأخبار الدبلوماسية
            'الجيش الإسرائيلي','جيش الاحتلال','قصف إسرائيلي',
            'قصف اسرائيلي','غارة إسرائيلية','غارة اسرائيلية','عدوان إسرائيلي',
            'عدوان اسرائيلي','سلاح الجو الإسرائيلي','مقاتلات الاحتلال',
            'طيران الاحتلال','مدفعية الاحتلال','الدبابات الإسرائيلية',
            'المسيّرات الإسرائيلية','مسيّرة إسرائيلية','مسيرة إسرائيلية',
            'قوات الاحتلال','الاحتلال الإسرائيلي',
        ],
        'الولايات المتحدة' => [
            'الولايات المتحدة','الإدارة الأميركية','الإدارة الأمريكية',
            'واشنطن','أميركا','أمريكا','البيت الأبيض',
        ],
        'إيران' => [
            'إيران','طهران','الجمهورية الإسلامية',
            'وزارة الخارجية الإيرانية',
        ],
        'الحرس الثوري الإيراني' => [
            'الحرس الثوري','حرس الثورة','فيلق القدس','خاتم الأنبياء',
        ],
        'حزب الله' => ['حزب الله','المقاومة الإسلامية في لبنان','نصرالله'],
        'الجيش اللبناني' => ['الجيش اللبناني','قوى الأمن الداخلي'],
        'أنصار الله (الحوثيون)' => ['أنصار الله','الحوثي','يحيى سريع','القوات المسلحة اليمنية'],
        'كتائب القسام (حماس)' => ['كتائب القسام','أبو عبيدة','حركة حماس'],
    ];

    // ── قرائن استنتاجية (inferred) ──────────────────────────────────────────
    $INFERRED = [
        'جيش العدو الإسرائيلي' => [
            'الطيران المعادي','الطيران المسير المعادي','مسيّرة معادية',
            'مسيرة معادية','المعادي','المعادية','دبابة معادية','مدفعية معادية',
            'الاحتلال استهدف','قصف من مواقع الاحتلال','الاحتلال يقصف',
        ],
        'الولايات المتحدة' => [
            'القواعد الأميركية','القواعد الأمريكية',
            'قصف أميركي','هجوم على قاعدة أميركية',
        ],
    ];

    // ── ألفاظ المصادر والادعاء (claimed) ────────────────────────────────────
    $CLAIM_VERBS = ['أعلن','أعلنت','قال','قالت','صرح','صرحت','بحسب','وفق','وفقاً','أفادت','ذكرت','نقلت','أكد','أكدت','كشف','نفذنا','استهدفنا','نفذت','تبنّت'];

    // ── ألفاظ التنازع والشك (contested) ─────────────────────────────────────
    $CONTESTED = ['نفى','نفت','روايات متضاربة','تضارب','لم يتسن التأكد','غير مؤكد','يُعتقد','على الأرجح','ربما','قد يكون'];

    // ── 1. تحقق من التنازع أولاً ─────────────────────────────────────────────
    foreach ($CONTESTED as $term) {
        if (mb_strpos($lower, mb_strtolower($term)) !== false) {
            $result['status'] = 'contested'; $result['confidence'] = 0.40;
            $result['evidence'][] = $term;
        }
    }

    // ── 2. إسناد مؤكد (confirmed) ────────────────────────────────────────────
    // ملاحظة حرجة: لا تُطبَّق قواعد الإسناد لإسرائيل على الأحداث الدبلوماسية/السياسية
    foreach ($CONFIRMED as $actor => $patterns) {
        foreach ($patterns as $p) {
            if (mb_strpos($lower, mb_strtolower($p)) !== false) {
                // استثناء حرجة: إذا كان الفاعل إسرائيل والحدث دبلوماسي/سياسي، لا تُنسب له
                if ($actor === 'جيش العدو الإسرائيلي' && $is_diplomatic_political) {
                    continue; // تخطي هذا النمط لإسرائيل في الأحداث غير العسكرية
                }
                $result['name']   = $actor;
                $result['raw']    = $p;
                $result['status'] = ($result['status'] === 'contested') ? 'contested' : 'confirmed';
                $result['confidence'] = ($result['status'] === 'contested') ? 0.40 : 0.95;
                $result['evidence'][] = $p;
                return $result;
            }
        }
    }

    // ── 3. ربط الأشخاص بجهاتهم ──────────────────────────────────────────────
    // استثناء حرجة: لا تُنسب تصريحات المسؤولين الإسرائيليين للأحداث الدبلوماسية كـ "جيش العدو"
    foreach ($PERSON_TO_ACTOR as $person => $actor) {
        if (mb_strpos($lower, mb_strtolower($person)) !== false) {
            // إذا كان الشخص إسرائيلي والحدث دبلوماسي/سياسي، لا تُنسب للجيش
            if ($actor === 'جيش العدو الإسرائيلي' && $is_diplomatic_political) {
                // تعيين فاعل بديل أو تركه غير محسوم
                $result['name']       = 'فاعل غير محسوم';
                $result['raw']        = $person . ' (دبلوماسي/سياسي)';
                $result['status']     = 'inferred';
                $result['confidence'] = 0.60;
                $result['evidence'][] = $person;
                return $result;
            }
            $result['name']       = $actor;
            $result['raw']        = $person;
            $result['status']     = 'confirmed';
            $result['confidence'] = 0.93;
            $result['evidence'][] = $person;
            return $result;
        }
    }

    // ── 4. إسناد استنتاجي (inferred) ─────────────────────────────────────────
    // ملاحظة حرجة: لا تُطبَّق قواعد الإسناد الاستنتاجي لإسرائيل على الأحداث الدبلوماسية/السياسية
    foreach ($INFERRED as $actor => $patterns) {
        foreach ($patterns as $p) {
            if (mb_strpos($lower, mb_strtolower($p)) !== false) {
                // استثناء حرجة: إذا كان الفاعل إسرائيل والحدث دبلوماسي/سياسي، لا تُنسب له
                if ($actor === 'جيش العدو الإسرائيلي' && $is_diplomatic_political) {
                    continue; // تخطي هذا النمط لإسرائيل في الأحداث غير العسكرية
                }
                $result['name']       = $actor;
                $result['raw']        = $p;
                $result['status']     = 'inferred';
                $result['confidence'] = 0.75;
                $result['evidence'][] = $p;
                return $result;
            }
        }
    }

    // ── 5. إسناد منسوب (claimed) — فعل ادعاء موجود لكن لا فاعل محدد ─────────
    foreach ($CLAIM_VERBS as $verb) {
        if (mb_strpos($lower, mb_strtolower($verb)) !== false) {
            $result['status']     = 'claimed';
            $result['confidence'] = 0.65;
            $result['evidence'][] = $verb;
            break;
        }
    }

    return $result; // unattributed إذا لم يُطابَق شيء
}

// ترجمة حالة الإسناد إلى نص عربي
function so_attribution_label(string $status): string {
    return match($status) {
        'confirmed'    => 'مؤكد',
        'inferred'     => 'استنتاجي',
        'claimed'      => 'منسوب',
        'contested'    => 'متنازع عليه',
        'unattributed' => 'غير منسوب',
        default        => 'غير محدد',
    };
}

function so_attribution_icon(string $status): string {
    return match($status) {
        'confirmed'    => '✅',
        'inferred'     => '🔷',
        'claimed'      => '📣',
        'contested'    => '⚠️',
        'unattributed' => '🕳️',
        default        => '❓',
    };
}

/**
 * استخراج الموقع التفصيلي (بلدة/منطقة محددة) من عنوان الخبر
 * يُستخدم لبناء الهدف بصيغة "لبنان / مجدل سلم"
 */
function so_extract_specific_location(string $title): string {
    $lower = mb_strtolower($title, 'UTF-8');
    // نمط 1: "المناطق المتأثرة: مكان" أو "المنطقة المتأثرة: مكان"
    if (preg_match('/المناطق? المتأثر[ةه][:\s]+([^\n،.()]{3,30})/u', $title, $m)) {
        return trim($m[1]);
    }
    // نمط 2: "في بلدة/قرية/مدينة/منطقة X" / "في ضيعة X"
    if (preg_match('/في (?:بلدة|قرية|قضاء|ضيعة|محيط|حي|بلدية|مدينة|قرب|منطقة|أحياء)\s+([^\s،.()]{3,25})/u', $title, $m)) {
        return trim($m[1]);
    }
    // نمط 3: "استهداف X" / "سقوط قذيفة/صاروخ في X"
    if (preg_match('/(?:سقوط|استهداف|تدمير|قصف)\s+(?:قذيفة|صاروخ|مسيرة|آلية|مركبة|مبنى|منزل)\s+في\s+([^\s،.()]{3,25})/u', $title, $m)) {
        return trim($m[1]);
    }
    // نمط 4: "الجنوب" / "البقاع" / "الضاحية" ← مناطق لبنانية عامة
    $subregions = [
        'الجنوب'          => 'الجنوب',
        'جنوب لبنان'      => 'الجنوب',
        'الضاحية الجنوبية'=> 'الضاحية الجنوبية',
        'البقاع'          => 'البقاع',
        'بعلبك'           => 'البقاع (بعلبك)',
        'الهرمل'          => 'البقاع (الهرمل)',
        'صيدا'            => 'صيدا',
        'صور'             => 'صور',
        'النبطية'         => 'النبطية',
        'بنت جبيل'        => 'بنت جبيل',
        'مرجعيون'         => 'مرجعيون',
        'عيتا الشعب'      => 'عيتا الشعب',
        'بلدة شبعا'       => 'شبعا',
        'شبعا'            => 'شبعا',
        'يارون'           => 'يارون',
        'عيناثا'          => 'عيناثا',
        'ميس الجبل'       => 'ميس الجبل',
        'كفركلا'          => 'كفركلا',
        'مجدل سلم'        => 'مجدل سلم',
        'تبنين'           => 'تبنين',
        'علما الشعب'      => 'علما الشعب',
        'الناقورة'        => 'الناقورة',
        'معركة'           => 'معركة',
        'قانا'            => 'قانا',
        'حولا'            => 'حولا',
        'طيرحرفا'         => 'طيرحرفا',
        'الخيام'          => 'الخيام',
        'الطيبة'          => 'الطيبة',
        'شمع'             => 'شمع',
        'حلوسية'          => 'حلوسية',
        'جبيل'            => 'جبيل',
        'الشوف'           => 'الشوف',
        'عاليه'           => 'عاليه',
        'الكيلة'          => 'الكيلة',
        'المطلة'          => 'المطلة',
        'رميش'            => 'رميش',
        'اللبونة'         => 'اللبونة',
        'دير سريان'       => 'دير سريان',
        'حانوت'           => 'حانوت',
        'طلوسة'           => 'طلوسة',
        'الريحانية'       => 'الريحانية',
        'مشغرة'           => 'البقاع (مشغرة)',
        'الهبارية'        => 'الهبارية',
        'كوكبا'           => 'كوكبا',
        'ارسال'           => 'عرسال',
        'عرسال'           => 'عرسال',
        'ترمانين'         => 'ترمانين',
        'الرياق'          => 'البقاع (الرياق)',
    ];
    foreach ($subregions as $pattern => $label) {
        if (mb_stripos($lower, $pattern) !== false) return $label;
    }
    return '';
}

/**
 * بناء حقل الهدف الذكي من العنوان والبيانات المستخرجة
 * يدعم: اكتشاف المدنيين، الموقع التفصيلي، والهدف العسكري
 */
function so_build_smart_target(string $title, string $region, array $entity_targets, string $where_target): string {
    $lower = mb_strtolower($title, 'UTF-8');

    // 1. اكتشاف المدنيين كهدف رئيسي
    $is_civilian_target = preg_match('/(?:ارتقى|ارتقوا|استشهد|شهيد|شهداء|شهيدًا|شهيدة|ضحايا|ضحية|جرحى|جريح|مدني|مدنيون|مدنيين|أبناء|أهالي|عائلة|لقوا حتفهم|لقي حتفه)/ui', $title);
    $is_residential    = preg_match('/(?:منزل|مبنى سكني|حي سكني|تجمع|خيمة|مخيم|سوق شعبي|سيارة مدنية)/ui', $title);

    // 2. استخراج الموقع التفصيلي
    $specific_loc = so_extract_specific_location($title);

    // 3. بناء الهدف
    if ($is_civilian_target) {
        // حدد نوع الضحايا
        if (preg_match('/(?:طاقم|عنصر|مقاتل|مسلح|قائد|مسؤول)/ui', $title)) {
            $base_target = 'عناصر مسلحة';
        } else {
            $base_target = 'مدنيون';
        }
        if ($specific_loc) return $base_target . ' / ' . $specific_loc;
        if ($region && $region !== 'غير محدد') return $base_target . ' / ' . $region;
        return $base_target;
    }

    // 4. إذا وُجد هدف عسكري محدد + موقع تفصيلي
    if (!empty($entity_targets)) {
        $main_target = implode(', ', array_unique($entity_targets));
        if ($specific_loc) return $main_target . ' / ' . $specific_loc;
        return $main_target;
    }

    // 5. الهدف من 5W1H + موقع تفصيلي
    if ($specific_loc) {
        if ($region && $region !== 'غير محدد' && $region !== $specific_loc) {
            return $region . ' / ' . $specific_loc;
        }
        return $specific_loc;
    }

    // 6. الإسقاط الاحتياطي
    if ($where_target && $where_target !== 'غير محدد') return $where_target;
    if ($region && $region !== 'غير محدد') return $region;
    return 'غير محدد';
}

function so_get_regions_hierarchy_html($selected = '') {
    $hierarchy = [
        'ساحة غرب آسيا' => ['لبنان','الأراضي المحتلة (إسرائيل)','إيران','سوريا','العراق','اليمن','السعودية','الإمارات'],
        'ساحة المحيط الهادئ' => ['الولايات المتحدة','الصين','اليابان','كوريا الجنوبية','تايوان','أستراليا'],
        'ساحة الجبهة الشرقية للناتو' => ['روسيا','أوكرانيا','بولندا','رومانيا','ليتوانيا','لاتفيا','إستونيا'],
    ];
    $html = '';
    foreach ($hierarchy as $parent => $children) {
        $p_val = 'PARENT:' . $parent;
        $html .= "<option value='" . esc_attr($p_val) . "' style='font-weight:bold;color:#6fbf73;' " . selected($selected, $p_val, false) . ">🌍 " . esc_html($parent) . " (الكل)</option>";
        foreach ($children as $child) $html .= "<option value='" . esc_attr($child) . "' " . selected($selected, $child, false) . ">&nbsp;&nbsp;-- " . esc_html($child) . "</option>";
    }
    return $html;
}

// ==========================================================================
// 3. نظام الكاش — Cache System
// ==========================================================================
if (!class_exists('SO_Cache_Manager')) {
class SO_Cache_Manager {
    private static $instance = null;
    public static function get_instance() { if (self::$instance === null) self::$instance = new self(); return self::$instance; }
    public function get($key, $group = 'raw_data') {
        $found = false; $cache = wp_cache_get($key, $group, false, $found);
        if ($found) return $cache;
        return get_transient('so_cache_' . $group . '_' . md5($key));
    }
    public function set($key, $data, $group = 'raw_data', $expire = 60) {
        wp_cache_set($key, $data, $group, $expire);
        set_transient('so_cache_' . $group . '_' . md5($key), $data, $expire);
    }
    public function invalidate($group = null) {
        global $wpdb;
        $pattern = $group ? "_transient_so_cache_{$group}_%" : "_transient_so_cache_%";
        $wpdb->query($wpdb->prepare("DELETE FROM {$wpdb->options} WHERE option_name LIKE %s", $pattern));
    }

    public static function send_word_ajax_v2() {
        if (!current_user_can('manage_options') || !check_ajax_referer('so_exec_report_ajax', 'nonce', false)) {
            wp_send_json_error(['message' => 'غير مصرح'], 403, JSON_UNESCAPED_UNICODE | (defined('JSON_INVALID_UTF8_SUBSTITUTE') ? JSON_INVALID_UTF8_SUBSTITUTE : 0));
        }
        try {
            $report = self::build_report();
            $token = trim(get_option('so_tg_token', ''));
            $exec_chat = trim(get_option('so_exec_reports_chat_id', ''));
            $chats_str = $exec_chat !== '' ? $exec_chat : get_option('so_tg_chat', '');
            $chats = array_filter(array_map('trim', explode(',', $chats_str)));
            if (empty($token) || empty($chats)) {
                wp_send_json_error(['message' => 'بيانات تيليغرام غير مكتملة'], 400, JSON_UNESCAPED_UNICODE | (defined('JSON_INVALID_UTF8_SUBSTITUTE') ? JSON_INVALID_UTF8_SUBSTITUTE : 0));
            }
            $file = self::create_word_report_file($report);
            if (!$file || !file_exists($file)) {
                wp_send_json_error(['message' => 'تعذر إنشاء ملف Word'], 500, JSON_UNESCAPED_UNICODE | (defined('JSON_INVALID_UTF8_SUBSTITUTE') ? JSON_INVALID_UTF8_SUBSTITUTE : 0));
            }
            $name = 'beiruttime-executive-brief-' . gmdate('Ymd-His') . '.doc';
            $ok = true;
            $last_error = '';
            foreach ($chats as $chat_id) {
                $sent = self::telegram_send_local_document($token, $chat_id, $file, 'application/msword', $name, 'Beiruttime OSINT Executive Brief');
                if (empty($sent['ok'])) {
                    $ok = false;
                    $last_error = (string)($sent['message'] ?? 'فشل إرسال ملف Word');
                }
            }
            @unlink($file);
            if ($ok) {
                update_option('so_exec_last_report_time', time(), false);
                wp_send_json_success(['message' => 'تم إرسال ملف Word بنجاح'], 200, JSON_UNESCAPED_UNICODE | (defined('JSON_INVALID_UTF8_SUBSTITUTE') ? JSON_INVALID_UTF8_SUBSTITUTE : 0));
            }
            wp_send_json_error(['message' => $last_error !== '' ? $last_error : 'فشل إرسال ملف Word'], 500, JSON_UNESCAPED_UNICODE | (defined('JSON_INVALID_UTF8_SUBSTITUTE') ? JSON_INVALID_UTF8_SUBSTITUTE : 0));
        } catch (\Throwable $e) {
            wp_send_json_error(['message' => 'فشل إرسال ملف Word: ' . $e->getMessage()], 500, JSON_UNESCAPED_UNICODE | (defined('JSON_INVALID_UTF8_SUBSTITUTE') ? JSON_INVALID_UTF8_SUBSTITUTE : 0));
        }
    }

    public static function send_pdf_ajax_v2() {
        if (!current_user_can('manage_options') || !check_ajax_referer('so_exec_report_ajax', 'nonce', false)) {
            wp_send_json_error(['message' => 'غير مصرح'], 403, JSON_UNESCAPED_UNICODE | (defined('JSON_INVALID_UTF8_SUBSTITUTE') ? JSON_INVALID_UTF8_SUBSTITUTE : 0));
        }
        try {
            $token = trim(get_option('so_tg_token', ''));
            $exec_chat = trim(get_option('so_exec_reports_chat_id', ''));
            $chats_str = $exec_chat !== '' ? $exec_chat : get_option('so_tg_chat', '');
            $chats = array_filter(array_map('trim', explode(',', $chats_str)));
            if (empty($token) || empty($chats)) {
                wp_send_json_error(['message' => 'بيانات تيليغرام غير مكتملة'], 400, JSON_UNESCAPED_UNICODE | (defined('JSON_INVALID_UTF8_SUBSTITUTE') ? JSON_INVALID_UTF8_SUBSTITUTE : 0));
            }
            $payload = (string)($_POST['pdf_base64'] ?? '');
            $file = self::create_pdf_report_file_from_base64($payload);
            if (!$file || !file_exists($file)) {
                wp_send_json_error(['message' => 'تعذر إنشاء ملف PDF. تأكد من اكتمال توليد الملف في المتصفح.'], 500, JSON_UNESCAPED_UNICODE | (defined('JSON_INVALID_UTF8_SUBSTITUTE') ? JSON_INVALID_UTF8_SUBSTITUTE : 0));
            }
            $name = 'beiruttime-executive-brief-' . gmdate('Ymd-His') . '.pdf';
            $ok = true;
            $last_error = '';
            foreach ($chats as $chat_id) {
                $sent = self::telegram_send_local_document($token, $chat_id, $file, 'application/pdf', $name, 'Beiruttime OSINT Executive Brief PDF');
                if (empty($sent['ok'])) {
                    $ok = false;
                    $last_error = (string)($sent['message'] ?? 'فشل إرسال ملف PDF');
                }
            }
            @unlink($file);
            if ($ok) {
                update_option('so_exec_last_report_time', time(), false);
                wp_send_json_success(['message' => 'تم إرسال ملف PDF بنجاح'], 200, JSON_UNESCAPED_UNICODE | (defined('JSON_INVALID_UTF8_SUBSTITUTE') ? JSON_INVALID_UTF8_SUBSTITUTE : 0));
            }
            wp_send_json_error(['message' => $last_error !== '' ? $last_error : 'فشل إرسال ملف PDF'], 500, JSON_UNESCAPED_UNICODE | (defined('JSON_INVALID_UTF8_SUBSTITUTE') ? JSON_INVALID_UTF8_SUBSTITUTE : 0));
        } catch (\Throwable $e) {
            wp_send_json_error(['message' => 'فشل إرسال ملف PDF: ' . $e->getMessage()], 500, JSON_UNESCAPED_UNICODE | (defined('JSON_INVALID_UTF8_SUBSTITUTE') ? JSON_INVALID_UTF8_SUBSTITUTE : 0));
        }
    }
}
}

// ==========================================================================
// 4. إدارة قواعد البيانات — Database Manager (7 Tables)
