function sod_get_bank_registry(): array {
    return [
        'actors'  => ['label' => 'الجهات الفاعلة',           'aliases' => ['actor','actors']],
        'types'   => ['label' => 'التصنيف الاستراتيجي',      'aliases' => ['type','types','intel_type']],
        'levels'  => ['label' => 'المستوى التكتيكي',         'aliases' => ['level','levels','tactical_level']],
        'regions' => ['label' => 'المناطق',                  'aliases' => ['region','regions']],
        'targets' => ['label' => 'الأهداف',                  'aliases' => ['target','targets','target_v2']],
        'contexts'=> ['label' => 'السياق',                   'aliases' => ['context','contexts','context_actor']],
        'intents' => ['label' => 'النية',                    'aliases' => ['intent','intents']],
        'weapons' => ['label' => 'السلاح / الأسلوب',         'aliases' => ['weapon','weapons','weapon_v2']],
    ];
}

function sod_normalize_bank_key(string $key): string {
    $key = trim((string)$key);
    $registry = sod_get_bank_registry();
    foreach ($registry as $canon => $meta) {
        if ($key === $canon || in_array($key, $meta['aliases'], true)) return $canon;
    }
    return $key;
}

