if (!function_exists('so_multi_actor_analysis')) {
function so_multi_actor_analysis($title, $source_name = '', $region = '') {
    $title = so_clean_text((string)$title);
    $source_name = trim((string)$source_name);
    $region = trim((string)$region);
    $t = so_clean_text($title . ' ' . $source_name);

    $out = [
        'primary_actor' => 'فاعل غير محسوم',
        'secondary_actor' => '',
        'target' => '',
        'context_actor' => '',
        'intent' => '',
        'event_type' => '',
        'confidence' => [
            'primary' => 10,
            'secondary' => 0,
            'target' => 0,
            'context' => 0,
            'intent' => 0,
        ],
    ];

    // event type
    if (preg_match('/(غارة|قصف|استهداف|صاروخ|رشقة|صلية|مسيّرة|مسيرة|اقتحام|اعتقال|اعتقالات|اشتباك|هجوم|نسف|إطلاق نار|إنذار|صفارات)/ui', $t)) {
        $out['event_type'] = 'عسكري/أمني';
    } elseif (preg_match('/(وفد|مفاوضات|محادثات|اجتماع|لقاء|زيارة|تصريح|قال|أكد|أعلنت|رحب|ندين|ندعو|حذر|الحكومة|الرئاسة)/ui', $t)) {
        $out['event_type'] = 'سياسي';
    } elseif (preg_match('/(النفط|الغاز|مضيق هرمز|إمدادات|أسعار الطاقة|ناقلات|مطار|الرحلات|اقتصاد|سوق)/ui', $t)) {
        $out['event_type'] = 'اقتصادي/لوجستي';
    } elseif (preg_match('/(تغطية خاصة|مراسل|وسائل إعلام|إعلام العدو|هآرتس|رويترز|القناة|إذاعة|برنامج|تحليل|وول ستريت جورنال|أكسيوس|بوليتيكو)/ui', $t)) {
        $out['event_type'] = 'إعلامي';
    } else {
        $out['event_type'] = 'عام';
    }

    // explicit primary actor
    if (preg_match('/(المقاومة الاسلامية|المقاومة الإسلامية|حزب الله|أمين عام حزب الله|الشيخ نعيم قاسم|استهدفنا|استهدف مجاهدونا|مجاهدونا)/ui', $t)) {
        $out['primary_actor'] = 'المقاومة الإسلامية (حزب الله)';
        $out['confidence']['primary'] = 88;
        $out['intent'] = 'هجوم/رد ميداني';
        $out['confidence']['intent'] = 70;
    } elseif (preg_match('/(كتائب القسام|حماس|سرايا القدس|الجهاد الإسلامي|أبو عبيدة|أبو حمزة)/ui', $t)) {
        $out['primary_actor'] = 'فصائل المقاومة الفلسطينية';
        $out['confidence']['primary'] = 86;
        $out['intent'] = 'هجوم/رد ميداني';
        $out['confidence']['intent'] = 68;
    } elseif (preg_match('/(الحرس الثوري|فيلق القدس|خاتم الأنبياء|خاتم الانبياء|قاآني)/ui', $t)) {
        $out['primary_actor'] = 'الحرس الثوري الإيراني';
        $out['confidence']['primary'] = 84;
    } elseif (preg_match('/(إيران|ايران|طهران|خامنئي|بزشكيان|قاليباف|عراقجي|وكالة فارس)/ui', $t) 
              and preg_match('/(وفد|مفاوضات|محادثات|زيارة|لقاء|اجتماع|استقبال|وصول|وصل)/ui', $t)) {
        $out['primary_actor'] = 'إيران';
        $out['confidence']['primary'] = 80;
        $out['intent'] = 'تفاوض/تموضع سياسي';
        $out['confidence']['intent'] = 72;
    } elseif (preg_match('/(الولايات المتحدة|أمريكا|امريكا|واشنطن|البيت الأبيض|البيت الابيض|ترامب|ترمب|حاملة الطائرات|جورج دبليو بوش|مسؤول أمريكي|مسؤول اميركي)/ui', $t)) {
        $out['primary_actor'] = 'الولايات المتحدة';
        $out['confidence']['primary'] = 78;
    } elseif (preg_match('/(الرئاسة اللبنانية|مجلس الوزراء|الجيش اللبناني|وزارة الصحة اللبنانية|نواف سلام|الرئيس اللبناني|الرئيس بري|رئاسة البرلمان اللبناني|أمن الدولة|الدفاع المدني في جنوب لبنان)/ui', $t)) {
        $out['primary_actor'] = 'لبنان';
        $out['confidence']['primary'] = 76;
    } elseif (preg_match('/(قيادة الجبهة الداخلية|الجبهة الداخلية|تسوفار|اللون الأحمر|انذار احمر|إنذار أحمر|صفارات الإنذار|صافرات الإنذار|لقد انتهى الحدث)/ui', $t)) {
        $out['primary_actor'] = 'الجبهة الداخلية الإسرائيلية';
        $out['confidence']['primary'] = 82;
        $out['intent'] = 'إنذار/استجابة دفاعية';
        $out['confidence']['intent'] = 75;
    } elseif (preg_match('/(جيش العدو الإسرائيلي|جيش العدو الاسرائيلي|الجيش الإسرائيلي|الجيش الاسرائيلي|الاحتلال|عدوان إسرائيلي|عدوان اسرائيلي)/ui', $t) 
              and preg_match('/(غارة|قصف|استهداف|اقتحام|اعتقالات|اعتقال|ضربة|إطلاق نار|استطلاع بطائرة مسيّرة|استطلاع بطائرة مسيرة|طيران حربي|نسف)/ui', $t)) {
        $out['primary_actor'] = 'جيش العدو الإسرائيلي';
        $out['confidence']['primary'] = 85;
        $out['intent'] = 'هجوم/ضغط ميداني';
        $out['confidence']['intent'] = 74;
    }

    // inferred primary actor
    if ($out['primary_actor'] === 'فاعل غير محسوم') {
        // استبعاد الأحداث الدبلوماسية/السياسية والاقتصادية والإعلامية أولاً - لا تُنسب لإسرائيل
        $is_diplomatic = preg_match('/(مفاوضات|محادثات|وفد|اجتماع|لقاء|قمة|مؤتمر|بيان سياسي|تصريح|وزارة الخارجية|الرئيس|رئيس الوزراء|الأمم المتحدة|الاتحاد الأوروبي)/ui', $t);
        $is_economic = preg_match('/(اقتصاد|نفط|غاز|طاقة|أسعار|سوق|تجارة|استثمار|بنك|صندوق|عملة|تضخم|مالية)/ui', $t);
        $is_media_report = preg_match('/(وسائل إعلام|تقرير إعلامي|تحليل|صحيفة|قناة|إذاعة|موقع إخباري|رويترز|غارديان|نيويورك تايمز|وول ستريت جورنال)/ui', $t);
        $is_political_statement = preg_match('/(قال|أكد|صرح|أعلن|أفاد|نقل عن|بحسب|وفق|ذكر|كشف|شجب|استنكر|أدان|رحب|حث|دعا|طالب)/ui', $t);
        
        // لا تُطبَّق القواعد الاستنتاجية على الأحداث غير العسكرية
        if (!$is_diplomatic && !$is_economic && !$is_media_report && !$is_political_statement) {
            // لبنان: غارات/قصف → إسرائيل (فقط مع سياق عسكري صريح وبدون كلمات دبلوماسية)
            if (($region === 'لبنان' || preg_match('/(لبنان|بيروت|الضاحية|الجنوب|النبطية|بنت جبيل|الخيام|شقرا|عدشيت|صور|صيدا|جبل لبنان)/ui', $t))
                && preg_match('/(غارة|غارات|قصف|استهداف|طيران حربي|طيران الاحتلال|طيران معادي|مسيّرة معادية|مسيرة معادية|عدوان|اعتداء إسرائيلي)/ui', $t)
                && !preg_match('/(قال|أكد|صرح|أعلن|أفاد|نقل عن|بحسب|وفق|ذكر|كشف|شجب|استنكر|أدان|رحب|حث|دعا|طالب)/ui', $t)) {
                $out['primary_actor'] = 'جيش العدو الإسرائيلي';
                $out['confidence']['primary'] = 68;
                $out['intent'] = 'هجوم/ضغط ميداني';
                $out['confidence']['intent'] = 60;
            }
            // فلسطين: اقتحامات/قصف → إسرائيل (فقط مع سياق عسكري صريح وبدون كلمات دبلوماسية)
            elseif (($region === 'فلسطين' || preg_match('/(غزة|الضفة الغربية|جنين|نابلس|الخليل|رفح|خان يونس|بيت لاهيا|جباليا|طولكرم)/ui', $t))
                && preg_match('/(اقتحام|اعتقالات|اعتقال|إطلاق نار من دبابات|إطلاق نار بحري|قصف مدفعي|قصف|نسف|جرافات|توغل)/ui', $t)
                && !preg_match('/(قال|أكد|صرح|أعلن|أفاد|نقل عن|بحسب|وفق|ذكر|كشف|شجب|استنكر|أدان|رحب|حث|دعا|طالب)/ui', $t)) {
                $out['primary_actor'] = 'جيش العدو الإسرائيلي';
                $out['confidence']['primary'] = 70;
                $out['intent'] = 'هجوم/ضغط ميداني';
                $out['confidence']['intent'] = 62;
            }
            // الأراضي المحتلة: سقوط صواريخ/مسيرات من لبنان → مقاومة
            elseif (($region === 'الأراضي المحتلة (إسرائيل)' || preg_match('/(كريات شمونة|نهاريا|حيفا|عكا|أفيفيم|المطلة|تل أبيب|تل ابيب|صفد|الجليل|النقب)/ui', $t))
                && preg_match('/(سقوط صاروخ|إطلاق صواريخ|رشقة|رشقات|صلية|وابل صاروخي|من لبنان|تسلل مسيرات لبنانية|هجوم بطائرات مسيّرة)/ui', $t)) {
                $out['primary_actor'] = 'جهة مقاومة من لبنان';
                $out['confidence']['primary'] = 66;
                $out['intent'] = 'هجوم/رد ميداني';
                $out['confidence']['intent'] = 58;
            }
        }
    }

    // secondary actor
    if ($out['primary_actor'] === 'المقاومة الإسلامية (حزب الله)' && preg_match('/(جيش العدو الإسرائيلي|الاحتلال|دبابة|ميركافا|تجمعات لجنود الاحتلال|موقع عسكري|قاعدة|كريات شمونة|نهاريا|أفيفيم)/ui', $t)) {
        $out['secondary_actor'] = 'جيش العدو الإسرائيلي';
        $out['confidence']['secondary'] = 68;
    } elseif ($out['primary_actor'] === 'جيش العدو الإسرائيلي' && preg_match('/(حزب الله|المقاومة الإسلامية|المقاومة الاسلامية|الدفاع المدني|أمن الدولة|سيارة إسعاف|مستشفى|مدنيين|الجيش اللبناني)/ui', $t)) {
        if (preg_match('/(حزب الله|المقاومة الإسلامية|المقاومة الاسلامية)/ui', $t)) {
            $out['secondary_actor'] = 'المقاومة الإسلامية (حزب الله)';
        } elseif (preg_match('/(الجيش اللبناني|أمن الدولة|الدفاع المدني)/ui', $t)) {
            $out['secondary_actor'] = 'لبنان';
        }
        $out['confidence']['secondary'] = 60;
    }

    // target
    if (preg_match('/(سيارة إسعاف|سيارة اسعاف|الدفاع المدني|مستشفى|الهيئة الصحية|مبنى سراي|مبنى|منشآت الطاقة|نقطة للدفاع المدني|موقع مشمار الكرمل|قاعدة بيت هلل|ثكنة برانيت|دبابة|آلية هامر|تجمع لجنود الاحتلال)/ui', $t, $m)) {
        $out['target'] = trim($m[1]);
        $out['confidence']['target'] = 72;
    } elseif (preg_match('/(كريات شمونة|نهاريا|حيفا|عكا|أفيفيم|المطلة|صفد|تل أبيب|تل ابيب|الضاحية الجنوبية|بنت جبيل|النبطية|الخيام|بيت لاهيا|رفح|خان يونس)/ui', $t, $m)) {
        $out['target'] = trim($m[1]);
        $out['confidence']['target'] = 55;
    }

    // context actor
    if (preg_match('/(الأمم المتحدة|غوتيريش|منظمة الصحة العالمية|اليونيسف|الاتحاد الأوروبي|البنك الدولي|فرنسا|وزير خارجية فرنسا|إيطاليا|الهند|الكويت|البحرين|مجلس التعاون الخليجي|السعودية|إسبانيا|روسيا|بريطانيا|المملكة المتحدة)/ui', $t, $m)) {
        $out['context_actor'] = trim($m[1]);
        $out['confidence']['context'] = 65;
    } elseif (preg_match('/(وسائل إعلام إسرائيلية|إعلام العدو|اعلام العدو|هآرتس|القناة 12|القناة 13|القناة 14|القناة 15|رويترز|أكسيوس|بوليتيكو|وول ستريت جورنال)/ui', $t, $m)) {
        $out['context_actor'] = trim($m[1]);
        $out['confidence']['context'] = 58;
    }

    // fallback intent
    if ($out['intent'] === '') {
        if ($out['event_type'] === 'سياسي') {
            $out['intent'] = 'تموضع/رسائل سياسية';
            $out['confidence']['intent'] = 48;
        } elseif ($out['event_type'] === 'إعلامي') {
            $out['intent'] = 'تغطية/رسائل إعلامية';
            $out['confidence']['intent'] = 45;
        } elseif ($out['event_type'] === 'عسكري/أمني') {
            $out['intent'] = 'نشاط ميداني';
            $out['confidence']['intent'] = 40;
        }
    }

    return $out;
}
}


if (!function_exists('so_ma_extract_from_field_data')) {
function so_ma_extract_from_field_data($raw) {
    $data = json_decode((string)$raw, true);
    if (!is_array($data)) return [];
    $ma = $data['multi_actor'] ?? [];
    return is_array($ma) ? $ma : [];
}
}

if (!function_exists('so_ma_short')) {
function so_ma_short($value, $limit = 28) {
    $value = trim(wp_strip_all_tags((string)$value));
    if ($value === '') return '—';
    if (function_exists('mb_strimwidth')) {
        return mb_strimwidth($value, 0, $limit, '…', 'UTF-8');
    }
    return strlen($value) > $limit ? substr($value, 0, $limit - 1) . '…' : $value;
}
}

if (!function_exists('so_ma_admin_render_multi_actor_meta')) {
function so_ma_admin_render_multi_actor_meta($item) {
    if (!is_array($item)) return '—';
    $fd = $item['field_data'] ?? '';
    $ma = so_ma_extract_from_field_data($fd);
    if (empty($ma)) return '—';

    $parts = [];
    if (!empty($ma['primary_actor']))   $parts[] = '<div><strong>رئيسي:</strong> ' . esc_html(so_ma_short($ma['primary_actor'])) . '</div>';
    if (!empty($ma['secondary_actor'])) $parts[] = '<div><strong>ثانوي:</strong> ' . esc_html(so_ma_short($ma['secondary_actor'])) . '</div>';
    if (!empty($ma['target']))          $parts[] = '<div><strong>هدف:</strong> ' . esc_html(so_ma_short($ma['target'])) . '</div>';
    if (!empty($ma['context_actor']))   $parts[] = '<div><strong>سياق:</strong> ' . esc_html(so_ma_short($ma['context_actor'])) . '</div>';
    if (!empty($ma['intent']))          $parts[] = '<div><strong>نية:</strong> ' . esc_html(so_ma_short($ma['intent'])) . '</div>';

    return empty($parts) ? '—' : implode('', $parts);
}
}

if (!function_exists('so_ma_admin_add_columns_css')) {
function so_ma_admin_add_columns_css() {
    if (!is_admin()) return;
    if (!isset($_GET['page'])) return;
    $page = sanitize_text_field((string)$_GET['page']);
    if (strpos($page, 'osint') === false && strpos($page, 'strategic') === false && strpos($page, 'beiruttime') === false) return;

    echo '<style>
    .so-ma-meta{min-width:190px;line-height:1.55}
    .so-ma-meta div{margin:0 0 2px}
    .column-so_ma_primary,.column-so_ma_target,.column-so_ma_context,.column-so_ma_intent{width:10%}
    </style>';
}
add_action('admin_head', 'so_ma_admin_add_columns_css', 50);

// ==========================================================================
// 15c. SO_Auto_Publisher_AI — النشر الآلي
// ==========================================================================
if (!class_exists('SO_Auto_Publisher_AI')) {
class SO_Auto_Publisher_AI {
    public static function should_push_now($item) {
        $source_name = trim((string)($item['source_name']??''));
        $ignored = array_filter(array_map('trim', preg_split('/[\r\n,]+/u', (string)get_option('so_publisher_ignored_sources',''))));
        if ($source_name && in_array($source_name, $ignored, true)) return false;
        $min_score = (int)get_option('so_publisher_min_score', (int)get_option('so_alert_threshold', 140));
        if ((int)($item['score']??0) < $min_score) return false;
        $cooldown = max(0, (int)get_option('so_publisher_min_gap', 120));
        $last_push = (int)get_option('so_publisher_last_push', 0);
        if ($cooldown > 0 && $last_push > 0 && (time() - $last_push) < $cooldown) return false;
        return true;
    }
    public static function mark_push_success() { update_option('so_publisher_last_push', time(), false); }
}
}

// ==========================================================================
// 15d. SO_Prediction_Engine — محرك التنبؤ
// ==========================================================================
if (!class_exists('SO_Prediction_Engine')) {
class SO_Prediction_Engine {
    public static function generate_scenarios($state = []) {
        $title = (string)($state['title'] ?? $state['headline'] ?? '');
        $prediction = sod_prediction_layer($title, [
            'actor' => (string)($state['actor'] ?? $state['actor_v2'] ?? ''),
            'region' => (string)($state['region'] ?? ''),
            'intel_type' => (string)($state['intel_type'] ?? ''),
            'target' => (string)($state['target'] ?? $state['target_v2'] ?? ''),
            'weapon' => (string)($state['weapon'] ?? $state['weapon_v2'] ?? ''),
            'early_warning' => is_array($state['early_warning'] ?? null) ? $state['early_warning'] : [],
        ]);

        $base = max(20, min(80, (int)$prediction['confidence']));
        $risk = (int)($prediction['risk_score'] ?? 0);

        $scenarios = [
            ['name' => 'استمرار النمط الحالي', 'probability' => (float)max(18, min(72, $base)), 'desc' => (string)$prediction['scenario']],
            ['name' => 'تصعيد إقليمي محدود', 'probability' => (float)max(10, min(65, (int)round($risk * 0.7))), 'desc' => 'ترجيح تصاعد قريب إذا تكررت المؤشرات نفسها على الساحة ذاتها.'],
            ['name' => 'احتواء/تبريد', 'probability' => (float)max(8, 100 - max(18, min(72, $base)) - max(10, min(65, (int)round($risk * 0.7))) - 10), 'desc' => 'احتمال التراجع إذا لم تظهر مؤشرات ميدانية أو إنذارية إضافية.'],
            ['name' => 'حدث مفاجئ خارج النمط', 'probability' => 10.0, 'desc' => 'يبقى احتمال التحول المفاجئ قائمًا لكنه غير المدعوم حاليًا بمؤشرات كافية.'],
        ];
        return $scenarios;
    }
}
}

// ==========================================================================
// 15e. خدمة الكرون الخارجي — External Cron Endpoint
// ==========================================================================
add_action('init', 'sod_external_cron_handler');
function sod_external_cron_handler() {
    if (!isset($_GET['sod_cron'])) return;
    $saved_key = trim((string)get_option('so_external_cron_key', ''));
    $provided  = trim((string)($_GET['key']??''));
    if ($saved_key === '' || !hash_equals($saved_key, $provided)) {
        status_header(401); echo json_encode(['success' => false, 'message' => 'Unauthorized']); exit;
    }
    $inserted = SO_Cron_Manager::safe_sync_news();
    $summary  = get_option('so_last_sync_summary', []);
    status_header(200); header('Content-Type: application/json');
    echo json_encode(['success' => true, 'inserted' => $inserted, 'message' => $summary['message'] ?? 'Done']);
    exit;
}

// AJAX: إرسال خبر فردي إلى تيليغرام من لوحة الأدمن
function so_send_news_event_to_telegram(array $event): array {
    $token = trim((string)get_option('so_tg_token', ''));
    $chats = array_values(array_filter(array_map('trim', explode(',', (string)get_option('so_tg_chat', '')))));
    if ($token === '' || empty($chats)) {
        return ['ok' => false, 'message' => 'إعدادات تيليغرام غير مكتملة'];
    }

    $title  = wp_strip_all_tags((string)($event['title'] ?? ''));
    $score  = (int)($event['score'] ?? 0);
    $region = sanitize_text_field((string)($event['region'] ?? 'غير محدد'));
    $intel  = sanitize_text_field((string)($event['intel_type'] ?? 'عام'));
    $actor  = sanitize_text_field((string)($event['actor_v2'] ?? 'فاعل غير محسوم'));
    $target = sanitize_text_field((string)($event['target_v2'] ?? ''));
    $intent = sanitize_text_field((string)($event['intent'] ?? ''));
    $link   = esc_url_raw((string)($event['link'] ?? SO_TELEGRAM_LINK));
    $media_url = trim((string)($event['image_url'] ?? ''));
    $media_kind = '';
    if ($media_url !== '') {
        $media_kind = preg_match('/\.(mp4|mov|webm|m4v)(\?|$)/i', $media_url) ? 'video' : 'photo';
    }

    $lines = [
        '🚨 <b>تنبيه استخباراتي — Beiruttime OSINT</b>',
        '<b>' . esc_html($title) . '</b>',
        '📍 <b>المنطقة:</b> ' . esc_html($region),
        '📌 <b>التصنيف:</b> ' . esc_html($intel),
        '🎯 <b>الفاعل:</b> ' . esc_html($actor),
    ];
    if ($target !== '') $lines[] = '🛡️ <b>الهدف:</b> ' . esc_html($target);
    if ($intent !== '') $lines[] = '🧭 <b>النية:</b> ' . esc_html($intent);
    $lines[] = '⚠️ <b>مؤشر الخطورة:</b> ' . esc_html((string)$score);
    if ($link !== '') $lines[] = '🔗 <a href="' . esc_url($link) . '">المصدر</a>';
    $text = implode("\n", $lines);

    foreach ($chats as $chat_id) {
        $endpoint = 'sendMessage';
        $bodyArgs = [
            'chat_id' => $chat_id,
            'text' => $text,
            'parse_mode' => 'HTML',
            'disable_web_page_preview' => '1',
        ];
        if ($media_kind === 'photo') {
            $endpoint = 'sendPhoto';
            $bodyArgs = [
                'chat_id' => $chat_id,
                'photo' => $media_url,
                'caption' => sod_safe_substr(wp_strip_all_tags($title), 0, 900),
                'parse_mode' => 'HTML',
            ];
        } elseif ($media_kind === 'video') {
            $endpoint = 'sendVideo';
            $bodyArgs = [
                'chat_id' => $chat_id,
                'video' => $media_url,
                'caption' => sod_safe_substr(wp_strip_all_tags($title), 0, 900),
                'parse_mode' => 'HTML',
                'supports_streaming' => '1',
            ];
        }
        $resp = wp_remote_post("https://api.telegram.org/bot{$token}/{$endpoint}", [
            'timeout' => 20,
            'body' => $bodyArgs,
        ]);
        if (is_wp_error($resp)) {
            return ['ok' => false, 'message' => $resp->get_error_message()];
        }
        $code = (int)wp_remote_retrieve_response_code($resp);
        $body = (string)wp_remote_retrieve_body($resp);
        if ($code < 200 || $code >= 300) {
            if ($media_kind !== '') {
                $fallback = wp_remote_post("https://api.telegram.org/bot{$token}/sendMessage", [
                    'timeout' => 20,
                    'body' => [
                        'chat_id' => $chat_id,
                        'text' => $text,
                        'parse_mode' => 'HTML',
                        'disable_web_page_preview' => '0',
                    ],
                ]);
                if (!is_wp_error($fallback) && (int)wp_remote_retrieve_response_code($fallback) >= 200 && (int)wp_remote_retrieve_response_code($fallback) < 300) {
                    continue;
                }
            }
            return ['ok' => false, 'message' => 'HTTP ' . $code . ': ' . sod_fix_mojibake_text($body)];
        }
    }

    return ['ok' => true, 'message' => 'تم الإرسال بنجاح إلى تيليغرام'];
}

function so_send_news_event_to_discord(array $event): array {
    $webhook = trim((string)get_option('so_discord_webhook', ''));
    if ($webhook === '') {
        return ['ok' => false, 'message' => 'Webhook ديسكورد غير مضبوط'];
    }
    $ok = SO_Alert_Dispatcher::send_discord($event);
    if ($ok) {
        return ['ok' => true, 'message' => 'تم الإرسال بنجاح إلى ديسكورد'];
    }
    return ['ok' => false, 'message' => 'فشل الإرسال إلى ديسكورد'];
}

function so_send_news_event_to_telegram_by_id(int $event_id): array {
    if ($event_id <= 0) return ['ok' => false, 'message' => 'معرف الخبر مطلوب'];
    global $wpdb;
    $event = $wpdb->get_row($wpdb->prepare("SELECT * FROM {$wpdb->prefix}so_news_events WHERE id = %d", $event_id), ARRAY_A);
    if (!$event) return ['ok' => false, 'message' => 'الخبر غير موجود'];
    return so_send_news_event_to_telegram($event);
}

function so_send_news_event_to_discord_by_id(int $event_id): array {
    if ($event_id <= 0) return ['ok' => false, 'message' => 'معرف الخبر مطلوب'];
    global $wpdb;
    $event = $wpdb->get_row($wpdb->prepare("SELECT * FROM {$wpdb->prefix}so_news_events WHERE id = %d", $event_id), ARRAY_A);
    if (!$event) return ['ok' => false, 'message' => 'الخبر غير موجود'];
    return so_send_news_event_to_discord($event);
}

function so_send_news_event_to_channels_by_id(int $event_id): array {
    if ($event_id <= 0) return ['ok' => false, 'message' => 'معرف الخبر مطلوب'];
    global $wpdb;
    $event = $wpdb->get_row($wpdb->prepare("SELECT * FROM {$wpdb->prefix}so_news_events WHERE id = %d", $event_id), ARRAY_A);
    if (!$event) return ['ok' => false, 'message' => 'الخبر غير موجود'];

    $telegram = so_send_news_event_to_telegram($event);
    $discord  = so_send_news_event_to_discord($event);

    if (!empty($telegram['ok']) || !empty($discord['ok'])) {
        $parts = [];
        if (!empty($telegram['ok'])) $parts[] = 'تيليغرام';
        if (!empty($discord['ok'])) $parts[] = 'ديسكورد';
        return ['ok' => true, 'message' => 'تم الإرسال بنجاح إلى ' . implode(' + ', $parts)];
    }

    $errors = [];
    if (!empty($telegram['message'])) $errors[] = $telegram['message'];
    if (!empty($discord['message'])) $errors[] = $discord['message'];
    return ['ok' => false, 'message' => implode(' | ', array_filter($errors)) ?: 'فشل الإرسال'];
}

add_action('wp_ajax_so_admin_send_telegram', 'so_ajax_admin_send_telegram');
function so_ajax_admin_send_telegram(): void {
    if (!current_user_can('manage_options') || !check_ajax_referer('so_admin_send_tg', 'nonce', false)) {
        sod_send_json_error(['message' => 'غير مصرح'], 403);
    }
    $result = so_send_news_event_to_channels_by_id((int)($_POST['event_id'] ?? 0));
    if (!empty($result['ok'])) {
        sod_send_json_success(['message' => (string)($result['message'] ?? 'تم الإرسال بنجاح')]);
    }
    if (isset($result['message'])) {
        sod_send_json_error(['message' => (string)$result['message']]);
    }
    if (!current_user_can('manage_options') || !check_ajax_referer('so_admin_send_tg', 'nonce', false)) {
        wp_send_json_error(['message' => 'غير مصرح'], 403);
    }
    $event_id = (int)($_POST['event_id'] ?? 0);
    if (!$event_id) { wp_send_json_error(['message' => 'معرف الخبر مطلوب']); }
    global $wpdb;
    $event = $wpdb->get_row($wpdb->prepare("SELECT * FROM {$wpdb->prefix}so_news_events WHERE id = %d", $event_id), ARRAY_A);
    if (!$event) { wp_send_json_error(['message' => 'الخبر غير موجود']); }
    $token = trim(get_option('so_tg_token', ''));
    $chats = array_filter(array_map('trim', explode(',', get_option('so_tg_chat', ''))));
    if (empty($token) || empty($chats)) { wp_send_json_error(['message' => 'إعدادات تيليغرام غير مكتملة']); }
    $title     = wp_strip_all_tags((string)($event['title']??''));
    $score     = (int)($event['score']??0);
    $region    = sanitize_text_field((string)($event['region']??''));
    $intel     = sanitize_text_field((string)($event['intel_type']??''));
    $actor     = sanitize_text_field((string)($event['actor_v2']??''));
    $link      = esc_url_raw((string)($event['link']??SO_TELEGRAM_LINK));
    $text  = "🚨 <b>تنبيه استخباراتي — Beiruttime OSINT</b>\n";
    $text .= "<b>{$title}</b>\n\n";
    $text .= "📍 <b>المنطقة:</b> {$region}\n";
    $text .= "📌 <b>التصنيف:</b> {$intel}\n";
    $text .= "🎯 <b>الفاعل:</b> {$actor}\n";
    $text .= "⚠️ <b>مؤشر الخطورة:</b> {$score}\n";
    $text .= "🔗 <a href=\"{$link}\">المصدر</a>";
    $ok = true;
    foreach ($chats as $chat_id) {
        $resp = wp_remote_post("https://api.telegram.org/bot{$token}/sendMessage", [
            'timeout' => 15, 'body' => ['chat_id' => $chat_id, 'text' => $text, 'parse_mode' => 'HTML', 'disable_web_page_preview' => '1'],
        ]);
        if (is_wp_error($resp)) $ok = false;
    }
    if ($ok) wp_send_json_success(['message' => 'تم الإرسال بنجاح إلى تيليغرام']);
    else wp_send_json_error(['message' => 'فشل الإرسال إلى تيليغرام']);
}

// ==========================================================================
// 16. مسار خاص لصفحة العرض — Dedicated Display Route
// ==========================================================================
function sod_dashboard_slug(): string {
    $slug = get_option('sod_dashboard_slug', 'osint-dashboard');
    $slug = trim((string) $slug, " /\t\n\r\0\x0B");
    $slug = sanitize_title($slug);
    return $slug !== '' ? $slug : 'osint-dashboard';
}

function sod_dashboard_route_enabled(): bool {
    return (bool) get_option('sod_dashboard_route_enabled', 1);
}

function sod_dashboard_display_mode(): string {
    $mode = sanitize_key((string) get_option('sod_dashboard_display_mode', 'custom'));
    return in_array($mode, ['powerbi', 'all', 'custom'], true) ? $mode : 'custom';
}

function sod_dashboard_display_order(): string {
    $order = sanitize_key((string) get_option('sod_dashboard_display_order', 'powerbi_command'));
    return in_array($order, ['powerbi_command', 'command_powerbi'], true) ? $order : 'powerbi_command';
}

function sod_is_dashboard_route(): bool {
    return sod_dashboard_route_enabled() && (bool) get_query_var('sod_dashboard_route');
}


