            'desc' => 'اللوحة الاحترافية + الخريطة معاً',
        ],
    ];
}

function sod_dashboard_selected_panels(): array {
    $available = sod_available_dashboard_panels();
    $allowed = ['powerbi','ticker','threat_analyzer','command_deck','osint_dashboard','osint_map','osint_command_center'];
    $selected = get_option('sod_dashboard_selected_panels', ['powerbi','ticker','threat_analyzer']);
    if (!is_array($selected)) $selected = ['powerbi','ticker','threat_analyzer'];
    $selected = array_values(array_filter(array_map('sanitize_key', $selected), function($key) use ($available){
        return isset($available[$key]);
    }));
    $selected = array_values(array_filter($selected, function($key) use ($allowed){
        return in_array($key, $allowed, true);
    }));
    if (empty($selected)) $selected = ['powerbi','ticker','threat_analyzer'];
    return $selected;
}

function sod_get_dashboard_route_shortcodes(): array {
    $available = sod_available_dashboard_panels();
    $powerbi = $available['powerbi']['shortcode'];
    $ticker = $available['ticker']['shortcode'];
    $threat = $available['threat_analyzer']['shortcode'];
    $mode = sod_dashboard_display_mode();
    $selected = sod_dashboard_selected_panels();

    if ($mode === 'custom') {
        $parts = [];
        foreach ($selected as $key) {
            if (!empty($available[$key]['shortcode'])) {
                $parts[] = $available[$key]['shortcode'];
            }
        }
        if (!empty($parts)) return $parts;
        return [$powerbi, $ticker, $threat];
    }

    if ($mode === 'powerbi') return [$powerbi];
    return [$powerbi, $ticker, $threat];
}

function sod_render_dashboard_route_content(): string {
    $parts = [];
    $top_ad = trim((string)get_option('sod_dashboard_top_ad_code', ''));
    $bottom_ad = trim((string)get_option('sod_dashboard_bottom_ad_code', ''));
    $ga_code = trim((string)get_option('sod_dashboard_ga_code', ''));
    
    // إضافة كود تتبع جوجل في البداية
    if ($ga_code !== '') {
        $parts[] = '<!-- Google Analytics -->' . $ga_code;
    }
    
    if ($top_ad !== '') {
        $parts[] = '<div class="sod-dashboard-ad sod-dashboard-ad-top">' . $top_ad . '</div>';
    }
    foreach (sod_get_dashboard_route_shortcodes() as $shortcode) {
        $html = do_shortcode($shortcode);
        if (trim((string) $html) !== '') $parts[] = $html;
    }

    if (empty($parts)) {
        return '<div class="sod-dashboard-route-empty" style="padding:24px;border:1px solid rgba(148,163,184,.18);border-radius:16px;background:#0f172a;color:#e2e8f0;text-align:center;">لم يتم اختيار أي لوحة للعرض في إعدادات الإضافة.</div>';
    }

    if ($bottom_ad !== '') {
        $parts[] = '<div class="sod-dashboard-ad sod-dashboard-ad-bottom">' . $bottom_ad . '</div>';
    }

    $footer_bits = [];
    $designer_name = trim((string)get_option('sod_dashboard_designer_name', ''));
    $designer_phone = preg_replace('/\s+/u', '', trim((string)get_option('sod_dashboard_designer_phone', '')));
    $wa_link = trim((string)get_option('sod_dashboard_whatsapp_url', ''));
    if ($wa_link === '' && $designer_phone !== '') {
        $wa_link = 'https://wa.me/' . preg_replace('/[^\d]/', '', str_replace('+', '', $designer_phone));
    }
    if ($designer_name !== '') $footer_bits[] = '<span class="sod-dashboard-credit-name">' . esc_html($designer_name) . '</span>';
    if ($designer_phone !== '') {
        $phone_html = esc_html($designer_phone);
        if ($wa_link !== '') $phone_html = '<a href="' . esc_url($wa_link) . '" target="_blank" rel="noopener">' . $phone_html . '</a>';
        $footer_bits[] = '<span class="sod-dashboard-credit-phone">' . $phone_html . '</span>';
    }

    $socials = [
        'x' => ['label' => 'X', 'url' => get_option('sod_dashboard_x_url', '')],
        'instagram' => ['label' => 'Instagram', 'url' => get_option('sod_dashboard_instagram_url', '')],
        'facebook' => ['label' => 'Facebook', 'url' => get_option('sod_dashboard_facebook_url', '')],
        'pinterest' => ['label' => 'Pinterest', 'url' => get_option('sod_dashboard_pinterest_url', '')],
        'discord' => ['label' => 'Discord', 'url' => get_option('sod_dashboard_discord_url', '')],
    ];
    $social_links = [];
    foreach ($socials as $social) {
        $url = trim((string)$social['url']);
        if ($url === '') continue;
        $social_links[] = '<a href="' . esc_url($url) . '" target="_blank" rel="noopener" class="sod-dashboard-social-link">' . esc_html($social['label']) . '</a>';
    }
    if (!empty($social_links)) {
        $footer_bits[] = '<span class="sod-dashboard-socials">' . implode('', $social_links) . '</span>';
    }
    if (!empty($footer_bits)) {
        $parts[] = '<footer class="sod-dashboard-footer">' . implode('', $footer_bits) . '</footer>';
    }

    return implode("\n<div style=\"height:16px\"></div>\n", $parts);
}

function sod_register_dashboard_rewrite_rule(): void {
    add_rewrite_tag('%sod_dashboard_route%', '1');
    if (sod_dashboard_route_enabled()) {
        add_rewrite_rule('^' . preg_quote(sod_dashboard_slug(), '/') . '/?$', 'index.php?sod_dashboard_route=1', 'top');
    }
}

add_action('init', 'sod_register_dashboard_rewrite_rule');

register_activation_hook(__FILE__, function () {
    sod_register_dashboard_rewrite_rule();
    flush_rewrite_rules();
    // تفعيل تحديثات الحرب المركبة
    if (function_exists('sod_activate_hybrid_warfare_update')) {
        sod_activate_hybrid_warfare_update();
    }
    // إعداد سجلات الأمان
    if (function_exists('osint_setup_security_logging')) {
        osint_setup_security_logging();
    }
});

register_deactivation_hook(__FILE__, function () {
    flush_rewrite_rules();
});

add_filter('query_vars', function ($vars) {
    $vars[] = 'sod_dashboard_route';
    return $vars;
});

// ==========================================================================
// إضافة Content-Security-Policy (CSP) للوحة OSINT
// ==========================================================================
add_action('send_headers', function () {
    // تطبيق CSP فقط على صفحة لوحة OSINT
    if (sod_is_dashboard_route()) {
        header("Content-Security-Policy: default-src 'self' https: data: blob:; script-src 'self' 'unsafe-inline' 'unsafe-eval' https: blob:; style-src 'self' 'unsafe-inline' https: data:; img-src 'self' data: blob: https:; font-src 'self' data: https://fonts.gstatic.com https:; connect-src 'self' https: wss: ws: blob: data: https://api.telegram.org; frame-src 'self' https://widgets.wp.com https:; media-src 'self' blob: data: https:; worker-src 'self' blob:; frame-ancestors 'self'; base-uri 'self'; form-action 'self' https:;");
    }
});

add_action('template_redirect', function () {
    if (!sod_is_dashboard_route()) return;

    status_header(200);
    nocache_headers();

    wp_enqueue_style('dashicons');
    do_action('wp_enqueue_scripts');

    $mode_label_map = [
        'powerbi' => 'PowerBI',
        'command_deck' => 'Command Deck',
        'all' => 'All Dashboards',
        'custom' => 'Custom Dashboards',
    ];
    $mode = sod_dashboard_display_mode();
    $title = apply_filters('sod_dashboard_page_title', 'Beiruttime Display — ' . ($mode_label_map[$mode] ?? 'Dashboard'));
    ?>
    <!DOCTYPE html>
    <html <?php language_attributes(); ?>>
    <head>
        <meta charset="<?php bloginfo('charset'); ?>">
        <meta name="viewport" content="width=device-width, initial-scale=1, viewport-fit=cover">
        <?php wp_head(); ?>
        <style>
            html,body{margin:0;padding:0;background:#08111f;color:#e5eefb;overflow-x:hidden}
            body.sod-dashboard-route-body{min-height:100vh}
            .sod-dashboard-route-shell{min-height:100vh;padding:14px}
            .sod-dashboard-route-shell,.sod-dashboard-route-shell *{box-sizing:border-box}
            .sod-dashboard-route-shell .sod-cd-wrap,.sod-dashboard-route-shell .so-powerbi-wrap,.sod-dashboard-route-shell .so-dashboard-wrap,.sod-dashboard-route-shell .osint-dashboard{width:100%;max-width:100%;margin:0}
            .sod-dashboard-ad{background:#0f172a;border:1px solid rgba(148,163,184,.18);border-radius:16px;padding:10px;overflow:hidden}
            .sod-dashboard-footer{display:flex;justify-content:center;align-items:center;gap:14px;flex-wrap:wrap;background:#0f172a;border:1px solid rgba(148,163,184,.18);border-radius:16px;padding:14px;color:#e2e8f0}
            .sod-dashboard-footer a{color:#60a5fa;text-decoration:none}
            .sod-dashboard-socials{display:flex;gap:8px;flex-wrap:wrap}
            .sod-dashboard-social-link{display:inline-flex;align-items:center;justify-content:center;padding:6px 10px;border-radius:999px;background:#0b1220;border:1px solid rgba(96,165,250,.24);font-size:12px}
            @media (max-width:768px){.sod-dashboard-route-shell{padding:8px}}
            @media (max-width:768px){.sod-dashboard-footer{flex-direction:column;text-align:center}}
        </style>
    </head>
    <body <?php body_class('sod-dashboard-route-body'); ?>>
        <?php wp_body_open(); ?>
        <main class="sod-dashboard-route-shell">
            <?php echo sod_render_dashboard_route_content(); ?>
        </main>
        <?php wp_footer(); ?>
    </body>
    </html>
    <?php
    exit;
});

// ==========================================================================
// 16. تحميل الأصول — Asset Enqueue
// ==========================================================================
add_action('wp_enqueue_scripts', 'sod_enqueue_assets');
function sod_enqueue_assets(): void {
    if (!sod_should_enqueue_public_assets()) return;
    // Google Fonts - load custom font from admin settings
    $custom_font = get_option('so_custom_font', 'Noto Naskh Arabic');
    $font_slug = urlencode(str_replace(' ', '+', $custom_font));
    wp_enqueue_style('sod-custom-font', "https://fonts.googleapis.com/css2?family={$font_slug}:wght@400;500;600;700&display=swap", [], null);
    // ── Leaflet — unique handles to avoid conflicts with other plugins ──────
    wp_enqueue_style('sod-leaflet-css','https://unpkg.com/leaflet@1.9.4/dist/leaflet.css',[],'sod1.9.4');
    wp_enqueue_script('sod-leaflet','https://unpkg.com/leaflet@1.9.4/dist/leaflet.js',[],'sod1.9.4',false);
    wp_enqueue_script('sod-leaflet-heat','https://unpkg.com/leaflet.heat@0.2.0/dist/leaflet-heat.js',['sod-leaflet'],'sod0.2.0',false);
    wp_enqueue_script('sod-topojson-client','https://unpkg.com/topojson-client@3/dist/topojson-client.min.js',[],'3.1.0',false);
    // ── Chart.js v4 — unique handle 'sod-chartjs-v4' to avoid conflicts ─────
    wp_enqueue_style('sod-cairo-font','https://fonts.googleapis.com/css2?family=Cairo:wght@300;400;600;700;900&family=Tajawal:wght@300;400;700&display=swap',[],null);
    wp_enqueue_script('sod-chartjs-v4','https://cdn.jsdelivr.net/npm/chart.js@4.4.3/dist/chart.umd.min.js',[],'sod4.4.3',false);
    // ── HLS.js for live streams ──────────────────────────────────────────────
    wp_enqueue_script('sod-hls-js','https://cdn.jsdelivr.net/npm/hls.js@1.5.15/dist/hls.min.js',[],'sod1.5.15',true);
    // ── Config object — localized to sod-chartjs-v4 so it's available early ─
    wp_localize_script('sod-chartjs-v4','SOD_CONFIG',['ajaxUrl'=>admin_url('admin-ajax.php'),'nonce'=>wp_create_nonce(SOD_AJAX_NONCE_ACTION),'tgLink'=>SOD_TG_LINK,'version'=>SOD_VERSION]);
    // Inject custom CSS variables from admin appearance settings
    $primary_color  = get_option('so_custom_primary_color', '#dc2626');
    $bg_color       = get_option('so_custom_bg_color', '#0f172a');
    $tc_heading     = get_option('so_text_color_heading', '#e0f2ff');
    $tc_body        = get_option('so_text_color_body',    '#94a3b8');
    $tc_accent      = get_option('so_text_color_accent',  '#60a5fa');
    $tc_muted       = get_option('so_text_color_muted',   '#64748b');
    $tc_score       = get_option('so_text_color_score',   '#ef4444');
    $custom_css  = ":root{--sod-red:{$primary_color};--sod-bg:{$bg_color};--sod-font:'{$custom_font}',serif;";
    $custom_css .= "--sod-tc-heading:{$tc_heading};--sod-tc-body:{$tc_body};--sod-tc-accent:{$tc_accent};--sod-tc-muted:{$tc_muted};--sod-tc-score:{$tc_score};}";
    $custom_css .= ".sod-powerbi-wrap,.sod-ticker-wrap,.sod-threat-wrap{font-family:'{$custom_font}',sans-serif !important;background:{$bg_color} !important;}";
    $custom_css .= ".sod-powerbi-wrap .sod-card-header,.sod-powerbi-wrap .sod-nav-btn,.sod-powerbi-wrap .sod-topbar-title{color:{$tc_heading} !important;}";
    $custom_css .= ".sod-powerbi-wrap .sod-news-card p,.sod-powerbi-wrap .sod-actor-name,.sod-powerbi-wrap .sod-region-name,.sod-powerbi-wrap .sod-setting-label{color:{$tc_body} !important;}";
    $custom_css .= ".sod-powerbi-wrap a,.sod-powerbi-wrap .sod-nav-btn.active,.sod-powerbi-wrap .sod-badge-gray{color:{$tc_accent} !important;}";
    $custom_css .= ".sod-powerbi-wrap .sod-kpi-label,.sod-powerbi-wrap .sod-ticker-bar-label,.sod-powerbi-wrap .sod-page-subtitle{color:{$tc_muted} !important;}";
    $custom_css .= ".sod-powerbi-wrap .sod-kpi-val,.sod-powerbi-wrap .sod-badge-red,.sod-powerbi-wrap .sod-actor-score{color:{$tc_score} !important;}";
    $custom_css .= ".sod-sidebar-nav,.sod-kpi-card,.so-alert-strip,.sod-news-card,.sod-tab-btn.active{border-color:{$primary_color} !important;}";
    $custom_css .= ".sod-tab-btn.active,.sod-badge-red,.sod-live-dot{background:{$primary_color} !important;}";
    wp_add_inline_style('sod-leaflet-css', $custom_css);
}

// ==========================================================================
// 17. الأنماط المشتركة — Shared Styles
// ==========================================================================
function sod_get_shared_styles(): string {
    ob_start(); ?>
    <style>
    /* =====================================================================
       BeirutTime OSINT Pro V15 — واجهة مطابقة للوحة React
    ===================================================================== */
    *{box-sizing:border-box;}
    .sod-powerbi-wrap,.sod-ticker-wrap,.sod-threat-wrap{
        font-family:'Noto Naskh Arabic','Cairo','Tajawal',sans-serif;
        direction:rtl;
    }
    /* Shell / container */
    .sod-shell{
        background:#0f172a;
        color:#e2e8f0;
        min-height:600px;
        border-radius:12px;
        overflow:hidden;
        display:flex;
        flex-direction:column;
        border:1px solid #1e293b;
        margin-bottom:24px;
    }
    /* Ticker bar — خبر واحد يصعد للأعلى */
    .sod-ticker-bar{
        background:#dc2626;
        color:#fff;
        font-size:13px;
        font-weight:700;
        display:flex;
        align-items:center;
        gap:10px;
        padding:0 16px;
        overflow:hidden;
        flex-shrink:0;
        height:42px;
    }
    .sod-ticker-bar-label{white-space:nowrap!important;flex-shrink:0!important;font-size:12px;}
    .sod-ticker-scroll-wrap{flex:1!important;overflow:hidden!important;position:relative!important;height:36px!important;}
    .sod-ticker-scroll{position:relative!important;height:36px!important;overflow:hidden!important;}
    /* عنصر خبر واحد */
    .sod-tick-item{
        position:absolute!important;width:100%!important;height:36px!important;
        display:flex!important;align-items:center!important;
        white-space:nowrap!important;overflow:hidden!important;text-overflow:ellipsis!important;
        font-size:12px!important;transition:transform .55s cubic-bezier(.4,0,.2,1),opacity .45s ease!important;
        padding:0 4px!important;
    }
    .sod-tick-item.sod-entering{transform:translateY(110%)!important;opacity:0!important;}
    .sod-tick-item.sod-active  {transform:translateY(0)!important;  opacity:1!important;}
    .sod-tick-item.sod-leaving {transform:translateY(-110%)!important;opacity:0!important;}
    /* Top bar */
    .sod-topbar{
        background:#1e293b;
        border-bottom:1px solid #334155;
        padding:10px 20px;
        display:flex;
        align-items:center;
        justify-content:space-between;
        flex-wrap:wrap;
        gap:10px;
        flex-shrink:0;
    }
    .sod-logo{display:flex;align-items:center;gap:10px;}
    .sod-logo-icon{font-size:22px;}
    .sod-logo-title{font-size:15px;font-weight:700;color:#f8fafc;}
    .sod-logo-sub{font-size:10px;color:#64748b;}
    .sod-live-badge{
        display:flex;align-items:center;gap:5px;
        background:#0f3a1a;border:1px solid #16a34a;border-radius:20px;
        padding:3px 10px;font-size:11px;font-weight:700;color:#4ade80;
    }
    .sod-live-dot{width:7px;height:7px;background:#22c55e;border-radius:50%;animation:sod-blink 1.4s infinite;flex-shrink:0;}
    .sod-topbar-controls{display:flex;align-items:center;gap:8px;flex-wrap:wrap;}
    .sod-select,.sod-input-sm{
        background:#0f172a;border:1px solid #334155;color:#cbd5e1;
        padding:4px 8px;border-radius:6px;font-size:11px;font-family:inherit;
    }
    .sod-btn{
        background:#1e293b;border:1px solid #334155;color:#cbd5e1;
        padding:5px 12px;border-radius:6px;cursor:pointer;font-size:11px;
        font-family:inherit;font-weight:600;transition:.15s;
    }
    .sod-btn:hover{background:#334155;color:#f8fafc;}
    .sod-btn-danger{background:#991b1b;border-color:#dc2626;color:#fecaca;}
    .sod-btn-danger:hover{background:#b91c1c;}
    .sod-time-label{font-size:11px;color:#475569;white-space:nowrap;}
    /* Body: sidebar + content */
    .sod-body{display:flex;flex:1;min-height:0;overflow:hidden;}
    /* Sidebar */
    .sod-sidebar{
        width:200px;flex-shrink:0;
        background:#1e293b;
        border-left:1px solid #334155;
        display:flex;flex-direction:column;
        overflow-y:auto;
    }
    .sod-sidebar-nav{list-style:none;margin:0;padding:8px 0;}
    .sod-sidebar-nav li{margin:0;}
    .sod-nav-btn{
        display:flex;align-items:center;gap:10px;
        width:100%;padding:10px 16px;
        background:none;border:none;cursor:pointer;
        font-family:inherit;font-size:12px;font-weight:600;
        color:#94a3b8;text-align:right;
        border-radius:0;transition:.15s;
    }
    .sod-nav-btn:hover{background:rgba(255,255,255,.05);color:#e2e8f0;}
    .sod-nav-btn.active{
        background:rgba(220,38,38,.15);
        color:#f87171;
        border-right:3px solid #dc2626;
    }
    .sod-nav-icon{font-size:16px;flex-shrink:0;}
    /* Popup overlay */
    .sod-popup-overlay{
        position:fixed;inset:0;background:rgba(0,0,0,.7);
        z-index:9999;display:flex;align-items:center;justify-content:center;
    }
    .sod-popup-overlay.hidden{display:none;}
    .sod-popup-box{
        background:#1e293b;border:1px solid #dc2626;border-radius:12px;
        padding:0;width:min(420px,90vw);overflow:hidden;
        box-shadow:0 20px 60px rgba(0,0,0,.6);
    }
    .sod-popup-header{
        background:#dc2626;padding:12px 16px;
        display:flex;align-items:center;justify-content:space-between;
    }
    .sod-popup-title{color:#fff;font-weight:700;font-size:14px;display:flex;align-items:center;gap:6px;}
    .sod-popup-close{
        background:none;border:none;color:#fecaca;font-size:20px;
        cursor:pointer;line-height:1;padding:0;
    }
    .sod-popup-body{padding:20px;}
    .sod-popup-event-title{font-size:15px;font-weight:700;color:#f8fafc;margin-bottom:8px;text-align:center;}
    .sod-popup-event-desc{font-size:12px;color:#94a3b8;line-height:1.7;margin-bottom:16px;text-align:center;}
    .sod-popup-actions{display:flex;gap:8px;justify-content:center;}
    .sod-popup-btn-primary{
        background:#dc2626;border:none;color:#fff;
        padding:8px 20px;border-radius:8px;cursor:pointer;
        font-family:inherit;font-weight:700;font-size:13px;
    }
    .sod-popup-btn-secondary{
        background:#334155;border:none;color:#cbd5e1;
        padding:8px 20px;border-radius:8px;cursor:pointer;
        font-family:inherit;font-weight:600;font-size:13px;
    }
    /* Page content */
    .sod-page{display:none;flex:1;overflow-y:auto;padding:16px;flex-direction:column;gap:14px;}
    .sod-page.active{display:flex;}
    /* Cards */
    .sod-card{
        background:#1e293b;border:1px solid #334155;
        border-radius:10px;overflow:hidden;
    }
    .sod-card-header{
        padding:10px 14px;font-size:13px;font-weight:700;
        color:#f8fafc;background:rgba(0,0,0,.2);
        border-bottom:1px solid #334155;
        display:flex;justify-content:center;align-items:center;
        text-align:center;position:relative;
    }
    .sod-card-header > span:first-child,
    .sod-card-header > div:first-child{
        margin:0 auto;
    }
    .sod-card-header .sod-feed-controls,
    .sod-card-header .sod-map-controls{
        position:absolute;
        inset-inline-start:12px;
        top:50%;
        transform:translateY(-50%);
    }
    .sod-card-header-red{background:rgba(220,38,38,.15);border-bottom-color:rgba(220,38,38,.3);}
    .sod-card-body{padding:14px;}
    /* KPI Grid */
    .sod-kpi-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(160px,1fr));gap:10px;}
    .sod-kpi-card{
        background:#0f172a;border:1px solid #334155;border-radius:8px;
        padding:12px 14px;display:flex;align-items:center;justify-content:center;gap:10px;
        transition:.2s;text-align:center;min-height:84px;
    }
    .sod-kpi-card:hover{border-color:#475569;transform:translateY(-1px);}
    .sod-kpi-icon{font-size:22px;flex-shrink:0;}
    .sod-kpi-label{font-size:11px;color:#cbd5e1;font-weight:700;margin-bottom:4px;}
    .sod-kpi-value{font-size:24px;font-weight:800;color:#f8fafc;line-height:1.1;}
    .sod-kpi-desc{font-size:11px;color:#94a3b8;margin-top:4px;}
    .kpi-danger .sod-kpi-value{color:#f87171;}
    .kpi-warn .sod-kpi-value{color:#fbbf24;}
    .kpi-hot .sod-kpi-value{color:#f97316;font-size:14px;}
    .kpi-info .sod-kpi-value{color:#60a5fa;}
    .kpi-esc .sod-kpi-value{color:#c084fc;}
    /* News cards */
    .sod-news-grid{display:flex;flex-direction:column;gap:10px;}
    .sod-news-card{
        background:#0f172a;border:1px solid #1e293b;border-radius:8px;
        padding:12px 14px;display:flex;flex-direction:column;gap:6px;
        transition:.2s;
    }
