    .sod-news-card-meta{display:flex;align-items:center;gap:8px;flex-wrap:wrap;}
    .sod-badge{
        display:inline-flex;align-items:center;padding:2px 7px;
        border-radius:10px;font-size:10px;font-weight:700;
    }
    .sod-badge-red{background:rgba(220,38,38,.2);color:#f87171;border:1px solid rgba(220,38,38,.3);}
    .sod-badge-orange{background:rgba(249,115,22,.2);color:#fb923c;border:1px solid rgba(249,115,22,.3);}
    .sod-badge-yellow{background:rgba(234,179,8,.2);color:#fbbf24;border:1px solid rgba(234,179,8,.3);}
    .sod-badge-green{background:rgba(34,197,94,.2);color:#4ade80;border:1px solid rgba(34,197,94,.3);}
    .sod-badge-blue{background:rgba(59,130,246,.2);color:#60a5fa;border:1px solid rgba(59,130,246,.3);}
    .sod-badge-purple{background:rgba(139,92,246,.2);color:#c084fc;border:1px solid rgba(139,92,246,.3);}
    .sod-badge-gray{background:rgba(100,116,139,.15);color:#94a3b8;border:1px solid rgba(100,116,139,.3);}
    .sod-news-title{font-size:13px;font-weight:600;color:#e2e8f0;line-height:1.5;}
    .sod-news-title a{color:#e2e8f0;text-decoration:none;}
    .sod-news-title a:hover{color:#60a5fa;}
    .sod-news-footer{display:flex;align-items:center;gap:8px;font-size:11px;color:#475569;}
    .sod-confidence-bar-wrap{display:flex;align-items:center;gap:6px;margin-top:4px;}
    .sod-confidence-label{font-size:10px;color:#64748b;white-space:nowrap;}
    .sod-confidence-bar{flex:1;height:3px;background:#1e293b;border-radius:2px;overflow:hidden;}
    .sod-confidence-fill{height:100%;border-radius:2px;background:#3b82f6;transition:width .4s;}
    /* Map */
    .sod-map-container{height:420px;border-radius:8px;overflow:hidden;}
    .sod-map-controls{display:flex;gap:6px;}
    .sod-map-btn{
        background:#0f172a;border:1px solid #334155;color:#94a3b8;
        padding:4px 10px;border-radius:6px;cursor:pointer;font-size:11px;
        font-family:inherit;transition:.15s;
    }
    .sod-map-btn.active{background:#dc2626;color:#fff;border-color:#dc2626;}
    /* Charts */
    .sod-charts-grid{display:grid;grid-template-columns:1fr 1fr;gap:12px;}
    .sod-chart-wrap{height:200px;padding:8px;position:relative;}
    .sod-chart-wrap canvas{cursor:pointer;transition:opacity .15s;}
    .sod-chart-wrap canvas:hover{opacity:.85;}
    /* ── Chart Modal ── */
    #sod-chart-modal{position:fixed;inset:0;z-index:999999;background:rgba(0,0,0,.8);display:flex;align-items:center;justify-content:center;animation:sod-modal-in .2s ease;}
    @keyframes sod-modal-in{from{opacity:0;transform:scale(.95)}to{opacity:1;transform:scale(1)}}
    .sod-cm-box{background:#0d1b2a;border:1px solid #1e3a5f;border-radius:12px;width:92vw;max-width:1280px;max-height:90vh;display:flex;flex-direction:column;overflow:hidden;box-shadow:0 24px 60px rgba(0,0,0,.8);}
    .sod-cm-hdr{display:flex;align-items:center;gap:10px;padding:12px 16px;border-bottom:1px solid #1e3a5f;background:#0a1522;flex-shrink:0;}
    .sod-cm-title{font-size:15px;font-weight:700;color:#e0f2ff;flex:1;}
    .sod-cm-btn{padding:6px 14px;border-radius:6px;border:none;cursor:pointer;font-size:12px;font-weight:700;}
    .sod-cm-btn-print{background:#1d4ed8;color:#fff;}
    .sod-cm-btn-print:hover{background:#2563eb;}
    .sod-cm-btn-close{background:#1e293b;color:#94a3b8;}
    .sod-cm-btn-close:hover{background:#dc2626;color:#fff;}
    .sod-cm-chart{height:240px;padding:12px;flex-shrink:0;position:relative;}
    .sod-cm-filters{display:flex;gap:8px;flex-wrap:wrap;padding:8px 14px;border-bottom:1px solid #1e3a5f;flex-shrink:0;background:#060e18;}
    .sod-cm-filter{background:#0f1e2e;border:1px solid #1e3a5f;color:#94a3b8;border-radius:6px;padding:4px 8px;font-size:11px;flex:1;min-width:100px;}
    .sod-cm-filter::placeholder{color:#475569;}
    .sod-cm-events{flex:1;overflow-y:auto;padding:0;}
    table.sod-cm-tbl{width:100%;border-collapse:collapse;font-size:11px;}
    table.sod-cm-tbl th{position:sticky;top:0;background:#0a1522;color:#60a5fa;padding:7px 10px;text-align:right;border-bottom:1px solid #1e3a5f;font-weight:600;}
    table.sod-cm-tbl td{padding:6px 10px;border-bottom:1px solid rgba(30,58,95,.4);color:#94a3b8;vertical-align:top;}
