    .sod-stat-value{font-size:20px;font-weight:700;color:#f8fafc;}
    /* Settings page */
    .sod-settings-grid{display:grid;grid-template-columns:1fr 1fr;gap:12px;}
    .sod-setting-item{background:#0f172a;border:1px solid #1e293b;border-radius:8px;padding:12px 14px;}
    .sod-setting-label{font-size:11px;color:#64748b;font-weight:600;margin-bottom:4px;}
    .sod-setting-value{font-size:13px;color:#e2e8f0;}
    /* Alerts page */
    .sod-alert-card{
