    .sod-video-live-grid{grid-template-columns:repeat(auto-fit,minmax(280px,1fr));}
    .sod-video-embed-grid{grid-template-columns:repeat(4,minmax(0,1fr));align-items:start;}
    .sod-video-section-title{grid-column:1/-1;font-size:13px;font-weight:700;margin-bottom:4px;display:flex;align-items:center;gap:8px;justify-content:center;text-align:center;}
    .sod-video-section-live{color:#dc2626;}
    .sod-video-section-embed{color:#60a5fa;margin-top:6px;}
    .sod-video-embed-card{background:#0a1929;border:1px solid #334155;border-radius:10px;overflow:hidden;display:flex;flex-direction:column;min-width:0;}
    .sod-video-embed-frame{width:100%;height:100%;min-height:420px;background:#fff;overflow:hidden;}
    .sod-video-embed-frame iframe{width:100% !important;height:100% !important;min-height:420px !important;border:0;display:block;}
    .sod-tg-widget{width:100%;min-height:420px;background:#fff;padding:6px;overflow:hidden;display:flex;align-items:flex-start;justify-content:center;}
    .sod-tg-widget > div,
    .sod-tg-widget iframe{max-width:100% !important;width:100% !important;}
    .sod-video-thumb{
        background:#0f172a;border:1px solid #1e293b;border-radius:8px;
        overflow:hidden;aspect-ratio:16/9;display:flex;align-items:center;
        justify-content:center;font-size:36px;cursor:pointer;
    }
    /* Misc */
    .sod-pbi-loading{display:none;}
    .sod-pbi-loading.show{display:inline;animation:sod-spin 1s linear infinite;}
    .sod-divider{height:1px;background:#1e293b;margin:8px 0;}
    .sod-text-muted{color:#475569;font-size:11px;}
    .sod-section-title{font-size:12px;font-weight:700;color:#94a3b8;margin-bottom:8px;display:block;}
    .sod-two-col{display:grid;grid-template-columns:1fr 1fr;gap:12px;}
    .sod-three-col{display:grid;grid-template-columns:2fr 1fr 1fr;gap:12px;}
    @keyframes sod-spin{to{transform:rotate(360deg)}}
    @keyframes sod-blink{0%,100%{opacity:1}50%{opacity:.2}}
    @media(max-width:900px){
        .sod-body{flex-direction:column;}
        .sod-sidebar{width:100%;border-left:none;border-top:1px solid #334155;order:2;}
