        .sod-nav-btn{white-space:nowrap;padding:7px 12px;border-right:none !important;border-bottom:2px solid transparent;}
        .sod-nav-btn.active{border-bottom-color:#dc2626;border-right:none !important;}
        .sod-page{order:1;}
        .sod-charts-grid,.sod-two-col,.sod-three-col,.sod-settings-grid{grid-template-columns:1fr;}
        .sod-video-live-grid{grid-template-columns:repeat(2,minmax(0,1fr));}
