<script>
(function(){
'use strict';
const UID='<?php echo esc_js($uid); ?>';
const AJAX_URL=(typeof SOD_CONFIG!=='undefined')?SOD_CONFIG.ajaxUrl:'<?php echo esc_js(admin_url('admin-ajax.php')); ?>';
const NONCE=(typeof SOD_CONFIG!=='undefined')?SOD_CONFIG.nonce:'<?php echo esc_js(wp_create_nonce(SOD_AJAX_NONCE_ACTION)); ?>';
const TG_LINK=(typeof SOD_CONFIG!=='undefined')?SOD_CONFIG.tgLink:'<?php echo esc_js(SOD_TG_LINK); ?>';
const AUTO_REFRESH=<?php echo (int)$auto_refresh; ?>;
const TICKER_FLIP_MS=<?php echo (int) max(1500, min(30000, (int) get_option('sod_ticker_flip_speed', 4500))); ?>;
const SHOW_MAP=<?php echo $show_map ? 'true' : 'false'; ?>;
const SHOW_CHARTS=<?php echo $show_charts ? 'true' : 'false'; ?>;
const FEED_PER_PAGE=20;
const NEWS_PER_PAGE=15;

const $id=id=>document.getElementById(UID+'-'+id);
let mapInstance=null,heatLayer=null,markerGroup=null,mapMode='heat';
let charts={};
let allEvents=[];
let lastAnalytics=null; // stored for chart modal
let feedPage=0;
let newsPage=0;
let newsSearchTerm='';
let newsMinScore=0;
let soundOn=false;
let prevTotal=0;
let popupEventLink='';
let currentPage='dashboard';

/* ── Utilities ── */
function ar(n){return Number(n).toLocaleString('en-US');}
function esc(s){const d=document.createElement('div');d.textContent=s;return d.innerHTML;}
function scoreColor(s){if(s>=300)return '#ef4444';if(s>=200)return '#f97316';if(s>=140)return '#f59e0b';if(s>=80)return '#eab308';return '#22c55e';}
function scoreLabel(s){if(s>=300)return 'استراتيجي';if(s>=200)return 'حرج';if(s>=140)return 'عالي';if(s>=80)return 'متوسط';if(s>=40)return 'منخفض';return 'مراقبة';}
function scoreBadgeClass(s){if(s>=200)return 'sod-badge-red';if(s>=140)return 'sod-badge-orange';if(s>=80)return 'sod-badge-yellow';return 'sod-badge-green';}
function timeAgo(ts){const d=Math.floor((Date.now()/1000)-ts);if(d<60)return 'الآن';if(d<3600)return ar(Math.floor(d/60))+'د';if(d<86400)return ar(Math.floor(d/3600))+'س';return ar(Math.floor(d/86400))+'ي';}

/* ── Page navigation ── */
document.querySelectorAll('.sod-nav-btn[data-uid="'+UID+'"]').forEach(btn=>{
    btn.addEventListener('click',()=>{
        const page=btn.getAttribute('data-page');
        currentPage=page;
        document.querySelectorAll('.sod-nav-btn[data-uid="'+UID+'"]').forEach(b=>b.classList.remove('active'));
        btn.classList.add('active');
        document.querySelectorAll('#'+UID+' .sod-page').forEach(p=>p.classList.remove('active'));
        const el=$id('page-'+page);
        if(el){el.classList.add('active');}
        if(page==='maps'&&SHOW_MAP&&mapInstance){setTimeout(()=>mapInstance.invalidateSize(),200);}
        if(page==='news'){renderNews();}
        if(page==='alerts'){renderAlerts();}
        if(page==='kpis'){if(lastAnalytics)renderKpisPage(lastAnalytics);else fetchData();}
        if(page==='reports'){if(lastAnalytics)renderReports(lastAnalytics,allEvents);else fetchData();}
        if(page==='video'){renderVideo();}
    });
});

/* ── Map ── */
const REGION_COORDS={
    'لبنان':[33.8,35.5],'الأراضي المحتلة (إسرائيل)':[32.0,34.9],'فلسطين':[31.5,34.5],
    'إيران':[35.6,51.4],'سوريا':[33.5,36.2],'العراق':[33.3,44.4],'اليمن':[15.5,48.5],
    'روسيا/أوكرانيا':[50.4,30.5],'الولايات المتحدة':[38.9,-77.0],'السعودية':[24.7,46.7]
};

function initMap(retry){
    if(!SHOW_MAP)return;
    const el=document.getElementById(UID+'-map');
    if(!el)return;
    if(!window.L){
        if((retry||0)<20){setTimeout(()=>initMap((retry||0)+1),150);}
        else{console.warn('[SOD] Leaflet.js failed to load');}
        return;
    }
    if(mapInstance)return; // already initialized
    try{
        mapInstance=L.map(el,{center:[32,38],zoom:5,zoomControl:true,attributionControl:false});
        L.tileLayer('https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png',{
            attribution:'©OpenStreetMap ©Carto',subdomains:'abcd',maxZoom:19
        }).addTo(mapInstance);
        markerGroup=L.layerGroup().addTo(mapInstance);
        // Invalidate size after any CSS transition completes
        setTimeout(()=>{if(mapInstance)mapInstance.invalidateSize();},400);
    }catch(e){console.error('[SOD] Map init error:',e.message);}
}

function updateMap(events){
    if(!SHOW_MAP||!mapInstance)return;
    if(heatLayer){mapInstance.removeLayer(heatLayer);heatLayer=null;}
    markerGroup.clearLayers();
    const heat=[];
    events.forEach(ev=>{
        const coords=REGION_COORDS[ev.region];
        if(!coords)return;
        const lat=coords[0]+(Math.random()-.5)*1.5,lng=coords[1]+(Math.random()-.5)*1.5;
        const intensity=Math.min(1,ev.score/300);
        heat.push([lat,lng,intensity]);
        if(mapMode==='markers'){
            const col=scoreColor(ev.score);
            const marker=L.circleMarker([lat,lng],{radius:Math.max(4,ev.score/40),color:col,fillColor:col,fillOpacity:.7,weight:1});
            marker.bindPopup(`<div dir="rtl" style="font-family:'Noto Naskh Arabic',Cairo,sans-serif;min-width:200px;"><b style="color:${col}">${ar(ev.score)} – ${scoreLabel(ev.score)}</b><br><b>${esc(ev.title.substring(0,80))}</b><br><small>الفاعل: ${esc(ev.actor_v2)}</small><br><small>المنطقة: ${esc(ev.region)}</small></div>`);
            markerGroup.addLayer(marker);
        }
    });
    if(mapMode==='heat'&&heat.length&&window.L&&L.heatLayer){
        heatLayer=L.heatLayer(heat,{radius:28,blur:18,maxZoom:10,gradient:{0.4:'#22c55e',0.65:'#f59e0b',0.8:'#f97316',1.0:'#ef4444'}});
        heatLayer.addTo(mapInstance);
    }
}

/* ── Charts ── */
function updateCharts(analytics,suffix){
    if(!SHOW_CHARTS||typeof Chart==='undefined')return;
    suffix=suffix||'';
    const hours=analytics.hourly||{};
    buildChart('chart'+suffix+'-hourly','bar',Object.keys(hours).map(k=>k.substring(11,16)),Object.values(hours),'تدفق الأحداث','#3b82f6');
    const actors=analytics.actors||{};
    const top8a=Object.entries(actors).slice(0,8);
    buildChart('chart'+suffix+'-actors','doughnut',top8a.map(a=>a[0].substring(0,20)),top8a.map(a=>a[1]),'الفاعلون',['#ef4444','#f97316','#f59e0b','#22c55e','#3b82f6','#8b5cf6','#ec4899','#14b8a6']);
    const tl=analytics.truth_layers||{};
    const tlLabels={'field_action':'ميداني','statement':'تصريح','report':'تقرير','defensive_alert':'إنذار','rumor':'شائعة','general':'عام'};
    buildChart('chart'+suffix+'-truth','pie',Object.keys(tl).map(k=>tlLabels[k]||k),Object.values(tl),'طبقات التحقق',['#ef4444','#f59e0b','#3b82f6','#f97316','#8b5cf6','#22c55e']);
    const it=analytics.intel_types||{};
    buildChart('chart'+suffix+'-intel','bar',Object.keys(it).map(k=>k.substring(0,15)),Object.values(it),'المحاور الاستراتيجية','#8b5cf6');
}

function buildChart(canvasId,type,labels,data,title,color){
    if(typeof Chart==='undefined'){console.warn('[SOD] Chart.js not loaded yet for',canvasId);return;}
    const canvas=document.getElementById(UID+'-'+canvasId);
    if(!canvas)return;
    try{
        if(charts[canvasId]){try{charts[canvasId].destroy();}catch(e){} charts[canvasId]=null;}
        const existing=Chart.getChart(canvas);if(existing)try{existing.destroy();}catch(e){}
        const colors=Array.isArray(color)?color:labels.map((_,i)=>[color,'#f97316','#22c55e','#f59e0b','#8b5cf6','#ec4899','#14b8a6','#64748b'][i%8]);
        charts[canvasId]=new Chart(canvas,{type,data:{labels,datasets:[{data,backgroundColor:colors,borderColor:Array.isArray(color)?colors:color,borderWidth:type==='bar'?0:2,borderRadius:type==='bar'?4:0}]},options:{responsive:true,maintainAspectRatio:false,plugins:{legend:{display:type!=='bar',labels:{color:'#94a3b8',font:{size:9},boxWidth:12}},tooltip:{callbacks:{label:ctx=>{const v=ctx.parsed.y??ctx.parsed;return ar(v);}}}},scales:type==='bar'?{x:{ticks:{color:'#64748b',font:{size:8}},grid:{color:'rgba(51,65,85,.5)'}},y:{ticks:{color:'#64748b',font:{size:8},callback:v=>ar(v)},grid:{color:'rgba(51,65,85,.5)'},beginAtZero:true}}:{},animation:{duration:300}}});
        // Chart modal trigger
        canvas._sodMeta={canvasId,type,labels,data,title,color};
        canvas.onclick=()=>openChartModal(canvas._sodMeta);
    }catch(e){console.error('[SOD] Chart build error:',canvasId,e.message);}
}

/* ══════════════════════════════════════════
   Chart Modal — نافذة الرسم البياني المنبثقة
   ══════════════════════════════════════════ */
let _cmEvents=[],_cmPage=1,_cmPerPage=25;

function openChartModal(meta){
    const existing=document.getElementById('sod-chart-modal');
    if(existing)existing.remove();

    const regions=[...new Set(allEvents.map(e=>e.region).filter(Boolean))].sort();
    const intelTypes=[...new Set(allEvents.map(e=>e.intel_type).filter(Boolean))].sort();

    const modal=document.createElement('div');
    modal.id='sod-chart-modal';

    const box=document.createElement('div');
    box.className='sod-cm-box';
    box.setAttribute('dir','rtl');

    // Header
    const hdr=document.createElement('div');
    hdr.className='sod-cm-hdr';
    const titleEl=document.createElement('span');
    titleEl.className='sod-cm-title';
    titleEl.textContent='📊 '+meta.title;
    const btnPrint=document.createElement('button');
    btnPrint.className='sod-cm-btn sod-cm-btn-print';
    btnPrint.textContent='🖨️ طباعة A3';
    const btnClose=document.createElement('button');
    btnClose.className='sod-cm-btn sod-cm-btn-close';
    btnClose.textContent='✕ إغلاق';
    hdr.append(titleEl,btnPrint,btnClose);

    // Chart area
    const chartWrap=document.createElement('div');
    chartWrap.className='sod-cm-chart';
    const cmCanvas=document.createElement('canvas');
    cmCanvas.id='sod-cm-canvas';
    chartWrap.appendChild(cmCanvas);

    // Filters
    const filtersEl=document.createElement('div');
    filtersEl.className='sod-cm-filters';
    filtersEl.innerHTML=`
        <input class="sod-cm-filter" id="sod-cm-search" type="text" placeholder="🔍 بحث في العنوان أو الفاعل...">
        <select class="sod-cm-filter" id="sod-cm-region">
            <option value="">🌍 كل المناطق</option>
            ${regions.map(r=>`<option value="${esc(r)}">${esc(r)}</option>`).join('')}
        </select>
        <select class="sod-cm-filter" id="sod-cm-intel">
            <option value="">🎯 كل المحاور</option>
            ${intelTypes.map(t=>`<option value="${esc(t)}">${esc(t)}</option>`).join('')}
        </select>
        <input class="sod-cm-filter" id="sod-cm-score" type="number" placeholder="درجة أدنى" min="0" max="500" style="max-width:130px;">
        <span style="font-size:10px;color:#64748b;align-self:center;" id="sod-cm-count"></span>`;

    // Events table
    const evWrap=document.createElement('div');
    evWrap.className='sod-cm-events';
    evWrap.id='sod-cm-events-wrap';
    evWrap.innerHTML=`<table class="sod-cm-tbl"><thead><tr>
        <th>الوقت</th><th>الدرجة</th><th>العنوان + كل التصنيفات</th><th>الفاعل</th><th>المنطقة</th><th>المحور</th><th>المصدر</th>
    </tr></thead><tbody id="sod-cm-tbody"></tbody></table>`;

    const pgEl=document.createElement('div');
    pgEl.className='sod-cm-pg';
    pgEl.id='sod-cm-pg';

    box.append(hdr,chartWrap,filtersEl,evWrap,pgEl);
    modal.appendChild(box);
    document.body.appendChild(modal);

    // ── Event listeners (no inline onclick) ──
    btnClose.addEventListener('click',closeChartModal);
    btnPrint.addEventListener('click',()=>printChartModal(meta));
    modal.addEventListener('click',e=>{if(e.target===modal)closeChartModal();});
    document.addEventListener('keydown',_cmEscHandler);

    // Filter listeners
    ['sod-cm-search','sod-cm-region','sod-cm-intel','sod-cm-score'].forEach(id=>{
        const el=document.getElementById(id);
        if(el)el.addEventListener(el.tagName==='SELECT'?'change':'input',cmApplyFilters);
    });

    // Render enlarged chart
    setTimeout(()=>{
        const ctx=document.getElementById('sod-cm-canvas');
        if(ctx&&typeof Chart!=='undefined'){
            try{
                const colors=Array.isArray(meta.color)?meta.color:meta.labels.map((_,i)=>[meta.color,'#f97316','#22c55e','#f59e0b','#8b5cf6','#ec4899','#14b8a6','#64748b'][i%8]);
                new Chart(ctx,{type:meta.type,data:{labels:meta.labels,datasets:[{data:meta.data,backgroundColor:colors,borderColor:Array.isArray(meta.color)?colors:meta.color,borderWidth:meta.type==='bar'?0:2,borderRadius:meta.type==='bar'?6:0}]},options:{responsive:true,maintainAspectRatio:false,plugins:{legend:{display:meta.type!=='bar',labels:{color:'#94a3b8',font:{size:12},boxWidth:16}},tooltip:{callbacks:{label:c2=>{const v=c2.parsed.y??c2.parsed;return ar(v);}}}},scales:meta.type==='bar'?{x:{ticks:{color:'#64748b',font:{size:11}},grid:{color:'rgba(51,65,85,.5)'}},y:{ticks:{color:'#64748b',font:{size:11},callback:v=>ar(v)},grid:{color:'rgba(51,65,85,.5)'},beginAtZero:true}}:{},animation:{duration:400}}});
            }catch(err){console.error('[SOD Modal] Chart:',err);}
        }
    },80);

    _cmEvents=allEvents.slice();
    _cmPage=1;
    cmRenderTable();
}

function _cmEscHandler(e){if(e.key==='Escape')closeChartModal();}

function closeChartModal(){
    const m=document.getElementById('sod-chart-modal');
    if(m){m.style.opacity='0';m.style.transition='opacity .15s';setTimeout(()=>m.remove(),150);}
    document.removeEventListener('keydown',_cmEscHandler);
}

function printChartModal(meta){
    // Build print-safe HTML in new window (most reliable cross-browser method)
    const tbody=document.getElementById('sod-cm-tbody');
    const tbodyHtml=tbody?tbody.innerHTML:'';
    const pw=window.open('','_blank','width=1400,height=900');
    if(!pw){alert('يرجى السماح بالنوافذ المنبثقة لتفعيل الطباعة');return;}
    const title=meta?meta.title:'التقرير';
    pw.document.write(`<!DOCTYPE html><html dir="rtl" lang="ar">
<head><meta charset="UTF-8">
<title>طباعة: ${esc(title)}</title>
<style>
@page{size:A3 landscape;margin:12mm}
*{box-sizing:border-box;font-family:'Segoe UI','Noto Naskh Arabic',Arial,sans-serif}
body{background:#fff;color:#1e293b;margin:0;padding:0}
.print-hdr{background:#1d4ed8;color:#fff;padding:12px 20px;display:flex;align-items:center;gap:16px;-webkit-print-color-adjust:exact;print-color-adjust:exact}
.print-hdr h1{margin:0;font-size:18px}
.print-date{font-size:12px;opacity:.8;margin-right:auto}
table{width:100%;border-collapse:collapse;font-size:11px;margin-top:8px}
th{background:#1e3a5f;color:#fff;padding:7px 10px;text-align:right;-webkit-print-color-adjust:exact;print-color-adjust:exact}
td{padding:6px 10px;border-bottom:1px solid #e2e8f0;color:#1e293b}
tr:nth-child(even) td{background:#f8fafc}
a{color:#1d4ed8;text-decoration:none}
</style></head><body>
<div class="print-hdr">
    <h1>📊 ${esc(title)}</h1>
    <span class="print-date">📅 ${new Date().toLocaleString('ar-LB')}</span>
</div>
<table>
<thead><tr><th>الوقت</th><th>الدرجة</th><th>العنوان</th><th>الفاعل</th><th>المنطقة</th><th>المحور</th><th>المصدر</th></tr></thead>
<tbody>${tbodyHtml}</tbody>
</table>
</body></html>`);
    pw.document.close();
    pw.focus();
    setTimeout(()=>{pw.print();},500);
}

function cmApplyFilters(){
    const search=(document.getElementById('sod-cm-search')||{}).value||'';
    const region=(document.getElementById('sod-cm-region')||{}).value||'';
    const intel=(document.getElementById('sod-cm-intel')||{}).value||'';
    const minScore=parseInt((document.getElementById('sod-cm-score')||{}).value)||0;
    const sl=search.toLowerCase();
    _cmEvents=allEvents.filter(e=>{
        if(minScore&&(e.score||0)<minScore)return false;
        if(region&&e.region!==region)return false;
        if(intel&&e.intel_type!==intel)return false;
        if(sl&&!(e.title||'').toLowerCase().includes(sl)&&!(e.actor_v2||'').toLowerCase().includes(sl))return false;
        return true;
    });
    _cmPage=1;
    cmRenderTable();
}

function cmRenderTable(){
    const tbody=document.getElementById('sod-cm-tbody');
    const pgEl=document.getElementById('sod-cm-pg');
    const countEl=document.getElementById('sod-cm-count');
    if(!tbody)return;
    const total=_cmEvents.length;
    const pages=Math.max(1,Math.ceil(total/_cmPerPage));
    if(_cmPage>pages)_cmPage=1;
    const slice=_cmEvents.slice((_cmPage-1)*_cmPerPage,_cmPage*_cmPerPage);
    if(countEl)countEl.textContent=ar(total)+' حدث';
    tbody.innerHTML=slice.map(ev=>{
        const col=(ev.score||0)>=300?'#ef4444':(ev.score||0)>=200?'#f97316':(ev.score||0)>=140?'#f59e0b':'#94a3b8';
        const dt=ev.event_timestamp?new Date(ev.event_timestamp*1000).toLocaleString('ar-LB',{month:'numeric',day:'numeric',hour:'2-digit',minute:'2-digit'}):'—';
        return`<tr>
            <td style="white-space:nowrap;font-size:10px;">${dt}</td>
            <td class="sod-cm-score" style="color:${col};">${ar(ev.score||0)}</td>
            <td><a href="${esc(ev.link||'#')}" target="_blank" rel="noopener" style="color:#60a5fa;text-decoration:none;">${esc((ev.title||'').substring(0,90))}${(ev.title||'').length>90?'…':''}</a></td>
            <td style="white-space:nowrap;">${esc(ev.actor_v2||'—')}</td>
            <td style="white-space:nowrap;">${esc(ev.region||'—')}</td>
            <td style="white-space:nowrap;">${esc(ev.intel_type||'—')}</td>
            <td style="white-space:nowrap;font-size:10px;">${esc(ev.source_name||'—')}</td>
        </tr>`;
    }).join('');
    // Pagination
    if(pgEl){
        let pg='';
        if(pages>1){
            const start=Math.max(1,_cmPage-3);
            const end=Math.min(pages,_cmPage+3);
            if(start>1)pg+=`<button class="sod-cm-pg-btn" onclick="_cmPage=1;cmRenderTable()">1</button><span style="color:#475569;padding:0 4px;">…</span>`;
            for(let i=start;i<=end;i++)pg+=`<button class="sod-cm-pg-btn${i===_cmPage?' active':''}" onclick="_cmPage=${i};cmRenderTable()">${i}</button>`;
            if(end<pages)pg+=`<span style="color:#475569;padding:0 4px;">…</span><button class="sod-cm-pg-btn" onclick="_cmPage=${pages};cmRenderTable()">${pages}</button>`;
        }
        pgEl.innerHTML=pg;
    }
}

/* ── KPI rendering ── */
function renderKPI(id,val){const el=$id('kpi-'+id);if(el)el.textContent=val;}

/* ── Feed (dashboard page) ── */
function renderFeed(){
    const tbody=$id('feed-tbody');if(!tbody)return;
    const scoreFilter=parseInt($id('feed-filter-score')?.value||0);
    const searchTerm=($id('feed-search')?.value||'').toLowerCase().trim();
    let filtered=allEvents.filter(e=>{
        if(e.score<scoreFilter)return false;
        const title=(e.title||'').toLowerCase();
        const actor=(e.actor_v2||'').toLowerCase();
        const region=(e.region||'').toLowerCase();
        if(searchTerm&&!title.includes(searchTerm)&&!actor.includes(searchTerm)&&!region.includes(searchTerm))return false;
        return true;
    });
    const total=filtered.length;
    const pages=Math.ceil(total/FEED_PER_PAGE);
    feedPage=Math.min(feedPage,Math.max(0,pages-1));
    const slice=filtered.slice(feedPage*FEED_PER_PAGE,(feedPage+1)*FEED_PER_PAGE);
    if(!slice.length){tbody.innerHTML='<tr><td colspan="10" class="sod-loading-row">لا توجد أحداث مطابقة</td></tr>';return;}
    tbody.innerHTML=slice.map(ev=>{
        const col=scoreColor(ev.score);
        const lbl=scoreLabel(ev.score);
        const aiB=ev.llm_verified?'<span title="تم التحقق بالذكاء الاصطناعي" style="color:#60a5fa;margin-left:4px;">🤖</span>':'';
        let war={};
        try{war=typeof ev.war_data==='string'?JSON.parse(ev.war_data||'{}'):(ev.war_data||{});}catch(_e){war={};}
        const primary=ev.actor_primary||ev.primary_actor||war.actor_primary||war.primary_actor||ev.actor_v2||'—';
        const target=ev.target_v2||war.target||'—';
        const context=ev.context_actor||war.context_actor||'—';
        const intent=ev.intent||war.intent||'—';
        const actorLabel=ev.actor_v2||'—';
        const regionLabel=ev.region||'—';
        const levelLabel=ev.tactical_level||'—';
        return `<tr>
            <td style="text-align:center;"><span class="sod-score-badge" style="background:${col}20;color:${col};border:1px solid ${col}40;">${ar(ev.score)}</span><br><small style="font-size:9px;color:#94a3b8;">${lbl}</small></td>
            <td style="color:#94a3b8;font-size:11px;text-align:center;white-space:nowrap;">${timeAgo(ev.event_timestamp)}</td>
            <td style="font-size:11px;color:#cbd5e1;text-align:center;">${esc(String(actorLabel).substring(0,24))}</td>
            <td style="font-size:11px;color:#f8fafc;text-align:center;">${esc(String(primary).substring(0,24))}</td>
            <td style="font-size:11px;color:#cbd5e1;text-align:center;">${esc(String(target).substring(0,24))}</td>
            <td style="font-size:11px;color:#93c5fd;text-align:center;">${esc(String(context).substring(0,22))}</td>
            <td style="font-size:11px;color:#fbbf24;text-align:center;">${esc(String(intent).substring(0,18))}</td>
            <td>${aiB}<a href="${esc(ev.link)}" target="_blank" rel="noopener noreferrer" style="font-size:12px;">${esc(ev.title.substring(0,88))}${ev.title.length>88?'...':''}</a></td>
            <td style="font-size:11px;color:#cbd5e1;text-align:center;">${esc(String(regionLabel).substring(0,18))}</td>
            <td style="text-align:center;"><span class="sod-level-chip">${esc(String(levelLabel).substring(0,14))}</span></td>
        </tr>`;
    }).join('');
    const pag=$id('feed-pagination');if(!pag)return;
    if(pages>1){pag.innerHTML=Array.from({length:pages},(_,i)=>`<button class="sod-page-btn${i===feedPage?' active':''}" onclick="sod_feedpage_${UID}(${i})">${ar(i+1)}</button>`).join('');}
    else pag.innerHTML='';
}
window['sod_feedpage_'+UID]=(p)=>{feedPage=p;renderFeed();};

/* ── News page ── */
function renderNews(){
    const grid=$id('news-grid');if(!grid)return;
    const scoreF=parseInt($id('news-filter-score')?.value||0);
    const searchT=($id('news-search')?.value||'').toLowerCase().trim();
    let filtered=allEvents.filter(e=>{
        if(e.score<scoreF)return false;
        if(searchT&&!e.title.toLowerCase().includes(searchT)&&!(e.actor_v2||'').toLowerCase().includes(searchT))return false;
        return true;
    });
    const pages=Math.ceil(filtered.length/NEWS_PER_PAGE);
    newsPage=Math.min(newsPage,Math.max(0,pages-1));
    const slice=filtered.slice(newsPage*NEWS_PER_PAGE,(newsPage+1)*NEWS_PER_PAGE);
    if(!slice.length){grid.innerHTML='<div class="sod-loading-row">لا توجد أخبار مطابقة</div>';return;}
    grid.innerHTML=slice.map(ev=>{
        const col=scoreColor(ev.score);
        const lbl=scoreLabel(ev.score);
        const bc=scoreBadgeClass(ev.score);
        const conf=Math.min(100,Math.round((ev.score/300)*100));
        const aiB=ev.llm_verified?'<span class="sod-badge sod-badge-blue" title="تم التحقق بالذكاء الاصطناعي">🤖 AI</span>':'';
        const evalB=ev.has_manual_override?'<span class="sod-badge sod-badge-orange" title="العنصر محفوظ يدويًا ومقفل من إعادة التحليل">✍️ يدوي</span>':`<span class="sod-badge sod-badge-green" title="آخر تقييم مسجل">${esc(ev.evaluation_label||'آلي')}</span>`;
        return `<div class="sod-news-card">
            <div class="sod-news-card-meta">
                <span class="sod-badge ${bc}">${ar(ev.score)} — ${lbl}</span>
                ${ev.actor_v2?`<span class="sod-badge sod-badge-gray">${esc(ev.actor_v2.substring(0,25))}</span>`:''}
                ${ev.region?`<span class="sod-badge sod-badge-purple">${esc(ev.region)}</span>`:''}
                ${ev.intel_type?`<span class="sod-badge sod-badge-blue">${esc(ev.intel_type.substring(0,20))}</span>`:''}
                ${evalB}${aiB}
            </div>
            <div class="sod-news-title">
                <a href="${esc(ev.link)}" target="_blank" rel="noopener noreferrer">${esc(ev.title)}</a>
            </div>
            <div class="sod-confidence-bar-wrap">
                <span class="sod-confidence-label">الثقة:</span>
                <div class="sod-confidence-bar"><div class="sod-confidence-fill" style="width:${conf}%;background:${col};"></div></div>
                <span style="font-size:10px;color:#64748b;">${ar(conf)}%</span>
            </div>
            <div class="sod-news-footer">
                <span>${timeAgo(ev.event_timestamp)}</span>
                ${ev.source_name?`<span>· ${esc(ev.source_name)}</span>`:''}
                ${ev.tactical_level?`<span class="sod-level-chip">${esc(ev.tactical_level)}</span>`:''}
            </div>
        </div>`;
    }).join('');
    const pag=$id('news-pagination');
    if(pag&&pages>1){pag.innerHTML=Array.from({length:pages},(_,i)=>`<button class="sod-page-btn${i===newsPage?' active':''}" onclick="sod_newspage_${UID}(${i})">${ar(i+1)}</button>`).join('');}
    else if(pag)pag.innerHTML='';
}
window['sod_newspage_'+UID]=(p)=>{newsPage=p;renderNews();};

/* ── Alerts page ── */
function renderAlerts(){
    const list=$id('alerts-list');if(!list)return;
    const critical=allEvents.filter(e=>e.score>=140).slice(0,30);
    if(!critical.length){list.innerHTML='<div class="sod-loading-row">لا توجد تنبيهات حرجة في الوقت الحالي.</div>';return;}
    list.innerHTML=critical.map(ev=>{
        const col=scoreColor(ev.score);
        return `<div class="sod-alert-card${ev.score>=200?' critical':''}">
            <div class="sod-alert-score-circle" style="background:${col}20;color:${col};border:1px solid ${col}40;">
                <div style="text-align:center;"><div style="font-size:14px;font-weight:700;">${ar(ev.score)}</div><div style="font-size:9px;">${scoreLabel(ev.score)}</div></div>
            </div>
            <div style="flex:1;">
                <div style="font-size:13px;font-weight:600;color:#f8fafc;margin-bottom:4px;">
                    <a href="${esc(ev.link)}" target="_blank" rel="noopener noreferrer" style="color:#f8fafc;text-decoration:none;">${esc(ev.title)}</a>
                </div>
                <div style="display:flex;gap:8px;flex-wrap:wrap;font-size:11px;color:#64748b;">
                    ${ev.actor_v2?`<span>🎭 ${esc(ev.actor_v2)}</span>`:''}
                    ${ev.region?`<span>📍 ${esc(ev.region)}</span>`:''}
                    <span>⏱ ${timeAgo(ev.event_timestamp)}</span>
                    ${ev.llm_verified?'<span>🤖 AI محقق</span>':''}
                </div>
            </div>
        </div>`;
    }).join('');
}

/* ── KPIs page ── */
function renderKpisPage(analytics){
    const el=$id('kpis-extended');if(!el||!analytics)return;
    const kpiData=[
        {label:'إجمالي الأحداث',value:ar(analytics.total||0),color:'#60a5fa',icon:'📊'},
        {label:'أحداث حرجة',value:ar(analytics.critical||0),color:'#f87171',icon:'🚨'},
        {label:'متوسط الخطورة',value:ar(analytics.avg_score||0),color:'#fbbf24',icon:'⚡'},
        {label:'مؤشر الصراع GCI',value:ar(analytics.gci||0),color:'#34d399',icon:'🌐'},
        {label:'مؤشر التصعيد',value:ar(analytics.escalation_index||0)+'%',color:'#c084fc',icon:'📈'},
        {label:'مؤشر التضليل',value:ar(analytics.deception_index||0)+'%',color:'#fbbf24',icon:'🎭'},
        {label:'أفعال ميدانية',value:ar(analytics.truth_layers?.field_action||0),color:'#f87171',icon:'💥'},
