if (!class_exists('SO_Frontend_Critical_Popup')) {
class SO_Frontend_Critical_Popup {
    public static function init() { add_action('wp_footer', [__CLASS__, 'render']); }
    public static function render() {
        if (is_admin() || !get_option('so_popup_enabled', 0)) return;
        $ajax_url = admin_url('admin-ajax.php');
        $sound_url = esc_url(get_option('so_alert_sound_url', ''));
        $tg_link = esc_url(get_option('so_popup_telegram_link', SO_TELEGRAM_LINK));
        ?>
        <div id="so-critical-popup" aria-hidden="true" style="position:fixed;inset:0;display:none;align-items:center;justify-content:center;z-index:999999;font-family:'Cairo','Tajawal',sans-serif;">
            <div class="so-critical-backdrop" style="position:absolute;inset:0;background:rgba(7,12,18,.5);"></div>
            <div class="so-critical-card" style="position:relative;max-width:560px;width:min(92vw,560px);background:linear-gradient(180deg,#102032,#0b1520);color:#fff;border:1px solid rgba(255,255,255,.12);border-radius:18px;box-shadow:0 18px 45px rgba(0,0,0,.35);padding:18px;cursor:pointer;" role="button" tabindex="0">
                <button type="button" style="position:absolute;top:10px;left:10px;width:34px;height:34px;border-radius:50%;border:none;background:#ef4444;color:#fff;font-size:18px;cursor:pointer;z-index:2;" class="so-critical-close" aria-label="إغلاق">×</button>
                <div style="font-size:20px;font-weight:800;margin:0 40px 10px 0;color:#fff;">🚨 خبر حرج</div>
                <div class="so-critical-meta" style="font-size:13px;opacity:.88;margin-bottom:8px;"></div>
                <div class="so-critical-text" style="font-size:15px;line-height:1.8;color:#eef6ff;"></div>
                <div style="margin-top:12px;font-size:13px;color:#a7d7ff;">اضغط للانتقال إلى قناة تليغرام</div>
            </div>
            <?php if ($sound_url): ?><audio id="so-critical-popup-audio" src="<?php echo $sound_url; ?>" preload="auto"></audio><?php endif; ?>
        </div>
        <script>
        document.addEventListener('DOMContentLoaded',function(){
            const wrap=document.getElementById('so-critical-popup');
            if(!wrap)return;
            const card=wrap.querySelector('.so-critical-card');
            const closeBtn=wrap.querySelector('.so-critical-close');
            const meta=wrap.querySelector('.so-critical-meta');
            const text=wrap.querySelector('.so-critical-text');
            const audio=document.getElementById('so-critical-popup-audio');
            const ajaxUrl=<?php echo wp_json_encode($ajax_url); ?>;
            const tgLink=<?php echo wp_json_encode($tg_link); ?>;
            let lastSeen=Number(localStorage.getItem('so_critical_popup_last_seen')||'0');
            let activeTs=0;
            function ar(n){return Number(n).toLocaleString('en-US');}
            function closePopup(ev){if(ev)ev.preventDefault();wrap.style.display='none';if(activeTs)localStorage.setItem('so_critical_popup_last_seen',String(activeTs));if(audio){audio.pause();audio.currentTime=0;}}
            function openPopup(ev){
                activeTs=Number(ev.event_timestamp||0);
                meta.textContent=(ev.source_name||'مصدر')+'  •  '+(ev.region||'غير محدد')+'  •  '+ar(ev.score||0);
                text.textContent=ev.title||'';
                card.onclick=function(){window.open(ev.telegram_link||tgLink,'_blank');closePopup();};
                wrap.style.display='flex';
                if(audio){audio.currentTime=0;audio.play().catch(()=>{});}
            }
            if(closeBtn)closeBtn.addEventListener('click',function(ev){ev.preventDefault();ev.stopPropagation();closePopup(ev);});
            wrap.querySelector('.so-critical-backdrop').addEventListener('click',closePopup);
            document.addEventListener('keydown',function(e){if(e.key==='Escape')closePopup();});
            async function parsePopupAjaxJson(res){
                const text=await res.text();
                try{return JSON.parse(text);}catch(e){
                    const trimmed=String(text||'').trim();
                    const objStart=trimmed.indexOf('{');
                    const arrStart=trimmed.indexOf('[');
                    let start=-1;
                    if(objStart>=0&&arrStart>=0) start=Math.min(objStart,arrStart);
                    else start=objStart>=0?objStart:arrStart;
                    if(start>=0) return JSON.parse(trimmed.slice(start));
                    throw new Error(trimmed.slice(0,220)||('HTTP '+res.status));
                }
            }
            async function poll(){
                try{
                    const fd=new FormData();fd.append('action','so_get_critical_popup');
                    const res=await fetch(ajaxUrl,{method:'POST',body:fd,credentials:'same-origin'});
                    const json=await parsePopupAjaxJson(res);
                    const ev=json&&json.success&&json.data?json.data.event:null;
                    if(ev&&Number(ev.event_timestamp||0)>lastSeen){openPopup(ev);}
                }catch(e){}
            }
            poll();setInterval(poll,45000);
        });
        </script>
        <?php
    }
}
}

