    private static function get_all_plugin_options(): array {
        $keys = [
            'so_enable_logging','so_fetch_latest_only','so_filter_keywords','so_openweather_api_key',
            'so_twitter_bearer_token','so_alert_threshold','so_popup_enabled','so_popup_threshold',
            'so_popup_recent_minutes','so_popup_telegram_link','so_alert_sound_url',
            'so_sources','so_tg_sources','so_x_sources',
            'so_llm_api_key','so_llm_brief_enabled',
            'so_tg_token','so_tg_chat','so_telegram_enabled','so_discord_webhook',
            'so_exec_reports_frequency','so_exec_reports_window_hours','so_exec_reports_critical_threshold',
            'so_exec_reports_chat_id','so_exec_reports_footer','so_exec_reports_custom_hours',
            'so_exec_reports_enabled','so_exec_reports_force_repeat',
            'so_custom_primary_color','so_custom_bg_color','so_custom_font',
            'so_video_streams','so_external_cron_key',
            'sod_powerbi_default_hours','sod_powerbi_auto_refresh',
            'sod_ticker_auto_refresh','sod_threat_auto_refresh',
            'so_powerbi_header_text','so_powerbi_logo_url','so_powerbi_footer_text',
        ];
        $data = ['_plugin'=>'beiruttime-osint-pro','_exported_at'=>gmdate('c')];
        foreach ($keys as $k) $data[$k] = get_option($k);
        return $data;
    }

    public static function ajax_test_telegram() {
        if (!current_user_can('manage_options') || !check_ajax_referer('so_test_telegram','nonce',false)) { wp_send_json_error(['message'=>'غير مصرح']); }
        $token = trim(get_option('so_tg_token',''));
        $chats = array_filter(array_map('trim', explode(',', get_option('so_tg_chat',''))));
        if (empty($token) || empty($chats)) { wp_send_json_error(['message'=>'يرجى إدخال التوكن وقائمة الغرف أولاً']); }
        $ok = false;
        foreach ($chats as $chat_id) {
            $res = so_safe_remote_post("https://api.telegram.org/bot{$token}/sendMessage", ['headers'=>['Content-Type'=>'application/json'],'body'=>wp_json_encode(['chat_id'=>$chat_id,'text'=>'✅ اختبار ناجح من Beiruttime OSINT System V.Beta 111 — نظام الرصد الاستخباراتي الموحد','parse_mode'=>'HTML']),'timeout'=>10]);
            if (!is_wp_error($res)) { $body = json_decode(wp_remote_retrieve_body($res),true); if (!empty($body['ok'])) $ok = true; }
        }
        $ok ? wp_send_json_success(['message'=>'تم الإرسال بنجاح']) : wp_send_json_error(['message'=>'فشل الإرسال — تحقق من التوكن وصلاحيات البوت']);
    }

