    public static function page_reports() {
        self::admin_wrap_open('التقارير التنفيذية');
        self::admin_nav('strategic-osint-reports');
        // Handle manual send via form submit
        if (isset($_GET['exec_report_sent'])) {
            $ok = $_GET['exec_report_sent'] === '1';
            echo '<div style="background:' . ($ok ? '#14532d' : '#7f1d1d') . ';color:#fff;padding:12px 16px;border-radius:8px;margin-bottom:16px;">';
            echo $ok ? '✅ تم إرسال التقرير إلى تيليغرام بنجاح.' : '❌ فشل إرسال التقرير. تحقق من إعدادات تيليغرام.';
            echo '</div>';
        }
        $last_sent = get_option('so_exec_last_report_time', 0);
        $last_sent_str = $last_sent ? wp_date('Y-m-d H:i', $last_sent) : 'لم يُرسل بعد';
        $report = [];
        $report_html = '';
        $report_error = '';
        try {
            $report = SO_Executive_Reports::build_report();
            $report_html = SO_Executive_Reports::render_exec_report_html($report);
        } catch (\Throwable $e) {
            $report_error = $e->getMessage();
            if (function_exists('so_log_event')) {
                so_log_event('exec_report_error', [
                    'message' => $e->getMessage(),
                    'file' => $e->getFile(),
                    'line' => $e->getLine(),
                ]);
            }
        }
        ?>
        <!-- إرسال يدوي فوري -->
        <div class="so-admin-card" style="border:2px solid #dc2626;">
            <h3>🚀 إرسال تقرير فوري الآن</h3>
