                    <td style="text-align:center;font-weight:700;color:<?php echo sod_get_score_color((int)$news_item['score']); ?>;"><?php echo (int)$news_item['score']; ?></td>
                    <td><?php echo esc_html($news_item['region']); ?></td>
                    <td style="color:#4a6a8a;font-size:11px;"><?php echo esc_html(wp_date('H:i d/m', (int)$news_item['event_timestamp'])); ?></td>
                    <td>
                        <button type="button" class="so-btn so-btn-secondary so-send-tg-btn" style="padding:4px 10px;font-size:11px;background:#16a34a;border-color:#16a34a;" data-id="<?php echo (int)$news_item['id']; ?>" data-nonce="<?php echo wp_create_nonce('so_admin_send_tg'); ?>">
                            📤 إرسال
                        </button>
                    </td>
                </tr>
                <?php endforeach; ?>
                </tbody>
            </table>
        </div>
        <script>
        document.querySelectorAll('.so-send-tg-btn').forEach(function(btn){
            btn.addEventListener('click', function(){
                const self=this; self.disabled=true; self.textContent='⏳ ...';
                const fd=new FormData();
                fd.append('action','so_admin_send_telegram');
                fd.append('nonce',self.dataset.nonce);
                fd.append('event_id',self.dataset.id);
                fetch('<?php echo esc_js(admin_url('admin-ajax.php')); ?>',{method:'POST',body:fd,credentials:'same-origin'})
                .then(r=>r.text().then(t=>({status:r.status,text:t})))
                .then(({status,text})=>{
                    let j=null;
                    try{j=JSON.parse(text);}catch(e){
                        const trimmed=String(text||'').trim();
                        const start=trimmed.indexOf('{');
                        if(start>=0){try{j=JSON.parse(trimmed.slice(start));}catch(e2){}}
                    }
                    if(!j){
                        self.textContent='❌ فشل';
                        self.style.background='#dc2626';
                        self.disabled=false;
                        alert(text ? text.slice(0,220) : ('HTTP '+status));
                        return;
                    }
                    if(j.success){self.textContent='✅ أُرسل';self.style.background='#15803d';}
                    else{self.textContent='❌ فشل';self.style.background='#dc2626';self.disabled=false;}
                    if(j.data?.message) alert(j.data.message);
                }).catch(()=>{self.textContent='❌ خطأ';self.disabled=false;});
            });
        });
        </script>
        <?php endif;
        self::admin_wrap_close();
    }

