        // Handle unified visible banks save/delete
        if ($_SERVER['REQUEST_METHOD'] === 'POST' && !empty($_POST['sod_bank_registry_action']) && check_admin_referer('sod_bank_registry_save')) {
            $bank_key = sanitize_text_field($_POST['bank_key'] ?? '');
            $bank_val = sanitize_text_field($_POST['bank_value'] ?? '');
            $action_kind = sanitize_key($_POST['sod_bank_registry_action'] ?? '');
            if ($action_kind === 'add' && $bank_val !== '') {
                sod_add_bank_value($bank_key, $bank_val);
                echo '<div class="updated notice"><p>✅ تمت إضافة القيمة إلى بنك التعلّم.</p></div>';
            } elseif ($action_kind === 'remove' && $bank_val !== '') {
