    public static function page_news_log() {
        self::admin_wrap_open('📋 سجل الأخبار');
        self::admin_nav('strategic-osint-newslog');
        global $wpdb;
        $table = $wpdb->prefix . 'so_news_events';
        $total = (int)$wpdb->get_var("SELECT COUNT(*) FROM {$table}");
        $intel_types = $wpdb->get_col("SELECT DISTINCT intel_type FROM {$table} WHERE intel_type IS NOT NULL AND intel_type != '' ORDER BY intel_type");
        $regions     = $wpdb->get_col("SELECT DISTINCT region FROM {$table} WHERE region IS NOT NULL AND region != '' ORDER BY region");
        $actors      = $wpdb->get_col("SELECT DISTINCT actor_v2 FROM {$table} WHERE actor_v2 IS NOT NULL AND actor_v2 NOT IN ('','غير محدد','عام/مجهول') ORDER BY actor_v2 LIMIT 60");
        $nonce_search = wp_create_nonce('sod_newslog_search');
        $nonce_save   = wp_create_nonce('sod_newslog_save');
        $nonce_reclas = wp_create_nonce('sod_newslog_reclassify');
        $nonce_bulk   = wp_create_nonce('sod_newslog_bulk');
        $nonce_bank   = wp_create_nonce('sod_newslog_save');
        // جلب الجهات من البنك
        $bank_actors = $wpdb->get_col("SELECT DISTINCT name_ar FROM {$wpdb->prefix}so_dict_actors ORDER BY name_ar");
        $actors_news = $wpdb->get_col("SELECT DISTINCT actor_v2 FROM {$table} WHERE actor_v2 IS NOT NULL AND actor_v2 NOT IN ('','غير محدد','عام/مجهول') ORDER BY actor_v2 LIMIT 80");
        $bank_actors = array_values(array_unique(array_merge($bank_actors, $actors_news)));
        sort($bank_actors);
        ?>
