<script type="text/template" id="sod-newslog-inline-disabled">
(function(){
const nonces={
    search:<?php echo json_encode($nonce_search); ?>,
    save:<?php echo json_encode($nonce_save); ?>,
    reclassify:<?php echo json_encode($nonce_reclas); ?>,
    bulk:<?php echo json_encode($nonce_bulk); ?>,
    bank:<?php echo json_encode($nonce_bank); ?>
};
let currentPage=1,currentItems=[],selectedIds=new Set(),BANKS={};
function nlSetStatus(message,type='info'){
    const box=document.getElementById('nl-status-box');
    if(!box)return;
    box.className='nl-status-box active';
    box.style.borderColor=type==='error'?'#7f1d1d':(type==='success'?'#166534':'#1e3a5f');
    box.style.background=type==='error'?'#2a0f14':(type==='success'?'#0f2a1a':'#0b2038');
    box.innerHTML=message;
}
function nlUpdateStats(stats,total){
    const filtered=document.querySelector('#nl-filtered-count b');
    const classified=document.querySelector('#nl-classified-count b');
    const unclassified=document.querySelector('#nl-unclassified-count b');
    if(filtered)filtered.textContent=(total||0).toLocaleString('ar');
    if(classified)classified.textContent=((stats&&stats.classified)||0).toLocaleString('ar');
    if(unclassified)unclassified.textContent=((stats&&stats.unclassified)||0).toLocaleString('ar');
}
function nlExtractRelatedQuery(title){
    const stopWords=['في','من','على','عن','إلى','الى','مع','هذا','هذه','ذلك','تلك','بعد','قبل','حول','بين','أمام','خلال','التي','الذي','كما','عند','تم','لقد','ثم','قال','أكد','أفاد','نقل','صورة','صور','خبر'];
    const tokens=String(title||'').replace(/[^\p{L}\p{N}\s]/gu,' ').split(/\s+/).map(s=>s.trim()).filter(Boolean);
    const filtered=tokens.filter(t=>t.length>=3&&!stopWords.includes(t));
    return filtered.slice(0,4).join(' ');
}
window.nlShowRelatedNews=function(title){
    const q=nlExtractRelatedQuery(title)||String(title||'').trim();
    document.getElementById('nl-q').value=q;
    nlSetStatus('تمت تصفية سجل الأخبار حسب العنوان المرتبط: <strong>'+esc(q)+'</strong>','info');
    nlLoad(1);
};
const BANK_SELECT_MAP={types:'nl-edit-type',levels:'nl-edit-level',regions:'nl-edit-region',actors:'nl-edit-actor',targets:'nl-edit-target',contexts:'nl-edit-context',intents:'nl-edit-intent',weapons:'nl-edit-weapon'};
function refillSelect(id, values, keepValue=''){const el=document.getElementById(id);if(!el)return;const current=keepValue||el.value||'';el.innerHTML='';const empty=new Option('-- اختر --','');el.appendChild(empty);(values||[]).forEach(v=>{const o=new Option(v,v);el.appendChild(o);});if(current){for(const o of el.options){if(o.value===current||o.text===current){el.value=o.value;return;}}const o=new Option(current,current);el.appendChild(o);el.value=current;}}
function refreshBankSelects(keep={}){
    Object.entries(BANK_SELECT_MAP).forEach(([bankKey,selectId])=>{
        refillSelect(selectId,BANKS[bankKey]||[],keep[bankKey]||'');
    });
}
function loadBanks(cb){
    fetch(ajaxurl,{method:'POST',headers:{'Content-Type':'application/x-www-form-urlencoded'},body:new URLSearchParams({action:'sod_newslog_get_banks',nonce:nonces.search})})
    .then(r=>r.json()).then(d=>{
        if(d.success){
            BANKS=d.data||{};
            refreshBankSelects();
            if(cb)cb();
        } else {
            showToast('تعذّر جلب البنوك','#dc2626');
        }
    }).catch(()=>showToast('تعذّر جلب البنوك','#dc2626'));
}
let _dbt=null;function nlDebounce(){clearTimeout(_dbt);_dbt=setTimeout(()=>nlLoad(1),400);}

/* ── تحديد جماعي ── */
window.nlToggleAll=function(checked){
    document.querySelectorAll('.nl-row-check').forEach(cb=>{
        cb.checked=checked;
        const id=parseInt(cb.value);
        if(checked)selectedIds.add(id);else selectedIds.delete(id);
    });
    nlUpdateBulkBar();
};
function nlUpdateBulkBar(){
    const bar=document.getElementById('nl-bulk-bar');
    const cnt=document.getElementById('nl-sel-count');
    if(selectedIds.size>0){bar.style.display='flex';if(cnt)cnt.textContent=selectedIds.size+' مُحدد';}
    else{bar.style.display='none';}
    const sa=document.getElementById('nl-select-all');
    if(sa){const all=document.querySelectorAll('.nl-row-check');sa.checked=all.length>0&&selectedIds.size===all.length;sa.indeterminate=selectedIds.size>0&&selectedIds.size<all.length;}
}
window.nlClearSelection=function(){
    selectedIds.clear();
    document.querySelectorAll('.nl-row-check').forEach(cb=>cb.checked=false);
    const sa=document.getElementById('nl-select-all');if(sa){sa.checked=false;sa.indeterminate=false;}
    nlUpdateBulkBar();
};
window.nlBulkApply=function(){
    if(!selectedIds.size){showToast('⚠️ لم يتم تحديد أي خبر','#f59e0b');return;}
    const action=document.getElementById('nl-bulk-action').value;
    if(!action){showToast('⚠️ اختر إجراءً أولاً','#f59e0b');return;}
    if(action==='delete'&&!confirm('سيتم حذف '+selectedIds.size+' خبر نهائياً. هل أنت متأكد؟'))return;
    const ids=Array.from(selectedIds).join(',');
    fetch(ajaxurl,{method:'POST',headers:{'Content-Type':'application/x-www-form-urlencoded'},body:new URLSearchParams({action:'sod_newslog_bulk',nonce:nonces.bulk,bulk_action:action,ids})})
    .then(r=>r.json()).then(d=>{
        if(d.success){
            const n=d.data.deleted??d.data.updated??0;
            showToast('✅ تم '+(action==='delete'?'حذف':'تحديث')+' '+n+' خبر');
            selectedIds.clear();nlLoad(currentPage);
        }else showToast('⚠️ فشل: '+(d.data||''),'#dc2626');
    });
};

/* ── إضافة / حذف قيمة من البنك ── */
window.nlAddToBank=function(bank,selectId){
    const label=bank==='actor'?'الجهة الفاعلة':'القيمة';
    const val=prompt('أدخل '+label+' الجديد:','');
    if(!val||!val.trim())return;
    fetch(ajaxurl,{method:'POST',headers:{'Content-Type':'application/x-www-form-urlencoded'},body:new URLSearchParams({action:'sod_newslog_add_to_bank',nonce:nonces.bank,bank,value:val.trim()})})
    .then(r=>r.json()).then(d=>{
        if(d.success){
            BANKS=d.data.banks||BANKS;
            const keep={};
            const canon=sodBankCanon(bank);
            keep[canon]=val.trim();
            refreshBankSelects(keep);
            showToast('✅ أُضيف "'+val.trim()+'" للبنك');
        }else showToast('⚠️ فشل: '+(d.data||''),'#dc2626');
    }).catch(()=>showToast('⚠️ تعذّر الإضافة','#dc2626'));
};

function sodBankCanon(bank){
    const map={actor:'actors',type:'types',level:'levels',region:'regions',target:'targets',context:'contexts',intent:'intents',weapon:'weapons'};
    return map[bank]||bank;
}

window.nlRemoveFromBank=function(bank,selectId){
    const sel=document.getElementById(selectId);
    const val=sel?String(sel.value||'').trim():'';
    if(!val){showToast('⚠️ اختر قيمة للحذف','#f59e0b');return;}
    if(!confirm('حذف "'+val+'" من البنك؟')) return;
    fetch(ajaxurl,{method:'POST',headers:{'Content-Type':'application/x-www-form-urlencoded'},body:new URLSearchParams({action:'sod_newslog_remove_from_bank',nonce:nonces.bank,bank,value:val})})
    .then(r=>r.json()).then(d=>{
        if(d.success){
            BANKS=d.data.banks||BANKS;
            refreshBankSelects();
            showToast('🗑️ تم حذف القيمة من البنك');
        }else showToast('⚠️ فشل الحذف: '+(d.data||''),'#dc2626');
    }).catch(()=>showToast('⚠️ تعذّر الحذف','#dc2626'));
};

window.nlLoad=function(p){
    currentPage=p||1;
    const q=document.getElementById('nl-q').value.trim();
    const region=document.getElementById('nl-region').value;
    const actor=document.getElementById('nl-actor').value;
    const type=document.getElementById('nl-type').value;
    const score=document.getElementById('nl-score').value;
    const perPage=document.getElementById('nl-per-page').value;
    document.getElementById('nl-tbody').innerHTML='<tr><td colspan="9" style="text-align:center;padding:20px;color:#5a7a9a;">جاري التحميل...</td></tr>';
    fetch(ajaxurl,{method:'POST',headers:{'Content-Type':'application/x-www-form-urlencoded'},body:new URLSearchParams({action:'sod_newslog_search',nonce:nonces.search,q,region,actor,intel_type:type,score,page:currentPage,per_page:perPage})})
    .then(r=>r.json()).then(d=>{
        if(!d.success){showToast('خطأ في التحميل','#dc2626');return;}
        currentItems=d.data.items;
        renderTable(d.data.items);
        renderPager(d.data.total,d.data.page,d.data.per_page);
        nlUpdateStats(d.data.stats||{},d.data.total||0);
    }).catch(()=>showToast('تعذّر الاتصال','#dc2626'));
};
function renderTable(items){
    const tb=document.getElementById('nl-tbody');
    if(!items.length){tb.innerHTML='<tr><td colspan="9" style="text-align:center;padding:20px;color:#5a7a9a;">لا توجد نتائج</td></tr>';return;}
    tb.innerHTML=items.map((e)=>{
        const sc=parseInt(e.score||0);
        const cls=sc>=200?'nl-score-crit':sc>=140?'nl-score-high':sc>=80?'nl-score-med':'nl-score-low';
        const dt=e.event_timestamp?new Date(e.event_timestamp*1000).toLocaleString('ar',{year:'2-digit',month:'2-digit',day:'2-digit',hour:'2-digit',minute:'2-digit'}):'—';
        const learned=e.has_learning?'<span class="nl-learning-badge">✓ تعلّم</span>':'';
        const chk=selectedIds.has(parseInt(e.id))?'checked':'';
        const chips = [
            ['استراتيجي', e.intel_type],
            ['تكتيكي', e.tactical_level],
            ['منطقة', e.region],
            ['فاعل', e.actor_v2],
            ['هدف', e.target_v2],
            ['سياق', e.context_actor],
            ['نية', e.intent],
            ['سلاح', e.weapon_v2]
        ].filter(x => x[1] && String(x[1]).trim() && String(x[1]).trim() !== 'غير محدد' && String(x[1]).trim() !== '—')
         .map(x => `<span class="nl-mini-chip"><b>${esc(x[0])}:</b> ${esc(String(x[1]).substring(0,42))}</span>`).join('');
        return `<tr id="nl-row-${e.id}">
            <td style="text-align:center;"><input type="checkbox" class="nl-row-check" value="${e.id}" ${chk} style="cursor:pointer;accent-color:#2563eb;width:14px;height:14px;" onchange="nlRowCheck(this,${e.id})"></td>
            <td style="color:#5a7a9a;font-size:11px;white-space:nowrap;">${dt}</td>
            <td style="max-width:420px;">
                <a href="#" class="nl-title-link" data-related="${encodeURIComponent(String(e.title||''))}" onclick="event.preventDefault();nlShowRelatedNews(decodeURIComponent(this.dataset.related||''))" title="${esc(e.title)}">${esc(e.title.substring(0,100))}${e.title.length>100?'...':''}</a>${learned}
                ${chips ? `<div class="nl-meta-stack">${chips}</div>` : ''}
            </td>
            <td><span class="nl-badge">${esc(e.source_name||'—')}</span></td>
            <td style="font-size:11px;">${esc(e.intel_type||'—')}</td>
            <td style="font-size:11px;">${esc(e.region||'—')}</td>
            <td style="font-size:11px;color:#94a3b8;" title="${esc(e.actor_v2||'—')}">${esc(e.actor_v2||'—')}</td>
            <td><span class="nl-score ${cls}">${sc}</span></td>
            <td style="white-space:nowrap;">
                <button class="nl-btn nl-btn-primary nl-btn-sm" onclick="nlOpenEditById(${e.id})">✏️</button>
                <button class="nl-btn nl-btn-success nl-btn-sm" onclick='nlReclassifyOneDirect(${e.id})' title="إعادة تصنيف">⚙️</button>
            </td>
        </tr>`;
    }).join('');
}
function nlRowCheck(cb,id){
    if(cb.checked)selectedIds.add(parseInt(id));else selectedIds.delete(parseInt(id));
    nlUpdateBulkBar();
}
function renderPager(total,page,perPage){
    const pages=Math.ceil(total/perPage);
    const wrap=document.getElementById('nl-pager');
    if(pages<=1){wrap.innerHTML='';return;}
    let html='';
    const start=Math.max(1,page-3),end=Math.min(pages,page+3);
    if(start>1)html+=`<button class="nl-page-btn" onclick="nlLoad(1)">«</button>`;
    for(let i=start;i<=end;i++)html+=`<button class="nl-page-btn${i===page?' active':''}" onclick="nlLoad(${i})">${i}</button>`;
    if(end<pages)html+=`<button class="nl-page-btn" onclick="nlLoad(${pages})">»</button>`;
    wrap.innerHTML=html;
}
function esc(s){return String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');}
window.nlOpenEditById=function(id){const e=currentItems.find(x=>+x.id===+id);if(!e){showToast('⚠️ لم يُعثر على العنصر','#dc2626');return;}nlOpenEdit(e);};
window.nlOpenEdit=function(e){
    document.getElementById('nl-edit-id').value=e.id;
    document.getElementById('nl-edit-title').value=e.title||'';
    let wd={};
    try{ wd=JSON.parse(e.war_data||'{}')||{}; }catch(x){ wd={}; }
    refreshBankSelects({
        types:e.intel_type||'',
        levels:e.tactical_level||'',
        regions:e.region||'',
        actors:e.actor_v2||'',
        weapons:wd.weapon_means||e.weapon_v2||'',
        targets:wd.target||e.target_v2||'',
        contexts:wd.context_actor||e.context_actor||'',
        intents:wd.intent||e.intent||''
    });
    document.getElementById('nl-edit-score').value=e.score||0;
    setSelect('nl-edit-status',e.status||'published');
    const evalEl=document.getElementById('nl-edit-evaluation');
    if(evalEl){evalEl.textContent=(e.has_manual_override?'يدوي مقفل':'آخر تقييم: '+(e.evaluation_label||'آلي'));evalEl.style.display='block';}
    document.getElementById('nl-modal').classList.add('open');
};
function setSelect(id,val){const el=document.getElementById(id);if(!el)return;for(const o of el.options){if(o.value===val||o.text===val){el.value=o.value;return;}}};
window.nlCloseModal=function(){document.getElementById('nl-modal').classList.remove('open');};
window.nlSaveItem=function(){
    const id=document.getElementById('nl-edit-id').value;
    const data={action:'sod_newslog_save',nonce:nonces.save,id,
        title:document.getElementById('nl-edit-title').value,
        intel_type:document.getElementById('nl-edit-type').value,
        tactical_level:document.getElementById('nl-edit-level').value,
        region:document.getElementById('nl-edit-region').value,
        actor_v2:document.getElementById('nl-edit-actor').value,
        score:document.getElementById('nl-edit-score').value,
        status:document.getElementById('nl-edit-status').value,
        weapon_v2:document.getElementById('nl-edit-weapon').value,
        target_v2:document.getElementById('nl-edit-target').value,
        context_actor:document.getElementById('nl-edit-context').value,
        intent:document.getElementById('nl-edit-intent').value,
    };
    nlSetStatus('جارٍ حفظ التعديل اليدوي...', 'info');
    fetch(ajaxurl,{method:'POST',headers:{'Content-Type':'application/x-www-form-urlencoded'},body:new URLSearchParams(data)})
    .then(r=>r.json()).then(d=>{
        if(d.success){showToast('✅ تم الحفظ والتعلم');nlCloseModal();nlLoad(currentPage);}
        else showToast('⚠️ فشل الحفظ: '+(d.data||''),'#dc2626');
    });
};
window.nlReclassifyOne=function(){
    const id=document.getElementById('nl-edit-id').value;
    nlReclassifyOneDirect(id);
};
window.nlReclassifyOneDirect=function(id){
    fetch(ajaxurl,{method:'POST',headers:{'Content-Type':'application/x-www-form-urlencoded'},body:new URLSearchParams({action:'sod_newslog_reclassify',nonce:nonces.reclassify,id,mode:'single'})})
    .then(r=>r.json()).then(d=>{
        if(d.success){showToast('⚙️ أعيد التصنيف بنجاح');nlCloseModal();nlLoad(currentPage);}
        else showToast('فشل إعادة التصنيف: '+(typeof d.data==='string'?d.data:JSON.stringify(d.data||'')),'#dc2626',6000);
    });
};
window.nlBulkReclassify=function(){
    if(!selectedIds.size){showToast('⚠️ لم تُحدد أي عناصر','#f59e0b');return;}
    if(!confirm('سيتم إعادة التصنيف الآلي لـ '+selectedIds.size+' خبر. هل تريد المتابعة؟'))return;
    showToast('⚙️ جارٍ إعادة التصنيف...','#2563eb',8000);
    const ids=Array.from(selectedIds);
    let done=0,errors=0;
    function next(){
        if(!ids.length){
            showToast('✅ أُعيد تصنيف '+(done)+' — أخطاء: '+errors,'#16a34a',4000);
            nlClearSelection();nlLoad(currentPage);return;
        }
        const id=ids.shift();
        fetch(ajaxurl,{method:'POST',headers:{'Content-Type':'application/x-www-form-urlencoded'},body:new URLSearchParams({action:'sod_newslog_reclassify',nonce:nonces.reclassify,id,mode:'single'})})
        .then(r=>r.json()).then(d=>{d.success?done++:errors++;next();}).catch(()=>{errors++;next();});
    }
    next();
};
window.nlReclassifyAll=function(){
    if(!confirm('سيتم إعادة تصنيف جميع الأخبار. هذه العملية قد تستغرق وقتاً. هل تريد المتابعة؟'))return;
    showToast('⚙️ جارٍ إعادة التصنيف... يرجى الانتظار','#2563eb',5000);
    fetch(ajaxurl,{method:'POST',headers:{'Content-Type':'application/x-www-form-urlencoded'},body:new URLSearchParams({action:'sod_newslog_reclassify',nonce:nonces.reclassify,mode:'all'})})
    .then(r=>r.json()).then(d=>{
        if(d.success){showToast('✅ أعيد تصنيف '+d.data.updated+' خبر بنجاح');}
        else showToast('فشل إعادة التصنيف: '+(typeof d.data==='string'?d.data:JSON.stringify(d.data||'')),'#dc2626',6000);
        nlLoad(currentPage);
    });
};
window.nlReclassifyAll=function(){
    if(!confirm('سيتم إعادة تصنيف جميع الأخبار. هذه العملية قد تستغرق وقتًا. هل تريد المتابعة؟'))return;
    showToast('جارٍ إعادة التصنيف...','#2563eb',5000);
    fetch(ajaxurl,{method:'POST',headers:{'Content-Type':'application/x-www-form-urlencoded'},body:new URLSearchParams({action:'sod_newslog_reclassify',nonce:nonces.reclassify,mode:'all'})})
    .then(r=>r.json()).then(d=>{
        if(d.success){
            const s=d.data.stats||{};
            nlSetStatus(
                'تمت إعادة تصنيف <strong>'+((d.data.updated)||0).toLocaleString('ar')+
                '</strong> خبر. المصنّف الآن: <strong>'+((s.classified_after)||0).toLocaleString('ar')+
                '</strong>، وغير المحسوم: <strong>'+((s.unclassified_after)||0).toLocaleString('ar')+
                '</strong>. قبل العملية كان غير المحسوم <strong>'+((s.unclassified_before)||0).toLocaleString('ar')+'</strong>.',
                'success'
            );
            showToast('تمت إعادة التصنيف بنجاح');
        }else{
            showToast('فشل إعادة التصنيف: '+(typeof d.data==='string'?d.data:JSON.stringify(d.data||'')),'#dc2626',6000);
        }
        nlLoad(currentPage);
    }).catch(()=>showToast('تعذر تنفيذ إعادة التصنيف','#dc2626',6000));
};
