// ==========================================================================
// 24. SO_V7_Upgrade — جداول الكيانات والمواقع الجغرافية
// ==========================================================================
if (!class_exists('SO_V7_Upgrade')) {
class SO_V7_Upgrade {
    public static function maybe_upgrade() {
        $installed = get_option('so_db_version', '0');
        if (version_compare((string)$installed, '7.0.0', '<')) {
            self::create_additional_tables();
            update_option('so_db_version', SOD_VERSION);
        }
        // Always ensure entity banks are seeded (idempotent — uses edge_hash unique key)
        if (!get_option('so_entity_banks_seeded_v17', false)) {
            self::seed_entity_banks();
            update_option('so_entity_banks_seeded_v17', true);
        }
        // Ensure title_fingerprint column exists for installs upgraded through multiple versions
        global $wpdb;
        $cols = $wpdb->get_col("SHOW COLUMNS FROM {$wpdb->prefix}so_news_events");
        if (is_array($cols) && !in_array('title_fingerprint', $cols, true)) {
            $wpdb->query("ALTER TABLE {$wpdb->prefix}so_news_events ADD COLUMN title_fingerprint varchar(64) DEFAULT NULL, ADD KEY title_fp (title_fingerprint)");
        }
    }
    public static function create_additional_tables() {
        global $wpdb;
        require_once ABSPATH . 'wp-admin/includes/upgrade.php';
        // Add title_fingerprint to existing so_news_events if missing
        $cols = $wpdb->get_col("SHOW COLUMNS FROM {$wpdb->prefix}so_news_events");
        if (is_array($cols) && !in_array('title_fingerprint', $cols, true)) {
            $wpdb->query("ALTER TABLE {$wpdb->prefix}so_news_events ADD COLUMN title_fingerprint varchar(64) DEFAULT NULL, ADD KEY title_fp (title_fingerprint)");
        }
        $c = $wpdb->get_charset_collate();
        dbDelta("CREATE TABLE {$wpdb->prefix}so_entity_graph (
            id bigint(20) NOT NULL AUTO_INCREMENT,
            edge_hash varchar(64) NOT NULL,
            actor_name varchar(191) NOT NULL,
            target_name varchar(191) NOT NULL,
            region varchar(100) DEFAULT '',
            weight float DEFAULT 0,
            event_count int(11) DEFAULT 1,
            first_seen bigint(20) NOT NULL,
            last_seen bigint(20) NOT NULL,
            PRIMARY KEY (id),
            UNIQUE KEY edge_hash (edge_hash),
            KEY actor_name (actor_name),
            KEY target_name (target_name),
            KEY last_seen (last_seen)
        ) $c;");
        dbDelta("CREATE TABLE {$wpdb->prefix}so_geo_cache (
            id bigint(20) NOT NULL AUTO_INCREMENT,
            place_hash varchar(64) NOT NULL,
            place_name varchar(191) NOT NULL,
            lat decimal(10,6) DEFAULT NULL,
            lon decimal(10,6) DEFAULT NULL,
            confidence float DEFAULT 0,
            source varchar(50) DEFAULT 'seed',
            updated_at bigint(20) NOT NULL,
            PRIMARY KEY (id),
            UNIQUE KEY place_hash (place_hash),
            KEY place_name (place_name)
        ) $c;");
        self::seed_geo_cache();
        self::seed_entity_banks();
        self::rebuild_entity_graph();
    }

    // -----------------------------------------------------------------------
    // بيانات البنوك الاستخباراتية الشاملة — أشخاص، أماكن، أسلحة، عمليات
    // -----------------------------------------------------------------------
