    public static function rebuild_entity_graph($limit = 500) {
        global $wpdb;
        $events = $wpdb->get_results($wpdb->prepare("SELECT id,actor_v2,region,event_timestamp,war_data FROM {$wpdb->prefix}so_news_events ORDER BY event_timestamp DESC LIMIT %d",$limit),ARRAY_A);
        if (empty($events)) return;
        foreach ($events as $ev) {
            $war = json_decode((string)$ev['war_data'],true);
            $actor = sanitize_text_field(so_normalize_actor_label($ev['actor_v2'] ?: ($war['actor'] ?? 'فاعل قيد التقييم')));
            $targets = [];
            if (!empty($war['target'])) $targets = array_filter(array_map('trim',explode(',',(string)$war['target'])));
            if (empty($targets)) $targets = [sanitize_text_field($ev['region'] ?: 'غير محدد')];
            foreach ($targets as $tgt) {
                self::upsert_edge($actor,$tgt,(string)$ev['region'],(int)$ev['event_timestamp'],1.0);
            }
        }
    }
    public static function upsert_edge($actor,$target,$region,$ts,$w=1.0) {
        global $wpdb;
        $actor=sanitize_text_field((string)$actor); $target=sanitize_text_field((string)$target);
        if ($actor===''||$target==='') return;
        $hash=md5(mb_strtolower($actor.'|'.$target.'|'.$region));
        $t="{$wpdb->prefix}so_entity_graph";
        $row=$wpdb->get_row($wpdb->prepare("SELECT * FROM $t WHERE edge_hash=%s",$hash),ARRAY_A);
        if ($row) {
            $wpdb->update($t,['weight'=>(float)$row['weight']+(float)$w,'event_count'=>(int)$row['event_count']+1,'last_seen'=>$ts],['id'=>(int)$row['id']]);
        } else {
            $wpdb->insert($t,['edge_hash'=>$hash,'actor_name'=>$actor,'target_name'=>$target,'region'=>$region,'weight'=>$w,'event_count'=>1,'first_seen'=>$ts,'last_seen'=>$ts]);
        }
    }
}
