if (!class_exists('SO_V11_INSIDE_PBI_DASHBOARD')) {
class SO_V11_INSIDE_PBI_DASHBOARD {
    public static function init() {
        add_action('wp_ajax_so_v11_inside_pbi_snapshot',[__CLASS__,'ajax_snapshot']);
        // تم إزالة wp_ajax_nopriv - يتطلب الآن صلاحيات مستخدم
        add_action('wp_footer',[__CLASS__,'render_assets'],130);
    }
    public static function recent_events($limit=25) {
        global $wpdb;
        $rows=$wpdb->get_results($wpdb->prepare("SELECT id,title,region,actor_v2,score,event_timestamp,status FROM {$wpdb->prefix}so_news_events WHERE status='published' ORDER BY event_timestamp DESC LIMIT %d",max(1,intval($limit))),ARRAY_A);
        return is_array($rows)?$rows:[];
    }
    public static function ajax_snapshot() {
        if (!current_user_can('read')) { wp_send_json_error(['message'=>'غير مصرح'],403); }
        $events=self::recent_events(25);
        foreach($events as &$e){$e['title']=wp_strip_all_tags((string)($e['title']??''));$e['region']=sanitize_text_field((string)($e['region']??'غير محدد'));$e['actor_v2']=sanitize_text_field((string)($e['actor_v2']??'غير محدد'));$e['score']=intval($e['score']??0);}
        wp_send_json_success(['events'=>$events]);
    }
    public static function render_assets() {
        if (is_admin()) return;
        $ajaxurl=admin_url('admin-ajax.php');
        ?>
        <style>
        [id^="pbi-dashboard-"]{position:relative!important}
        .so-v11-pbi-live-box{position:absolute;top:84px;left:14px;width:320px;max-width:calc(100% - 28px);z-index:25;background:#07101b;color:#e6f3ff;border:1px solid rgba(93,149,255,.25);border-radius:18px;box-shadow:0 10px 32px rgba(0,0,0,.35);overflow:hidden;backdrop-filter:blur(6px);}
        .so-v11-pbi-live-box.collapsed .so-v11-pbi-live-body{display:none}
        .so-v11-pbi-live-hd{padding:14px 16px 10px;border-bottom:1px solid rgba(255,255,255,.07);background:linear-gradient(180deg,rgba(11,18,32,.96),rgba(7,16,27,.94));display:flex;align-items:flex-start;justify-content:space-between;gap:8px;}
        .so-v11-pbi-live-title{color:#fff;font-size:20px;line-height:1.1;font-weight:700;}
        .so-v11-pbi-live-sub{color:#93c5fd;font-size:11px;display:block;margin-top:4px;}
        .so-v11-pbi-live-ctrls{display:flex;gap:6px;align-items:center;}
        .so-v11-pbi-btn{background:#111827;color:#fff;border:1px solid #374151;border-radius:9px;padding:4px 8px;cursor:pointer;font-size:11px;line-height:1.2;}
        .so-v11-pbi-live-body{padding:10px 10px 12px;max-height:500px;overflow:auto;display:flex;flex-direction:column;gap:8px;}
        .so-v11-pbi-item{border:1px solid #20324f;border-radius:12px;background:#050c15;padding:10px 12px;line-height:1.65;}
        .so-v11-pbi-item .t{color:#fff;font-weight:700;font-size:13px;margin-bottom:5px;}
        .so-v11-pbi-item .m{color:#9ec9ff;font-size:11px;margin-bottom:3px;}
        .so-v11-pbi-item .s{color:#f6d365;font-size:11px;}
        @media(max-width:768px){.so-v11-pbi-live-box{top:64px;left:8px;width:280px;}.so-v11-pbi-live-body{max-height:280px;}}
        </style>
        <script>
        (function(){
            const ajaxUrl=<?php echo wp_json_encode($ajaxurl);?>;
            const CLOSED_KEY='so_v11_pbi_closed';
            const SEEN_KEY='so_v11_pbi_seen';
            // Load seen IDs from sessionStorage to persist across polls without page-reload duplication
            let seen={};
            try{const s=sessionStorage.getItem(SEEN_KEY);if(s)seen=JSON.parse(s);}catch(e){}
            function saveSeen(){try{sessionStorage.setItem(SEEN_KEY,JSON.stringify(seen));}catch(e){}}
            function isClosed(){return sessionStorage.getItem(CLOSED_KEY)==='1';}
            function markClosed(){sessionStorage.setItem(CLOSED_KEY,'1');}
            function scoreBorder(s){return s>=400?'#ef4444':s>=250?'#f59e0b':'#20324f';}
            function makeCard(e){const d=document.createElement('div');d.className='so-v11-pbi-item';d.style.borderColor=scoreBorder(e.score||0);d.innerHTML='<div class="t">'+(e.title||'')+'</div><div class="m">📍 '+(e.region||'غير محدد')+' — '+(e.actor_v2||'غير محدد')+'</div><div class="s">درجة: '+(e.score||0)+'</div>';return d;}
            function ensureBoxes(){
                if(isClosed())return[]; // user closed — do NOT recreate until next page session
                const dashes=document.querySelectorAll('[id^="pbi-dashboard-"]');
                if(!dashes.length)return[];
                const boxes=[];
                dashes.forEach((dash)=>{
                    let box=dash.querySelector('.so-v11-pbi-live-box');
                    if(box){boxes.push(box);return;}
                    box=document.createElement('aside');
                    box.className='so-v11-pbi-live-box';
                    box.innerHTML='<div class="so-v11-pbi-live-hd"><div><div class="so-v11-pbi-live-title">⚡ Live Intelligence</div><span class="so-v11-pbi-live-sub">شريط استخباري مباشر</span></div><div class="so-v11-pbi-live-ctrls"><button class="so-v11-pbi-btn so-v11-pbi-collapse">طي</button><button class="so-v11-pbi-btn so-v11-pbi-close">إغلاق</button></div></div><div class="so-v11-pbi-live-body"></div>';
                    dash.style.position='relative';
                    dash.appendChild(box);
                    box.querySelector('.so-v11-pbi-collapse').addEventListener('click',()=>box.classList.toggle('collapsed'));
                    box.querySelector('.so-v11-pbi-close').addEventListener('click',()=>{
                        box.remove();
                        markClosed(); // persists closed state for this browser session
                    });
                    boxes.push(box);
                });
                return boxes;
            }
            function poll(){
                if(isClosed())return; // skip polling entirely when closed
                const fd=new FormData();fd.append('action','so_v11_inside_pbi_snapshot');
                fetch(ajaxUrl,{method:'POST',body:fd,credentials:'same-origin'}).then(r=>r.text().then(t=>{
                    try{return JSON.parse(t);}catch(e){
                        const trimmed=String(t||'').trim();const start=trimmed.indexOf('{');
                        if(start>=0){return JSON.parse(trimmed.slice(start));}
                        throw e;
                    }
                })).then(json=>{
                    if(!json.success||!json.data||!json.data.events)return;
                    if(isClosed())return;
                    const boxes=ensureBoxes();if(!boxes.length)return;
                    let added=false;
                    json.data.events.forEach(e=>{
                        if(seen[e.id])return;
                        seen[e.id]=true;added=true;
                        boxes.forEach(box=>{
                            const body=box.querySelector('.so-v11-pbi-live-body');
                            if(!body)return;
                            body.insertBefore(makeCard(e),body.firstChild);
                            if(body.children.length>12)body.removeChild(body.lastChild);
                        });
                    });
                    if(added)saveSeen();
                }).catch(()=>{});
            }
            document.addEventListener('DOMContentLoaded',()=>{poll();setInterval(poll,45000);});
        })();
        </script>
        <?php
    }
}
}

