<!-- COMMAND DECK CSS -->
<style>
.sod-cd-wrap{font-family:'Cairo','Tajawal',sans-serif!important;direction:rtl!important;background:#05080f;color:#cde;border-radius:14px;overflow:hidden;box-shadow:0 0 40px rgba(0,0,0,.8);margin:0 0 24px;width:100%!important;max-width:100%!important;position:relative;isolation:isolate;}
.sod-cd-wrap *{box-sizing:border-box;}
:root{--cd-blue:#1e3a5f;--cd-accent:#3b82f6;--cd-crit:#ef4444;--cd-warn:#f59e0b;--cd-ok:#22c55e;--cd-text:#c8dff2;--cd-sub:#5a7a9a;--cd-bg:#080e1a;--cd-card:#0a1628;--cd-card2:#0d1f3c;--cd-border:#1e3a5f;}
/* Header */
.sod-cd-header{display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:12px;padding:14px 20px;background:linear-gradient(135deg,#030810,#0a1628);border-bottom:2px solid #1e3a5f;position:relative;z-index:10;}
.sod-cd-brand{display:flex;align-items:center;gap:12px;}
.sod-cd-brand-icon{font-size:clamp(22px,3vw,32px);filter:drop-shadow(0 0 10px #3b82f6);}
.sod-cd-brand-title{display:block;font-size:clamp(12px,2vw,17px);font-weight:900;color:#e0f2ff;letter-spacing:.04em;}
.sod-cd-brand-sub{display:block;font-size:10px;color:#4a6a8a;font-weight:400;}
.sod-cd-live-badge{display:flex;align-items:center;gap:5px;background:#0a200a;border:1px solid #2d6a2d;border-radius:20px;padding:4px 10px;font-size:11px;font-weight:700;color:#6fbf73;letter-spacing:.08em;}
.sod-cd-live-dot{width:7px;height:7px;background:#22c55e;border-radius:50%;animation:cd-blink 1.4s ease-in-out infinite;}
@keyframes cd-blink{0%,100%{opacity:1;box-shadow:0 0 4px #22c55e}50%{opacity:.2;box-shadow:none}}
.sod-cd-header-center{text-align:center;}
.sod-cd-clock{font-size:clamp(18px,3vw,28px);font-weight:900;color:#e0f2ff;font-variant-numeric:tabular-nums;letter-spacing:.08em;font-family:monospace,Cairo;}
.sod-cd-date{font-size:11px;color:#4a6a8a;}
.sod-cd-header-actions{display:flex;align-items:center;gap:8px;flex-wrap:wrap;}
.sod-cd-filter-group{display:flex;align-items:center;gap:5px;}
.sod-cd-filter-group label{font-size:11px;color:#5a7a9a;}
.sod-cd-sel{background:#0d1f3c!important;border:1px solid #1e3a5f!important;color:#e0f2ff!important;padding:5px 8px!important;border-radius:8px!important;font-size:12px!important;font-family:'Cairo','Tajawal',sans-serif!important;cursor:pointer!important;box-shadow:none!important;appearance:auto;-webkit-appearance:auto;height:auto!important;}
.sod-cd-sel-sm{padding:3px 6px;font-size:11px;}
.sod-cd-btn{background:linear-gradient(135deg,#1d4ed8,#2563eb)!important;color:#fff!important;border:none!important;padding:6px 12px!important;border-radius:8px!important;cursor:pointer!important;font-size:12px!important;font-family:'Cairo','Tajawal',sans-serif!important;font-weight:600;transition:.2s;white-space:nowrap;box-shadow:none!important;outline:none;text-decoration:none!important;line-height:1.4!important;}
.sod-cd-btn:hover{filter:brightness(1.15);transform:translateY(-1px);}
.sod-cd-loading{font-size:16px;animation:cd-blink .8s infinite;}
/* Print menu */
.sod-cd-print-wrap{position:relative;}
.sod-cd-print-toggle{background:linear-gradient(135deg,#0f4c75,#1b6ca8);}
.sod-cd-print-menu{display:none;position:absolute;top:calc(100% + 4px);left:0;background:#0a1628;border:1px solid #1e3a5f;border-radius:10px;min-width:170px;z-index:99999;padding:6px;box-shadow:0 8px 24px rgba(0,0,0,.7);}
.sod-cd-print-menu.open{display:block;}
.sod-cd-pmenu-item{display:block!important;width:100%!important;text-align:right!important;background:transparent!important;border:none!important;color:#c8dff2!important;padding:7px 12px!important;border-radius:6px!important;cursor:pointer!important;font-size:12px!important;font-family:'Cairo','Tajawal',sans-serif!important;transition:.15s;box-shadow:none!important;outline:none;line-height:1.5!important;}
.sod-cd-pmenu-item:hover{background:rgba(59,130,246,.15);color:#fff;}
/* Alert strip */
.sod-cd-alert-strip{display:flex;align-items:center;background:#1a0808;border-bottom:1px solid #7f1d1d;height:34px;overflow:hidden;}
.sod-cd-alert-icon{background:#ef4444;color:#fff;padding:0 14px;height:100%;display:flex;align-items:center;font-size:12px;font-weight:700;white-space:nowrap;flex-shrink:0;}
.sod-cd-alert-ticker{flex:1;overflow:hidden;position:relative;height:34px;}
.sod-cd-alert-inner{position:absolute;top:0;right:0;width:100%;will-change:transform;}
.sod-cd-alert-inner:hover{animation-play-state:paused;}
.sod-cd-alert-vitem{display:flex;align-items:center;gap:8px;padding:4px 14px;border-bottom:1px solid rgba(127,29,29,.3);height:34px;overflow:hidden;}
@keyframes cd-marquee-up{0%{transform:translateY(0);}100%{transform:translateY(-50%);}}
/* KPI row */
.sod-cd-kpi-row{display:grid;grid-template-columns:repeat(6,1fr);gap:10px;padding:14px;background:#060c16;border-bottom:1px solid #1e3a5f;}
.sod-cd-kpi{background:linear-gradient(135deg,#0a1628,#0d1f3c);border:1px solid #1e3a5f;border-radius:12px;padding:12px 14px;display:flex;align-items:flex-start;gap:10px;position:relative;overflow:hidden;transition:.25s;}
.sod-cd-kpi::before{content:'';position:absolute;top:0;left:0;right:0;height:3px;border-radius:12px 12px 0 0;}
.kpi-total::before{background:#3b82f6;}.kpi-crit::before{background:#ef4444;}.kpi-avg::before{background:#f59e0b;}.kpi-peak::before{background:#f97316;}.kpi-region::before{background:#8b5cf6;}.kpi-actor::before{background:#22c55e;}
.sod-cd-kpi:hover{transform:translateY(-2px);box-shadow:0 8px 20px rgba(0,0,0,.5);}
.sod-cd-kpi-icon{font-size:22px;flex-shrink:0;margin-top:2px;}
.sod-cd-kpi-body{flex:1;min-width:0;}
.sod-cd-kpi-val{font-size:clamp(16px,2.5vw,24px);font-weight:900;color:#e0f2ff;line-height:1.1;}
.sod-cd-kpi-val-sm{font-size:clamp(10px,1.2vw,13px);overflow:hidden;text-overflow:ellipsis;white-space:nowrap;max-width:100%;display:block;}
.kpi-crit .sod-cd-kpi-val{color:#ef4444;}.kpi-avg .sod-cd-kpi-val{color:#f59e0b;}.kpi-peak .sod-cd-kpi-val{color:#f97316;}
.sod-cd-kpi-lbl{font-size:10px;color:#5a7a9a;font-weight:600;margin-top:3px;}
.sod-cd-kpi-sub{font-size:10px;color:#3a5a7a;margin-top:2px;}
/* Cards */
.sod-cd-card{background:linear-gradient(135deg,#080e1a,#0a1628);border:1px solid #1e3a5f;border-radius:12px;overflow:hidden;}
.sod-cd-card-hdr{padding:10px 14px;font-size:13px;font-weight:700;color:#e0f2ff;background:rgba(0,0,0,.25);border-bottom:1px solid #1e3a5f;display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:6px;}
.sod-cd-card-hdr-right{display:flex;align-items:center;gap:6px;flex-wrap:wrap;}
.sod-cd-chip{background:#0d1f3c!important;border:1px solid #1e3a5f!important;color:#7aa0c4!important;padding:3px 8px!important;border-radius:6px!important;cursor:pointer!important;font-size:11px!important;font-family:'Cairo','Tajawal',sans-serif!important;transition:.15s;box-shadow:none!important;outline:none;text-decoration:none!important;line-height:1.4!important;}
.sod-cd-chip.active,.sod-cd-chip:hover{background:#1d4ed8;border-color:#2563eb;color:#fff;}
/* Gauge */
.sod-cd-main-grid{display:grid;grid-template-columns:280px 1fr;gap:14px;padding:14px;}
.sod-cd-gauge-card{display:flex;flex-direction:column;}
.sod-cd-gauge-wrap{padding:14px;display:flex;flex-direction:column;align-items:center;flex:1;}
.sod-cd-gauge-svg{width:100%;max-width:220px;}
.sod-cd-gauge-label{font-size:20px;font-weight:900;margin-top:8px;}
.sod-cd-gauge-sub{font-size:11px;color:#5a7a9a;margin-top:4px;text-align:center;}
.sod-cd-trend-row{display:flex;align-items:center;gap:8px;padding:10px 14px;border-top:1px solid #1e3a5f;}
.sod-cd-trend-lbl{font-size:11px;color:#5a7a9a;white-space:nowrap;}
.sod-cd-trend-bars{display:flex;align-items:flex-end;gap:3px;flex:1;height:28px;}
.sod-cd-trend-bar{width:100%;border-radius:2px 2px 0 0;transition:.3s;}
.sod-cd-trend-val{font-size:11px;font-weight:700;white-space:nowrap;}
.sod-cd-timeline-card{display:flex;flex-direction:column;}
.sod-cd-chart-wrap{padding:12px;flex:1;min-height:180px;position:relative;}
.sod-cd-chart-sm{min-height:160px;}
/* Analytics */
.sod-cd-analytics-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:14px;padding:0 14px 14px;}
/* Feed */
.sod-cd-feed-card{margin:0 14px 14px;}
.sod-cd-feed-wrap{max-height:420px;overflow-y:auto;}
.sod-cd-feed-table{width:100%;border-collapse:collapse;font-size:12px;}
.sod-cd-feed-table thead th{background:#0d1f3c;color:#9db4c8;padding:8px 10px;text-align:right;font-size:11px;position:sticky;top:0;z-index:1;border-bottom:2px solid #1e3a5f;}
.sod-cd-feed-table tbody tr{border-bottom:1px solid rgba(30,58,95,.3);cursor:pointer;transition:.15s;}
.sod-cd-feed-table tbody tr:hover{background:rgba(59,130,246,.08);}
.sod-cd-feed-table tbody td{padding:7px 10px;vertical-align:top;}
.sod-cd-loading-row{text-align:center;color:#5a7a9a;padding:20px!important;}
.sod-cd-score-badge{display:inline-block;padding:2px 8px;border-radius:6px;font-size:11px;font-weight:700;}
.score-crit{background:rgba(239,68,68,.2);color:#fca5a5;border:1px solid rgba(239,68,68,.3);}
.score-warn{background:rgba(245,158,11,.2);color:#fcd34d;border:1px solid rgba(245,158,11,.3);}
.score-ok{background:rgba(34,197,94,.2);color:#86efac;border:1px solid rgba(34,197,94,.3);}
.sod-cd-feed-footer{display:flex;justify-content:space-between;align-items:center;padding:8px 14px;border-top:1px solid #1e3a5f;background:rgba(0,0,0,.2);}
.sod-cd-pagination{display:flex;gap:4px;flex-wrap:wrap;}
.sod-cd-pg-btn{background:#0d1f3c!important;border:1px solid #1e3a5f!important;color:#7aa0c4!important;padding:3px 8px!important;border-radius:5px!important;cursor:pointer!important;font-size:11px!important;font-family:monospace!important;min-width:28px;box-shadow:none!important;}
.sod-cd-pg-btn.active,.sod-cd-pg-btn:hover{background:#1d4ed8!important;border-color:#2563eb!important;color:#fff!important;}
.sod-cd-last-update{font-size:11px;color:#3a5a7a;}
.sod-cd-search{background:#0d1f3c!important;border:1px solid #1e3a5f!important;color:#e0f2ff!important;padding:4px 8px!important;border-radius:7px!important;font-size:12px!important;font-family:'Cairo','Tajawal',sans-serif!important;width:140px;outline:none!important;box-shadow:none!important;}
.sod-cd-feed-count{font-size:11px;color:#5a7a9a;}
.sod-cd-title-link{color:#dbeafe!important;text-decoration:none!important;border-bottom:1px dashed rgba(125,211,252,.35);}
.sod-cd-title-link:hover{color:#fff!important;border-bottom-color:#7dd3fc;}
.sod-cd-meta-stack{display:flex;flex-wrap:wrap;gap:6px;margin-top:6px;}
.sod-cd-mini-chip{display:inline-flex;align-items:center;gap:4px;background:rgba(15,23,42,.9);border:1px solid rgba(51,65,85,.9);border-radius:999px;padding:2px 8px;font-size:10px;color:#9db4c8;max-width:100%;}
.sod-cd-mini-chip b{color:#e2e8f0;font-weight:700;}
/* Brief */
.sod-cd-brief-card{margin:0 14px 14px;}
.sod-cd-brief-body{display:grid;grid-template-columns:repeat(auto-fit,minmax(200px,1fr));gap:14px;padding:14px;}
.sod-cd-brief-placeholder{color:#5a7a9a;font-size:13px;padding:20px;text-align:center;grid-column:1/-1;}
.sod-cd-brief-section{background:rgba(0,0,0,.2);border-right:3px solid #3b82f6;border-radius:8px;padding:12px 14px;}
.sod-cd-brief-section-title{font-size:12px;font-weight:700;color:#7dd3fc;margin-bottom:8px;letter-spacing:.04em;}
.sod-cd-brief-line{display:flex;justify-content:space-between;align-items:baseline;gap:6px;font-size:12px;color:#9db4c8;padding:4px 0;border-bottom:1px solid rgba(148,163,184,.07);}
.sod-cd-brief-card,.so-ai-btn{display:none!important;}
/* Print header */
.sod-cd-print-hdr{display:none;padding:16px 20px;border-bottom:2px solid #000;margin-bottom:16px;justify-content:space-between;align-items:flex-start;}
/* Modal */
.sod-cd-modal{display:none;position:fixed;inset:0;background:rgba(0,0,0,.7);z-index:999999;align-items:center;justify-content:center;}
.sod-cd-modal.open{display:flex;}
.sod-cd-modal-box{background:#0a1628;border:1px solid #1e3a5f;border-radius:14px;padding:20px;min-width:280px;max-width:90vw;}
.sod-cd-modal-hdr{font-size:15px;font-weight:700;color:#e0f2ff;margin-bottom:12px;}
/* Print media */
@media print{
.sod-cd-header-actions,.sod-cd-alert-strip,.sod-cd-filter-group,.sod-cd-print-wrap,.sod-cd-live-badge,.sod-cd-btn,.sod-cd-chip,.sod-cd-modal{display:none!important;}
.sod-cd-print-hdr{display:flex!important;}
.sod-cd-wrap{background:#fff!important;color:#000!important;border-radius:0!important;box-shadow:none!important;}
.sod-cd-card,.sod-cd-kpi,.sod-cd-feed-table thead th{background:#f5f5f5!important;border-color:#ddd!important;}
.sod-cd-kpi-val,.sod-cd-brand-title,.sod-cd-card-hdr{color:#000!important;}
.sod-cd-kpi-lbl,.sod-cd-kpi-sub,.sod-cd-feed-table tbody td{color:#444!important;}
}
/* Responsive */
@media(max-width:1100px){.sod-cd-main-grid{grid-template-columns:1fr!important;}.sod-cd-analytics-grid{grid-template-columns:repeat(2,1fr)!important;}}
@media(max-width:700px){.sod-cd-kpi-row{grid-template-columns:repeat(2,minmax(0,1fr))!important;}.sod-cd-analytics-grid{grid-template-columns:1fr!important;}.sod-cd-brief-body{grid-template-columns:1fr!important;}.sod-cd-header{flex-direction:column;align-items:stretch;}.sod-cd-header-actions{justify-content:flex-start;flex-wrap:wrap;}.sod-cd-search{width:100%!important;}.sod-cd-main-grid,.sod-cd-analytics-grid,.sod-cd-kpi-row{gap:8px!important;}.sod-cd-feed-table{display:block;overflow-x:auto;white-space:nowrap;}.sod-cd-feed-table thead,.sod-cd-feed-table tbody,.sod-cd-feed-table tr{white-space:nowrap;}}
</style>

<!-- COMMAND DECK JavaScript -->
<script>
(function(){
'use strict';
const UID='<?php echo esc_js($uid);?>';
const AJAX_URL=(typeof SOD_CONFIG!=='undefined')?SOD_CONFIG.ajaxUrl:'<?php echo esc_js($ajax_url);?>';
const NONCE=(typeof SOD_CONFIG!=='undefined')?SOD_CONFIG.nonce:'<?php echo esc_js($nonce);?>';
const AUTO_SEC=<?php echo intval($auto_refresh);?>;
const DEF_HOURS=<?php echo intval($hours);?>;
const MIN_SCORE=<?php echo intval($min_score);?>;
const $e=id=>document.getElementById(UID+'-'+id);
let allEvents=[],filteredEvents=[],currentPage=1,isFetching=false,charts={},timelineMode='bar';
const PAGE_SIZE=30;

(function tickClock(){const now=new Date();const cl=$e('clock'),dt=$e('date');if(cl)cl.textContent=now.toLocaleTimeString('en-US',{hour:'2-digit',minute:'2-digit',second:'2-digit',hour12:false});if(dt)dt.textContent=now.toLocaleDateString('en-US',{year:'numeric',month:'2-digit',day:'2-digit'});setTimeout(tickClock,1000);})();

function esc(s){const d=document.createElement('div');d.textContent=s+'';return d.innerHTML;}
function fmt(ts){if(!ts)return '—';const d=new Date(ts*1000);return d.toLocaleTimeString('en-US',{hour:'2-digit',minute:'2-digit',hour12:false})+' '+d.toLocaleDateString('en-US',{month:'2-digit',day:'2-digit'});}
function scoreClass(s){return s>=140?'score-crit':(s>=80?'score-warn':'score-ok');}
function truncate(s,n){s=s||'';return s.length>n?s.substring(0,n)+'…':s;}

async function fetchData(){
    if(isFetching)return;isFetching=true;
    const loader=$e('loader');if(loader)loader.style.display='inline';
    const hoursSel=$e('hours-sel');
    const hours=hoursSel?parseInt(hoursSel.value)||DEF_HOURS:DEF_HOURS;
    try{
        const fd=new FormData();fd.append('action','sod_get_dashboard_data');fd.append('nonce',NONCE);fd.append('hours',hours);fd.append('region','all');fd.append('min_score',MIN_SCORE);
        const res=await fetch(AJAX_URL,{method:'POST',body:fd,credentials:'same-origin'});
        const json=await parseDeckAjaxJson(res);
        if(json.success&&json.data){allEvents=json.data.events||[];renderAll();}
    }catch(e){
        console.error('Command Deck fetch error:',e);
        const tb=$e('feed-body');if(tb)tb.innerHTML='<tr><td colspan="6" class="sod-cd-loading-row" style="color:#ef4444;">⚠️ خطأ في تحميل البيانات</td></tr>';
    }
    isFetching=false;if(loader)loader.style.display='none';
    const lu=$e('last-update');if(lu)lu.textContent='آخر تحديث: '+new Date().toLocaleTimeString('en-US',{hour:'2-digit',minute:'2-digit'});
}

function renderAll(){const s=computeStats(allEvents);renderKPIs(s);renderGauge(s);renderAlertStrip(allEvents);renderTimeline(allEvents);renderRegionsChart(s.regions);renderActorsChart(s.actors);renderDomainsChart(s.types);populateRegionFilter(s.regions);applyFeedFilters();renderBrief(s,allEvents);}

function computeStats(events){
    const regions={},actors={},types={};let crit=0,maxS=0,sumS=0;
    events.forEach(e=>{const s=parseInt(e.score)||0;sumS+=s;if(s>maxS)maxS=s;if(s>=140)crit++;const r=e.region||'غير محدد';regions[r]=(regions[r]||0)+1;const a=e.actor_v2||'غير محدد';actors[a]=(actors[a]||0)+1;const t=e.intel_type||'أخرى';types[t]=(types[t]||0)+1;});
    const n=events.length;
    return{total:n,crit,avg:n?Math.round(sumS/n):0,max:maxS,regions:sortTop(regions,8),actors:sortTop(actors,8),types:sortTop(types,10)};
}
function sortTop(obj,n){return Object.entries(obj).sort((a,b)=>b[1]-a[1]).slice(0,n);}

function renderKPIs(s){
    setText('k-total',s.total);setText('k-total-sub','خلال الفترة المحددة');
    setText('k-crit',s.crit);setText('k-crit-sub',(s.total?Math.round(s.crit/s.total*100):0)+'% من الإجمالي');
    setText('k-avg',s.avg);setText('k-avg-sub',s.avg>=140?'⚠️ فوق العتبة الحرجة':s.avg>=80?'تحذير':'طبيعي');
    setText('k-peak',s.max);setText('k-peak-sub',s.max>=200?'🔴 استثنائي':s.max>=140?'🟠 حرج':'🟡 مرصود');
    const topR=s.regions[0];if(topR){setText('k-region',truncate(topR[0],28));setText('k-region-sub',topR[1]+' حدث');}
    const topA=s.actors.find(([a])=>a!=='غير محدد');if(topA){setText('k-actor',truncate(topA[0],28));setText('k-actor-sub',topA[1]+' حدث');}
}
function setText(id,val){const el=$e(id);if(el)el.textContent=val;}

function renderGauge(s){
    const ratio=Math.min(1,s.avg/250);const arcLen=283;
    const arc=document.getElementById(UID+'-gauge-arc');const needle=document.getElementById(UID+'-gauge-needle');
    if(arc)arc.setAttribute('stroke-dasharray',(ratio*arcLen)+' '+arcLen);
    if(needle)needle.setAttribute('transform','rotate('+((-90)+ratio*180)+',110,110)');
    const lbl=$e('gauge-label'),sub=$e('gauge-sub');
    let level,color;
    if(s.crit>=10||s.max>=220||s.avg>=140){level='حرج جداً';color='#ef4444';}
    else if(s.crit>=3||s.max>=140||s.avg>=90){level='مرتفع';color='#f97316';}
    else if(s.crit>=1||s.avg>=60){level='متوسط';color='#f59e0b';}
    else{level='منخفض';color='#22c55e';}
    if(lbl){lbl.textContent=level;lbl.style.color=color;}
    if(sub)sub.textContent='متوسط '+s.avg+' | ذروة '+s.max+' | '+s.crit+' حدث حرج';
    const bars=$e('trend-bars'),tv=$e('trend-val');
    if(bars&&allEvents.length>10){
        const half=Math.floor(allEvents.length/2);
        const rA=allEvents.slice(0,half).reduce((a,e)=>a+parseInt(e.score||0),0)/half;
        const oA=allEvents.slice(half).reduce((a,e)=>a+parseInt(e.score||0),0)/half;
        const sp=[oA,rA*.7,rA*.85,rA].map(v=>Math.round(v));
        bars.innerHTML=sp.map((v,i)=>{const h=Math.max(4,Math.round(v/Math.max(...sp)*24));const c=i===sp.length-1?'#3b82f6':'#1e3a5f';return '<div class="sod-cd-trend-bar" style="height:'+h+'px;background:'+c+';"></div>';}).join('');
        const diff=rA-oA;if(tv){tv.textContent=diff>10?'↑ تصاعدي':diff<-10?'↓ هبوطي':'↔ مستقر';tv.style.color=diff>10?'#ef4444':diff<-10?'#22c55e':'#f59e0b';}
    }
}

function renderAlertStrip(events){
    const crits=events.filter(e=>parseInt(e.score||0)>=140).slice(0,20);
    const strip=$e('alert-strip'),inner=$e('alert-inner');
    if(!strip||!inner)return;
    if(!crits.length){strip.style.display='none';return;}
    strip.style.display='flex';
    // بناء عناصر عمودية — مضاعفة للتمرير اللانهائي السلس
    const buildItems=arr=>arr.map(e=>{
        const sc=parseInt(e.score||0);
        const col=sc>=200?'#ef4444':sc>=140?'#f97316':'#f59e0b';
        return '<div class="sod-cd-alert-vitem"><span style="color:'+col+';font-weight:900;margin-left:6px;">['+sc+']</span><span style="flex:1;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">'+esc(e.title||'')+'</span><span style="color:#7f1d1d;font-size:10px;margin-right:6px;">'+esc(e.region||'')+'</span></div>';
    }).join('');
    inner.innerHTML=buildItems(crits)+buildItems(crits);
    requestAnimationFrame(()=>{
        const h=inner.scrollHeight;
        const dur=Math.max(15,Math.round(h/35))+'s';
        inner.style.animation='none';
        void inner.offsetHeight;
        inner.style.animation='cd-marquee-up '+dur+' linear infinite';
    });
}

/* Safe chart destroy — handles Chart.js v4 "canvas already in use" */
function safeDestroyChart(key,el){
    if(charts[key]){try{charts[key].destroy();}catch(e){}charts[key]=null;}
    if(el&&typeof Chart!=='undefined'){const ex=Chart.getChart(el);if(ex)try{ex.destroy();}catch(e){}}
}
/* Retry helper — Chart.js قد يُحمَّل بعد تحميل الصفحة */
let _chartRetryQ=[];
function withChart(fn,retries){
    if(typeof Chart!=='undefined')return fn();
    retries=(retries||0)+1;
    if(retries>10)return;
    setTimeout(()=>withChart(fn,retries),400);
}

function renderTimeline(events){
    if(typeof Chart==='undefined'){withChart(()=>renderTimeline(events));return;}
    const now=Date.now()/1000;const hourMap={};
    for(let i=23;i>=0;i--){const h=new Date((now-i*3600)*1000);hourMap[String(h.getHours()).padStart(2,'0')+':00']=0;}
    events.forEach(e=>{const h=new Date((e.event_timestamp||0)*1000);const k=String(h.getHours()).padStart(2,'0')+':00';if(k in hourMap)hourMap[k]++;});
    const labels=Object.keys(hourMap);const data=Object.values(hourMap);const maxV=Math.max(...data,1);
    const colors=data.map(v=>v>=maxV*.8?'rgba(239,68,68,.8)':v>=maxV*.5?'rgba(249,115,22,.8)':'rgba(59,130,246,.7)');
    const ctx=document.getElementById(UID+'-timeline-chart');if(!ctx)return;
    safeDestroyChart('timeline',ctx);
    try{charts.timeline=new Chart(ctx,{type:timelineMode,data:{labels,datasets:[{label:'عدد الأحداث',data,backgroundColor:timelineMode==='bar'?colors:'rgba(59,130,246,.3)',borderColor:timelineMode==='line'?'#3b82f6':colors,borderWidth:2,tension:.3,fill:timelineMode==='line',pointBackgroundColor:'#3b82f6'}]},options:{responsive:true,maintainAspectRatio:false,plugins:{legend:{display:false},tooltip:{callbacks:{title:i=>i[0].label+' ساعة',label:i=>i.raw+' حدث'}}},scales:{x:{ticks:{color:'#5a7a9a',font:{size:10}},grid:{color:'rgba(30,58,95,.4)'}},y:{ticks:{color:'#5a7a9a',font:{size:10},precision:0},grid:{color:'rgba(30,58,95,.4)'},beginAtZero:true}}}});}catch(e){console.error('[SOD] timeline chart:',e.message);}
}

function renderRegionsChart(regions){
    if(typeof Chart==='undefined'){withChart(()=>renderRegionsChart(regions));return;}
    const ctx=document.getElementById(UID+'-regions-chart');if(!ctx)return;
    safeDestroyChart('regions',ctx);
    const top=regions.slice(0,7);
    try{charts.regions=new Chart(ctx,{type:'bar',data:{labels:top.map(r=>truncate(r[0],12)),datasets:[{label:'أحداث',data:top.map(r=>r[1]),backgroundColor:['#ef4444','#f97316','#f59e0b','#3b82f6','#8b5cf6','#22c55e','#06b6d4'].slice(0,top.length),borderWidth:0,borderRadius:4}]},options:{indexAxis:'y',responsive:true,maintainAspectRatio:false,plugins:{legend:{display:false},tooltip:{callbacks:{label:i=>i.raw+' حدث'}}},scales:{x:{ticks:{color:'#5a7a9a',font:{size:10}},grid:{color:'rgba(30,58,95,.4)'},beginAtZero:true},y:{ticks:{color:'#c8dff2',font:{size:10}},grid:{color:'rgba(30,58,95,.2)'}}}}})}catch(e){console.error('[SOD] regions chart:',e.message);}
}

function renderActorsChart(actors){
    if(typeof Chart==='undefined'){withChart(()=>renderActorsChart(actors));return;}
    const ctx=document.getElementById(UID+'-actors-chart');if(!ctx)return;
    safeDestroyChart('actors',ctx);
    const top=actors.filter(([a])=>a!=='غير محدد').slice(0,7);
    try{charts.actors=new Chart(ctx,{type:'bar',data:{labels:top.map(a=>truncate(a[0],14)),datasets:[{label:'أحداث',data:top.map(a=>a[1]),backgroundColor:'rgba(139,92,246,.7)',borderWidth:0,borderRadius:4}]},options:{indexAxis:'y',responsive:true,maintainAspectRatio:false,plugins:{legend:{display:false},tooltip:{callbacks:{label:i=>i.raw+' حدث'}}},scales:{x:{ticks:{color:'#5a7a9a',font:{size:10}},grid:{color:'rgba(30,58,95,.4)'},beginAtZero:true},y:{ticks:{color:'#c8dff2',font:{size:10}},grid:{color:'rgba(30,58,95,.2)'}}}}})}catch(e){console.error('[SOD] actors chart:',e.message);}
}

function renderDomainsChart(types){
    if(typeof Chart==='undefined'){withChart(()=>renderDomainsChart(types));return;}
    const ctx=document.getElementById(UID+'-domains-chart');if(!ctx)return;
    safeDestroyChart('domains',ctx);
    const domainKeys=['العسكري','الإعلامي','الاقتصادي','الدبلوماسي','الاجتماعي','السيبراني','البيئي','الاستخباراتي','الأمن'];
    const labels=['عسكري','معلوماتي','اقتصادي','دبلوماسي','اجتماعي','سيبراني','بيئي','استخباراتي','داخلي'];
    const data=domainKeys.map(k=>{const f=types.find(([t])=>t&&t.includes&&t.includes(k.substring(0,4)));return f?f[1]:0;});
    try{charts.domains=new Chart(ctx,{type:'radar',data:{labels,datasets:[{label:'حجم النشاط',data,backgroundColor:'rgba(59,130,246,.2)',borderColor:'#3b82f6',borderWidth:2,pointBackgroundColor:'#3b82f6',pointRadius:3}]},options:{responsive:true,maintainAspectRatio:false,plugins:{legend:{display:false}},scales:{r:{ticks:{color:'#5a7a9a',font:{size:9},backdropColor:'transparent'},grid:{color:'rgba(30,58,95,.5)'},angleLines:{color:'rgba(30,58,95,.6)'},pointLabels:{color:'#9db4c8',font:{size:10}}}}}})}catch(e){console.error('[SOD] domains chart:',e.message);}
}

function populateRegionFilter(regions){
    const sel=$e('region-filter');if(!sel)return;const current=sel.value;
    sel.innerHTML='<option value="all">كل الساحات</option>';
    regions.forEach(([r])=>{const opt=document.createElement('option');opt.value=r;opt.textContent=r;if(r===current)opt.selected=true;sel.appendChild(opt);});
    const cSel=$e('country-sel');if(cSel){cSel.innerHTML='';regions.forEach(([r])=>{const o=document.createElement('option');o.value=r;o.textContent=r;cSel.appendChild(o);});}
}

function applyFeedFilters(){
    const search=($e('search')||{}).value?.toLowerCase()||'';
    const filter=($e('feed-filter')||{}).value||'all';
    const regionF=($e('region-filter')||{}).value||'all';
    filteredEvents=allEvents.filter(e=>{
        if(filter==='critical'&&parseInt(e.score||0)<140)return false;
        if(regionF!=='all'&&e.region!==regionF)return false;
        if(search&&!(e.title||'').toLowerCase().includes(search)&&!(e.region||'').toLowerCase().includes(search))return false;
        return true;
    });
    currentPage=1;renderFeedPage();
}

function renderFeedPage(){
    const tbody=$e('feed-body'),pgWrap=$e('pagination'),cntEl=$e('feed-count');if(!tbody)return;
    const total=filteredEvents.length;const pages=Math.ceil(total/PAGE_SIZE);
    if(cntEl)cntEl.textContent=total+' حدث';
    const slice=filteredEvents.slice((currentPage-1)*PAGE_SIZE,currentPage*PAGE_SIZE);
    if(!slice.length){tbody.innerHTML='<tr><td colspan="6" class="sod-cd-loading-row">لا توجد أحداث مطابقة</td></tr>';return;}
    tbody.innerHTML=slice.map(e=>{const s=parseInt(e.score||0);const sc=scoreClass(s);const t=e.intel_type||'—';const a=truncate(e.actor_v2||'—',20);return '<tr onclick="window.open(\''+esc(e.link||'#')+'\',\'_blank\')"><td style="font-size:11px;color:#5a7a9a;white-space:nowrap;">'+fmt(e.event_timestamp)+'</td><td><span class="sod-cd-score-badge '+sc+'">'+s+'</span></td><td style="font-size:11px;">'+esc(truncate(e.region||'—',15))+'</td><td style="font-size:11px;color:#9db4c8;">'+esc(a)+'</td><td style="font-size:10px;color:#5a7a9a;">'+esc(truncate(t,10))+'</td><td style="color:#c8dff2;max-width:320px;">'+esc(truncate(e.title||'—',100))+'</td></tr>';}).join('');
    if(pgWrap){let pgHtml='';for(let i=1;i<=Math.min(pages,10);i++){pgHtml+='<button class="sod-cd-pg-btn '+(i===currentPage?'active':'')+'" onclick="sodCdPage_'+UID+'('+i+')">'+i+'</button>';}if(pages>10)pgHtml+='<span style="color:#5a7a9a;font-size:11px;padding:0 6px;">… '+pages+' صفحة</span>';pgWrap.innerHTML=pgHtml;}
}
window['sodCdPage_'+UID]=function(p){currentPage=p;renderFeedPage();};

function relatedFeedQuery(title){
    const stopWords=['من','في','على','إلى','عن','مع','هذا','هذه','ذلك','تلك','بعد','قبل','حول','عند','بين','تم','رصد','خبر','عاجل'];
    const parts=String(title||'').replace(/[^\p{L}\p{N}\s]/gu,' ').split(/\s+/).filter(Boolean);
    const keywords=parts.filter(word=>word.length>2 && !stopWords.includes(word)).slice(0,4);
    return keywords.join(' ').trim() || String(title||'').trim();
}
window['sodCdRelated_'+UID]=function(title){
    const query=relatedFeedQuery(title);
    const search=$e('search');
    if(search)search.value=query;
    applyFeedFilters();
};
function renderFeedPage(){
    const tbody=$e('feed-body'),pgWrap=$e('pagination'),cntEl=$e('feed-count');if(!tbody)return;
    const total=filteredEvents.length;const pages=Math.ceil(total/PAGE_SIZE);
    if(cntEl)cntEl.textContent=total+' حدث';
    const slice=filteredEvents.slice((currentPage-1)*PAGE_SIZE,currentPage*PAGE_SIZE);
    if(!slice.length){tbody.innerHTML='<tr><td colspan="6" class="sod-cd-loading-row">لا توجد أحداث مطابقة</td></tr>';return;}
    tbody.innerHTML=slice.map(e=>{
        const s=parseInt(e.score||0);
        const sc=scoreClass(s);
        const t=e.intel_type||'—';
        const a=truncate(e.actor_v2||'—',20);
        const titleText=esc(truncate(e.title||'—',100));
        const titleData=encodeURIComponent(String(e.title||''));
        const chips=[
            ['استراتيجي',e.intel_type],
            ['تكتيكي',e.tactical_level],
            ['المنطقة',e.region],
            ['الفاعل',e.actor_v2],
            ['الهدف',e.target_v2],
            ['السياق',e.context_actor],
            ['النية',e.intent],
            ['السلاح',e.weapon_v2]
        ].filter(x=>x[1] && String(x[1]).trim() && String(x[1]).trim()!=='غير محدد' && String(x[1]).trim()!=='â€”')
         .map(x=>'<span class="sod-cd-mini-chip"><b>'+esc(x[0])+':</b> '+esc(truncate(String(x[1]),34))+'</span>').join('');
        return '<tr><td style="font-size:11px;color:#5a7a9a;white-space:nowrap;">'+fmt(e.event_timestamp)+'</td><td><span class="sod-cd-score-badge '+sc+'">'+s+'</span></td><td style="font-size:10px;color:#9db4c8;">'+esc(truncate(e.intent||'—',18))+'</td><td style="color:#c8dff2;max-width:320px;"><a href="#" class="sod-cd-title-link" data-related="'+titleData+'" onclick="event.preventDefault();window[\'sodCdRelated_'+UID+'\'](decodeURIComponent(this.dataset.related||\'\'))">'+titleText+'</a>'+(chips?'<div class="sod-cd-meta-stack">'+chips+'</div>':'')+'</td><td style="font-size:11px;">'+esc(truncate(e.region||'—',15))+'</td><td style="font-size:10px;color:#5a7a9a;">'+esc(truncate(e.tactical_level||t,12))+'</td></tr>';
    }).join('');
    if(pgWrap){let pgHtml='';for(let i=1;i<=Math.min(pages,10);i++){pgHtml+='<button class="sod-cd-pg-btn '+(i===currentPage?'active':'')+'" onclick="sodCdPage_'+UID+'('+i+')">'+i+'</button>';}if(pages>10)pgHtml+='<span style="color:#5a7a9a;font-size:11px;padding:0 6px;">… '+pages+' صفحة</span>';pgWrap.innerHTML=pgHtml;}
}

function renderBrief(s,events){
    const body=$e('brief-body');if(!body)return;
    const topR=s.regions.slice(0,3).map(r=>'<div class="sod-cd-brief-line">📍 '+esc(r[0])+' — <strong style="color:#e0f2ff;margin-right:auto;">'+r[1]+' حدث</strong></div>').join('');
    const topA=s.actors.filter(([a])=>a!=='غير محدد').slice(0,3).map(a=>'<div class="sod-cd-brief-line">🎯 '+esc(a[0])+' — <strong style="color:#e0f2ff;margin-right:auto;">'+a[1]+' حدث</strong></div>').join('');
    const topE=events.filter(e=>parseInt(e.score||0)>=140).slice(0,4).map(e=>'<div class="sod-cd-brief-line">['+e.score+'] '+esc(truncate(e.title||'',90))+'</div>').join('');
    const topT=s.types.slice(0,4).map(t=>'<div class="sod-cd-brief-line">🧩 '+esc(t[0])+' — <strong style="color:#e0f2ff;margin-right:auto;">'+t[1]+'</strong></div>').join('');
    let tw=s.crit>=10||s.max>=220?'حرجة جداً':s.crit>=3||s.max>=140?'مرتفعة':s.crit>=1||s.avg>=60?'متوسطة':'منخفضة';
    let trend='↔ مستقرة';
    if(allEvents.length>10){const half=Math.floor(allEvents.length/2);const r1=allEvents.slice(0,half).reduce((a,e)=>a+parseInt(e.score||0),0)/half;const r2=allEvents.slice(half).reduce((a,e)=>a+parseInt(e.score||0),0)/half;trend=r1>r2+10?'↑ تصاعدية':r2>r1+10?'↓ هابطة':'↔ مستقرة';}
    body.innerHTML='<div class="sod-cd-brief-section"><div class="sod-cd-brief-section-title">📊 ملخص المؤشرات</div><div class="sod-cd-brief-line">إجمالي الأحداث: <strong style="color:#e0f2ff;margin-right:auto;">'+s.total+'</strong></div><div class="sod-cd-brief-line">الحرجة (≥140): <strong style="color:#ef4444;margin-right:auto;">'+s.crit+'</strong></div><div class="sod-cd-brief-line">متوسط التهديد: <strong style="color:#f59e0b;margin-right:auto;">'+s.avg+'</strong></div><div class="sod-cd-brief-line">الذروة: <strong style="color:#f97316;margin-right:auto;">'+s.max+'</strong></div><div class="sod-cd-brief-line">الحالة: <strong style="color:#3b82f6;margin-right:auto;">'+tw+'</strong></div><div class="sod-cd-brief-line">الاتجاه: <strong style="margin-right:auto;">'+trend+'</strong></div></div><div class="sod-cd-brief-section" style="border-right-color:#8b5cf6;"><div class="sod-cd-brief-section-title" style="color:#c4b5fd;">🌍 الساحات الأشد سخونة</div>'+(topR||'<div class="sod-cd-brief-line">لا بيانات</div>')+'</div><div class="sod-cd-brief-section" style="border-right-color:#22c55e;"><div class="sod-cd-brief-section-title" style="color:#86efac;">🎯 الجهات الفاعلة</div>'+(topA||'<div class="sod-cd-brief-line">لا بيانات</div>')+'</div><div class="sod-cd-brief-section" style="border-right-color:#ef4444;"><div class="sod-cd-brief-section-title" style="color:#fca5a5;">⚡ أبرز الأحداث الحرجة</div>'+(topE||'<div class="sod-cd-brief-line">لا أحداث حرجة</div>')+'</div><div class="sod-cd-brief-section" style="border-right-color:#f59e0b;"><div class="sod-cd-brief-section-title" style="color:#fcd34d;">🧩 الأنماط السائدة</div>'+(topT||'<div class="sod-cd-brief-line">لا بيانات</div>')+'</div>';
}
window['sodCdBrief_'+UID]=function(){const s=computeStats(allEvents);renderBrief(s,allEvents);};

window['sodCdChartMode_'+UID]=function(mode){timelineMode=mode;document.querySelectorAll('#'+UID+' [data-chart]').forEach(btn=>btn.classList.toggle('active',btn.dataset.chart===mode));renderTimeline(allEvents);};

const PRINT_TITLES={full:'التقرير الكامل',kpi:'تقرير المؤشرات',timeline:'الجدول الزمني',actors:'تقرير الجهات',country:'تقرير الساحة'};
window['sodCdPrint_'+UID]=function(mode){const menu=$e('print-menu');if(menu)menu.classList.remove('open');if(mode==='country'){const modal=$e('country-modal');if(modal)modal.classList.add('open');return;}triggerPrint(mode,'');};
window['sodCdCountryPrint_'+UID]=function(){const sel=$e('country-sel');if(!sel)return;const modal=$e('country-modal');if(modal)modal.classList.remove('open');triggerPrint('country',sel.value);};
function triggerPrint(mode,country){
    const phdr=$e('print-hdr'),ptt=$e('print-title'),pdt=$e('print-dt');
    if(phdr)phdr.style.display='flex';if(ptt)ptt.textContent=PRINT_TITLES[mode]+(country?' — '+country:'');if(pdt)pdt.textContent=new Date().toLocaleDateString('en-US',{year:'numeric',month:'2-digit',day:'2-digit',hour:'2-digit',minute:'2-digit'});
    setTimeout(()=>{window.print();if(phdr)phdr.style.display='none';},300);
}

// Print menu toggle
const ptb=document.getElementById(UID+'-print-toggle');const pmenu=document.getElementById(UID+'-print-menu');
if(ptb&&pmenu){ptb.addEventListener('click',e=>{e.stopPropagation();pmenu.classList.toggle('open');});document.addEventListener('click',()=>pmenu.classList.remove('open'));}

// Refresh button
const rbtn=document.getElementById(UID+'-refresh-btn');if(rbtn)rbtn.addEventListener('click',fetchData);

// Search & filter listeners
const searchEl=$e('search'),filterEl=$e('feed-filter'),regionEl=$e('region-filter');
if(searchEl)searchEl.addEventListener('input',applyFeedFilters);
if(filterEl)filterEl.addEventListener('change',applyFeedFilters);
if(regionEl)regionEl.addEventListener('change',applyFeedFilters);
const hoursSel=document.getElementById(UID+'-hours-sel');if(hoursSel)hoursSel.addEventListener('change',fetchData);

// Init
fetchData();if(AUTO_SEC>0)setInterval(fetchData,AUTO_SEC*1000);
})();
</script>
