if (!function_exists('so_get_breaking_news_items')) {
    function so_get_breaking_news_items($limit = 10) {
        global $wpdb;
        $table = $wpdb->prefix . 'so_news_events';
        $limit = max(1, min(20, (int)$limit));
        $rows = $wpdb->get_col("SELECT title FROM {$table} ORDER BY event_timestamp DESC LIMIT {$limit}");
        $out = [];
        if (is_array($rows)) {
            foreach ($rows as $r) {
                $t = so_clean_text((string)$r);
                if ($t !== '') $out[] = $t;
            }
        }
        return array_values(array_unique($out));
    }
}

if (!function_exists('so_bt_render_breaking_bar_html')) {
    function so_bt_render_breaking_bar_html($title = '⚡ عاجل', $items = [], $extra_class = '') {
        $title = $title !== '' ? $title : '⚡ عاجل';
        if (empty($items)) return '';
        ob_start(); ?>
        <div class="so-breaking-shell <?php echo esc_attr($extra_class); ?>" dir="rtl">
            <div class="so-breaking-label"><?php echo esc_html($title); ?></div>
            <div class="so-breaking-track-wrap">
                <div class="so-breaking-track">
                    <?php
                    $merged = array_merge($items, $items);
                    foreach ($merged as $item): ?>
                        <span class="so-breaking-item"><?php echo esc_html($item); ?></span>
                    <?php endforeach; ?>
                </div>
            </div>
        </div>
        <?php
        return ob_get_clean();
    }
}

