function so_is_lebanon_local_event($title, $region = '', $actor = '', $intel_type = '') {
    $title = so_clean_text((string)$title);
    $region = trim((string)$region);
    $actor = trim((string)$actor);
    $intel_type = trim((string)$intel_type);

    if ($region !== 'لبنان') {
        return false;
    }

    if (preg_match('/(إيران|طهران|باكستان|روسيا|أوكرانيا|أميركا|أمريكا|الولايات المتحدة|ترامب|ترمب|بوتين|الخليج|الإمارات|البحرين|قطر|السعودية|العراق|سوريا|اليمن|الهند|الصين)/ui', $title)) {
        return false;
    }

    if (in_array($intel_type, ['سياسي', 'إعلامي', 'شجب/استنكار', 'بيان'], true)) {
        if (!preg_match('/(غارة|قصف|استهداف|مسيّرة|مسيرة|عدوان|إصابة|شهداء|جرحى|حربي فوق|تحليق|صفارات|انذار|إنذار|إطلاق نار|اقتحام|تسلل طائرة|سقوط مباشر)/ui', $title)) {
            return false;
        }
    }

    if (preg_match('/(بيروت|الضاحية|الجنوب|صور|صيدا|النبطية|بنت جبيل|مرجعيون|حاصبيا|جزين|الشوف|عاليه|بعبدا|المتن|كسروان|جبيل|زحلة|بعلبك|الهرمل|راشيا|البقاع الغربي|عكار|طرابلس|الكورة|البترون|زغرتا|بشامون|عرمون|سوق الغرب|الخيام|كفركلا|العديسة|حولا|ميس الجبل|قانا|حناويه|العباسية|المنصوري|دورس|شمسطار|سحمر|الكرك|سن الفيل|الحدث|الشويفات|عين الحلوة|عبرا|الزهراني|الريحان|كفررمان|حبوش|ميفدون|الدوير|عيترون|عيناثا|يارون|رميش|مارون الراس)/ui', $title)) {
        return true;
    }

    if (preg_match('/(غارة|قصف|استهداف|تحليق|حربي فوق|مسيّرة|مسيرة|شهداء|جرحى|إصابات|عدوان)/ui', $title)) {
        return true;
    }

    return false;
}


function so_extract_lebanon_district($title, $region = '', $actor = '', $intel_type = '') {
    if (!so_is_lebanon_local_event($title, $region, $actor, $intel_type)) {
        return '';
    }
    $t = so_clean_text((string)$title . ' ' . (string)$region);

    $district_map = [
        'بيروت' => ['بيروت','الظريف','زقاق البلاط','تلة الخياط','طريق الجديدة','الجناح','حي السلم','سن الفيل','الحدث','الضاحية'],
        'صور' => ['صور','المنصوري','العباسية','حناويه','البازورية','طيردبا','رشيدية','قانا','صديقين','الشهابية','شمع'],
        'صيدا' => ['صيدا','عين الحلوة','الهلالية','عبرا','المية ومية','الزهراني'],
        'النبطية' => ['النبطية','كفرتبنيت','حبوش','كفررمان','الدوير','ميفدون'],
        'بنت جبيل' => ['بنت جبيل','عيترون','عيناثا','يارون','رميش','مارون الراس','برعشيت','دبل','عيتا الشعب'],
        'مرجعيون' => ['مرجعيون','الخيام','كفركلا','العديسة','الطيبة','مركبا','حولا','ميس الجبل'],
        'حاصبيا' => ['حاصبيا','شبعا','كفرشوبا','مرج الزهور'],
        'جزين' => ['جزين','الريحان'],
        'الشوف' => ['الشوف','بعقلين','دير القمر','بيت الدين','برجا','الدامور'],
        'عاليه' => ['عاليه','بشامون','عرمون','سوق الغرب','ضهر الوحش','الشويفات'],
        'بعبدا' => ['بعبدا','الحدث','حازمية','اليرزة','الضاحية الجنوبية'],
        'المتن' => ['المتن','سن الفيل','الدكوانة','جل الديب','بكفيا'],
        'كسروان' => ['كسروان','جونية','غزير','جعيتا','زوق مصبح','زوق مكايل'],
        'جبيل' => ['جبيل','عمشيت','قرطبا','العاقورة'],
        'زحلة' => ['زحلة','تعنايل','شتورا','بر الياس','الكرك'],
        'بعلبك' => ['بعلبك','شمسطار','دورس','إيعات','النبي شيت'],
        'الهرمل' => ['الهرمل','القصر','القاع','حوش السيد علي'],
        'راشيا' => ['راشيا','كفرمشكي','عقبة راشيا'],
        'البقاع الغربي' => ['البقاع الغربي','سحمر','جب جنين','مشغرة','يحمر'],
        'عكار' => ['عكار','حلبا','ببنين','العبدة','القبيات'],
        'المنية الضنية' => ['المنية','الضنية','بحنين','سير الضنية'],
        'طرابلس' => ['طرابلس','الميناء','القبة','باب التبانة'],
        'الكورة' => ['الكورة','أميون','كفرحزير'],
        'البترون' => ['البترون','شكا','تنورين','دوما'],
        'زغرتا' => ['زغرتا','إهدن','مزيارة'],
    ];

    foreach ($district_map as $district => $aliases) {
        foreach ($aliases as $alias) {
            if ($alias !== '' && mb_stripos($t, $alias) !== false) return $district;
        }
    }
    return '';
}


