            'فلسطين' => ['غزة','الضفة','القدس','جنين','نابلس','الخليل','طولكرم','رفح','خان يونس'],
            'إيران' => ['إيران','ايران','طهران'],
            'سوريا' => ['سوريا','دمشق','حلب','حمص'],
            'العراق' => ['العراق','بغداد'],
